INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (55, 52, 1, 2, 2025, 230, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'Số 47-49 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP. HCM.', N'<p><strong>Thông báo Tuyển sinh Hệ Chính quy năm 2025</strong></p>
<p>Trường Cao đẳng Bách khoa Nam Sài Gòn thông báo kế hoạch tuyển sinh năm 2025. Với phương châm &quot;Thực học - Thực nghiệp&quot;, nhà trường cam kết mang đến môi trường đào tạo hiện đại, bám sát nhu cầu thực tế của doanh nghiệp.</p>
<p><strong>1. Điều kiện và Đối tượng xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh đã tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức xét tuyển:</strong> * Xét tuyển dựa trên kết quả học bạ THPT (Điểm trung bình cả năm lớp 12 hoặc điểm trung bình 3 học kỳ).</p>
<ul>
<li>
<p>Xét tuyển dựa trên kết quả thi tốt nghiệp THPT năm 2025.</p>
</li>
</ul>
</li>
</ul>
<p><strong>2. Quyền lợi của Sinh viên:</strong></p>
<ul>
<li>
<p><strong>Đào tạo chú trọng thực hành:</strong> Thời lượng thực hành chiếm hơn 70% chương trình học, giúp sinh viên vững tay nghề ngay khi tốt nghiệp.</p>
</li>
<li>
<p><strong>Cam kết việc làm:</strong> Nhà trường hỗ trợ kết nối và giới thiệu việc làm tại các tập đoàn, doanh nghiệp đối tác uy tín trong và ngoài nước.</p>
</li>
<li>
<p><strong>Cơ sở vật chất:</strong> Hệ thống phòng học, phòng thí nghiệm và xưởng thực hành được đầu tư trang thiết bị hiện đại, chuẩn quốc tế.</p>
</li>
<li>
<p><strong>Học bổng:</strong> Nhiều chính sách học bổng dành cho sinh viên có thành tích xuất sắc, sinh viên có hoàn cảnh khó khăn và các gói ưu đãi học phí khi nhập học sớm.</p>
</li>
</ul>
<p><strong>3. Hồ sơ đăng ký xét tuyển:</strong></p>
<ul>
<li>
<p>01 Phiếu đăng ký xét tuyển (theo mẫu của trường).</p>
</li>
<li>
<p>01 Bản sao công chứng Học bạ THPT.</p>
</li>
<li>
<p>01 Bản sao công chứng Giấy chứng nhận tốt nghiệp tạm thời hoặc Bằng tốt nghiệp THPT.</p>
</li>
<li>
<p>01 Bản sao công chứng CCCD.</p>
</li>
<li>
<p>02 Ảnh thẻ 3x4 (chụp không quá 6 tháng).</p>
</li>
</ul>
<p><strong>4. Thông tin liên hệ:</strong></p>
<ul>
<li>
<p><strong>Địa chỉ:</strong> Số 47-49 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP. Hồ Chí Minh.</p>
</li>
<li>
<p><strong>Hotline hỗ trợ:</strong> (Vui lòng điền số điện thoại tuyển sinh của trường).</p>
</li>
</ul>', CAST(N'2026-04-30T16:49:49.193' AS DateTime), 6, 1, N'Tuyển sinh 2025 - Ngành Công nghệ Thông tin - Xét tuyển học bạ THPT', CAST(N'2026-04-30T00:00:00.000' AS DateTime), N'12 - 15 triệu/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (56, 52, 4, 2, 2026, 200, N'A00,A01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Cao Lỗ, Quận 8, TP.HCM', N'<p>Ngành đào tạo theo chương trình thực hành, bám sát nhu cầu doanh nghiệp, giúp sinh viên có kỹ năng nghề nghiệp ngay sau khi tốt nghiệp.<br />Nhà trường xét tuyển theo 2 phương thức: học bạ THPT và điểm thi tốt nghiệp THPT.<br />Thí sinh đã tốt nghiệp THPT hoặc tương đương đều có thể đăng ký xét tuyển.<br />Riêng các ngành thuộc khối sức khỏe yêu cầu điểm xét tuyển đạt từ 15 điểm trở lên theo quy định.<br />Thời gian nhận hồ sơ từ khi thông báo đến 30/10/2026 hoặc đến khi đủ chỉ tiêu</p>', CAST(N'2026-04-30T17:12:53.333' AS DateTime), 11, 1, N'Tuyển sinh 2026 – Ngành An toàn Thông tin – Xét học bạ & THPT', CAST(N'2026-08-30T00:00:00.000' AS DateTime), N'khoảng 10 – 20 triệu/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (57, 52, 4, 1, 2025, 200, N'A00', CAST(25.00 AS Decimal(4, 2)), CAST(26.00 AS Decimal(4, 2)), NULL, N'Cao đẳng', N'128 Nam Từ Liêm', N'<p>avawvawvwavawvewa</p>', CAST(N'2026-04-30T21:15:25.870' AS DateTime), 0, 1, NULL, CAST(N'2024-06-12T00:00:00.000' AS DateTime), N'10 triệu/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (58, 52, 17, 2, 2025, 100, N'B00,D01,D08', CAST(16.00 AS Decimal(4, 2)), CAST(16.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH ĐIỀU DƯỠNG - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN</strong></p>
<p><strong>1. Điều kiện xét tuyển:</strong></p>
<ul>
<li>
<p>Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Lưu ý:</strong> Ưu tiên thí sinh có học lực lớp 12 xếp loại Khá trở lên (theo quy định chung của khối ngành sức khỏe).</p>
</li>
<li>
<p>Có sức khỏe tốt để đáp ứng môi trường làm việc tại các cơ sở y tế.</p>
</li>
</ul>
<p><strong>2. Điểm nổi bật của chương trình:</strong></p>
<ul>
<li>
<p>Chương trình đào tạo chú trọng kỹ năng lâm sàng, chăm sóc bệnh nhân chuyên nghiệp.</p>
</li>
<li>
<p>Thực tập thực tế tại các bệnh viện lớn trên địa bàn TP.HCM như Bệnh viện Quận 7, Bệnh viện Nguyễn Tri Phương...</p>
</li>
<li>
<p>Đào tạo kỹ năng mềm và ngoại ngữ để có cơ hội làm việc tại Nhật Bản, Đức theo các chương trình hợp tác của trường.</p>
</li>
</ul>
<p><strong>3. Hồ sơ xét tuyển:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký theo mẫu.</p>
</li>
<li>
<p>Học bạ THPT (photo công chứng).</p>
</li>
<li>
<p>Bằng tốt nghiệp hoặc Giấy chứng nhận tốt nghiệp tạm thời.</p>
</li>
</ul>', CAST(N'2026-04-30T21:31:06.657' AS DateTime), 2, 1, N'Tuyển sinh 2025 - Ngành Điều dưỡng - Xét học bạ THPT', CAST(N'2025-08-31T00:00:00.000' AS DateTime), N'Khoảng 18 - 20 triệu/năm')
