INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (60, 52, 10, 2, 2025, 80, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH KẾ TOÁN - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN</strong></p>
<p><strong>1. Điều kiện xét tuyển:</strong></p>
<ul>
<li>
<p>Tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p>Xét tuyển dựa trên điểm học bạ lớp 12 hoặc điểm thi tốt nghiệp THPT 2025.</p>
</li>
</ul>
<p><strong>2. Nội dung đào tạo:</strong></p>
<ul>
<li>
<p>Học viên được trang bị kiến thức về kế toán tài chính, kế toán quản trị, kiểm toán và thuế.</p>
</li>
<li>
<p>Thành thạo các phần mềm kế toán thông dụng (MISA, FAST...) và kỹ năng tin học văn phòng chuyên sâu.</p>
</li>
<li>
<p>Đào tạo kỹ năng kê khai thuế, lập báo cáo tài chính và quyết toán thuế thực tế.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp:</strong></p>
<ul>
<li>
<p>Chuyên viên kế toán tại các doanh nghiệp, công ty sản xuất, thương mại.</p>
</li>
<li>
<p>Nhân viên kiểm soát nội bộ, tư vấn tài chính.</p>
</li>
<li>
<p>Làm việc tại bộ phận kế toán của các cơ quan hành chính sự nghiệp, ngân hàng.</p>
</li>
<li>
<p>Cơ hội liên thông lên Đại học dễ dàng sau khi tốt nghiệp.</p>
</li>
</ul>
<p><strong>4. Hồ sơ nhập học:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển theo mẫu.</p>
</li>
<li>
<p>Học bạ THPT (sao y bản chính).</p>
</li>
<li>
<p>Bằng tốt nghiệp hoặc Giấy chứng nhận tốt nghiệp THPT tạm thời.</p>
</li>
</ul>', CAST(N'2026-04-30T21:36:22.147' AS DateTime), 1, 1, N'Tuyển sinh 2025 - Ngành Kế toán - Xét học bạ THPT', CAST(N'2025-12-31T00:00:00.000' AS DateTime), N'Khoảng 16,5 triệu/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (61, 52, 23, 2, 2025, 60, N'A01,D01,H00', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH THIẾT KẾ ĐỒ HỌA - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN</strong></p>
<p><strong>1. Điều kiện xét tuyển:</strong></p>
<ul>
<li>
<p>Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p>Xét tuyển dựa trên điểm trung bình học bạ lớp 12 (Tổng 3 môn đạt từ 15.0 điểm).</p>
</li>
<li>
<p>Ưu tiên các bạn có năng khiếu thẩm mỹ hoặc đam mê sáng tạo nội dung số.</p>
</li>
</ul>
<p><strong>2. Kỹ năng đạt được sau khóa học:</strong></p>
<ul>
<li>
<p>Sử dụng thành thạo các phần mềm đồ họa chuyên nghiệp: Adobe Photoshop, Illustrator, InDesign, Premiere, After Effects.</p>
</li>
<li>
<p>Thiết kế bộ nhận diện thương hiệu, ấn phẩm quảng cáo (Poster, Banner, Brochure).</p>
</li>
<li>
<p>Thiết kế giao diện Web/App (UI/UX) cơ bản và xử lý hậu kỳ video, motion graphics.</p>
</li>
<li>
<p>Kỹ thuật nhiếp ảnh và xử lý hình ảnh chuyên nghiệp.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp:</strong></p>
<ul>
<li>
<p>Chuyên viên thiết kế tại các công ty quảng cáo (Agency), tòa soạn báo, nhà xuất bản.</p>
</li>
<li>
<p>Nhân viên truyền thông, marketing, thiết kế nội dung cho các nền tảng mạng xã hội.</p>
</li>
<li>
<p>Freelancer (Làm việc tự do) về thiết kế logo, chỉnh sửa hình ảnh, video.</p>
</li>
<li>
<p>Làm việc trong bộ phận thiết kế của các doanh nghiệp lớn.</p>
</li>
</ul>
<p><strong>4. Hồ sơ xét tuyển:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký theo mẫu.</p>
</li>
<li>
<p>Bản sao học bạ THPT.</p>
</li>
<li>
<p>Bằng tốt nghiệp hoặc Giấy chứng nhận tốt nghiệp THPT tạm thời.</p>
</li>
</ul>', CAST(N'2026-04-30T21:38:35.187' AS DateTime), 0, 1, N'Tuyển sinh 2025 - Ngành Thiết kế Đồ họa - Xét học bạ THPT', CAST(N'2025-11-30T00:00:00.000' AS DateTime), N'Khoảng 17,5 - 19 triệu/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (62, 52, 6, 2, 2025, 80, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH KỸ THUẬT CƠ ĐIỆN TỬ - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN</strong></p>
<p><strong>1. Điều kiện xét tuyển:</strong></p>
<ul>
<li>
<p>Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p>Xét tuyển dựa trên học bạ lớp 12 (Tổng điểm 3 môn tổ hợp $\ge$ 15.0 điểm) hoặc điểm thi tốt nghiệp THPT 2025.</p>
</li>
<li>
<p>Ưu tiên thí sinh có đam mê về máy móc, robot và tư duy kỹ thuật tốt.</p>
</li>
</ul>
<p><strong>2. Nội dung đào tạo chuyên sâu:</strong></p>
<ul>
<li>
<p>Lắp ráp, vận hành và bảo trì các hệ thống sản xuất tự động, cánh tay robot công nghiệp.</p>
</li>
<li>
<p>Thiết kế cơ khí (AutoCAD, SolidWorks) kết hợp lập trình điều khiển (PLC, vi điều khiển).</p>
</li>
<li>
<p>Thực hành trên các thiết bị hiện đại tại xưởng thực hành của trường.</p>
</li>
<li>
<p>Rèn luyện tác phong công nghiệp và kỹ năng an toàn lao động.</p>
</li>
</ul>
<p><strong>3. Cơ hội việc làm:</strong></p>
<ul>
<li>
<p>Kỹ thuật viên vận hành dây chuyền sản xuất tự động tại các nhà máy, khu chế xuất.</p>
</li>
<li>
<p>Chuyên viên bảo trì, sửa chữa thiết bị điện tử - cơ khí.</p>
</li>
<li>
<p>Nhân viên tư vấn, lắp đặt hệ thống tự động hóa cho doanh nghiệp.</p>
</li>
<li>
<p>Làm việc tại các tập đoàn công nghệ lớn như Samsung, Intel, hoặc các nhà máy tại khu công nghệ cao.</p>
</li>
</ul>
<p><strong>4. Hồ sơ bao gồm:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển theo mẫu.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT.</p>
</li>
<li>
<p>Giấy chứng nhận tốt nghiệp THPT tạm thời hoặc Bằng tốt nghiệp.</p>
</li>
</ul>', CAST(N'2026-04-30T21:44:22.040' AS DateTime), 1, 1, N'Tuyển sinh 2025 - Ngành Kỹ thuật Cơ điện tử - Xét học bạ THPT', CAST(N'2025-11-15T00:00:00.000' AS DateTime), N'Khoảng 16,5 - 17,5 triệu/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (63, 52, 9, 2, 2025, 100, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH QUẢN TRỊ KINH DOANH - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN</strong></p>
<p><strong>1. Điều kiện xét tuyển:</strong></p>
<ul>
<li>
<p>Thí sinh đã tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p>Xét tuyển dựa trên học bạ lớp 12 (Tổng điểm trung bình 3 môn thuộc tổ hợp xét tuyển đạt từ 15.0 điểm trở lên).</p>
</li>
<li>
<p>Thí sinh có sức khỏe tốt, yêu thích lĩnh vực kinh doanh, khởi nghiệp và quản lý.</p>
</li>
</ul>
<p><strong>2. Mục tiêu đào tạo:</strong></p>
<ul>
<li>
<p>Trang bị kiến thức nền tảng về quản trị: quản trị nhân sự, quản trị marketing, quản trị tài chính, và quản trị sản xuất.</p>
</li>
<li>
<p>Rèn luyện kỹ năng lập kế hoạch kinh doanh, phân tích thị trường, kỹ năng đàm phán và giải quyết vấn đề trong môi trường doanh nghiệp thực tế.</p>
</li>
<li>
<p>Sử dụng thành thạo các công cụ hỗ trợ quản lý và tin học văn phòng chuyên sâu.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp:</strong></p>
<ul>
<li>
<p>Chuyên viên tại các phòng ban: Kinh doanh, Marketing, Nhân sự, Hành chính của các công ty, tập đoàn.</p>
</li>
<li>
<p>Trợ lý giám đốc, quản lý bộ phận sản xuất hoặc dịch vụ tại các doanh nghiệp vừa và nhỏ.</p>
</li>
<li>
<p>Tự khởi nghiệp và vận hành mô hình kinh doanh cá nhân.</p>
</li>
<li>
<p>Làm việc trong các lĩnh vực dịch vụ khách hàng, quản trị chuỗi cung ứng cơ bản.</p>
</li>
</ul>
<p><strong>4. Ưu điểm khi học tại trường:</strong></p>
<ul>
<li>
<p>Chương trình đào tạo ứng dụng thực tế (70% thực hành), giảng viên giàu kinh nghiệm thực chiến.</p>
</li>
<li>
<p>Môi trường học tập năng động tại Quận 7, TP.HCM – khu vực tập trung nhiều doanh nghiệp lớn.</p>
</li>
<li>
<p>Được cam kết hỗ trợ thực tập và giới thiệu việc làm sau khi tốt nghiệp.</p>
</li>
</ul>
<p><strong>5. Hồ sơ xét tuyển:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển (theo mẫu của trường).</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT.</p>
</li>
<li>
<p>Bản sao bằng tốt nghiệp THPT hoặc Giấy chứng nhận tốt nghiệp tạm thời.</p>
</li>
</ul>', CAST(N'2026-04-30T21:55:48.740' AS DateTime), 0, 1, N'Tuyển sinh 2025 - Ngành Quản trị Kinh doanh - Xét học bạ THPT', CAST(N'2025-11-30T00:00:00.000' AS DateTime), N'Khoảng 16,5 triệu/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (64, 52, 20, 2, 2025, 80, N'D01,D14,D15', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH NGÔN NGỮ ANH - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN</strong></p>
<p><strong>1. Điều kiện xét tuyển:</strong> &gt; * Tốt nghiệp THPT hoặc tương đương.</p>
<ul>
<li>
<p>Xét học bạ lớp 12 với tổng điểm 3 môn tổ hợp đạt từ 15.0 điểm trở lên.</p>
</li>
</ul>
<p><strong>2. Chương trình đào tạo:</strong> &gt; * Tập trung phát triển toàn diện 4 kỹ năng: Nghe, Nói, Đọc, Viết đạt chuẩn đầu ra tương đương bậc 4 (B2) theo Khung năng lực ngoại ngữ 6 bậc Việt Nam.</p>
<ul>
<li>
<p>Trang bị kiến thức về Tiếng Anh thương mại, biên - phiên dịch, và tiếng Anh chuyên ngành văn phòng/du lịch.</p>
</li>
<li>
<p>Rèn luyện kỹ năng mềm: Giao tiếp quốc tế, thuyết trình, và soạn thảo văn bản bằng tiếng Anh.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp:</strong> &gt; * Chuyên viên văn phòng, trợ lý đối ngoại tại các công ty nước ngoài.</p>
<ul>
<li>
<p>Biên dịch viên, hướng dẫn viên du lịch quốc tế.</p>
</li>
<li>
<p>Nhân viên tại các trung tâm ngoại ngữ hoặc bộ phận chăm sóc khách hàng quốc tế.</p>
</li>
</ul>', CAST(N'2026-04-30T21:57:19.880' AS DateTime), 0, 1, N'Tuyển sinh 2025 - Ngành Ngôn ngữ Anh - Xét học bạ THPT', CAST(N'2025-11-30T00:00:00.000' AS DateTime), N'Khoảng 16,5 - 17,5 triệu/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (65, 52, 20, 2, 2024, 80, N'D01,D14,D15', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH NGÔN NGỮ ANH - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2024)</strong></p>
<p><strong>1. Điều kiện xét tuyển:</strong></p>
<ul>
<li>
<p>Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p>Hình thức xét tuyển: Dựa trên điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp xét tuyển đạt từ 15.0 điểm.</p>
</li>
<li>
<p>Ưu tiên thí sinh có năng khiếu ngoại ngữ và yêu thích môi trường làm việc quốc tế.</p>
</li>
</ul>
<p><strong>2. Mục tiêu đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p>Đào tạo sinh viên sử dụng thành thạo Tiếng Anh trong giao tiếp và công việc (tương đương chuẩn B2 theo khung tham chiếu Châu Âu).</p>
</li>
<li>
<p>Cung cấp kiến thức chuyên sâu về: Tiếng Anh Thương mại, Tiếng Anh Văn phòng, và Biên - Phiên dịch cơ bản.</p>
</li>
<li>
<p>Rèn luyện các kỹ năng bổ trợ: Kỹ năng soạn thảo văn bản hành chính bằng tiếng Anh, kỹ năng thuyết trình và làm việc nhóm trong môi trường đa văn hóa.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp thực tế:</strong></p>
<ul>
<li>
<p>Chuyên viên hành chính, thư ký, trợ lý đối ngoại cho các văn phòng đại diện, công ty nước ngoài.</p>
</li>
<li>
<p>Nhân viên bộ phận chăm sóc khách hàng quốc tế, điều phối viên dự án tại các tổ chức phi chính phủ hoặc doanh nghiệp FDI.</p>
</li>
<li>
<p>Biên dịch viên tại các tòa soạn, nhà xuất bản hoặc làm hướng dẫn viên du lịch quốc tế.</p>
</li>
<li>
<p>Giảng dạy tiếng Anh cơ bản tại các trung tâm ngoại ngữ sau khi bồi dưỡng thêm chứng chỉ nghiệp vụ sư phạm.</p>
</li>
</ul>
<p><strong>4. Hồ sơ xét tuyển:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2024.</p>
</li>
<li>
<p>Học bạ THPT (bản sao công chứng).</p>
</li>
<li>
<p>Bằng tốt nghiệp THPT hoặc Giấy chứng nhận tốt nghiệp tạm thời.</p>
</li>
<li>
<p>Căn cước công dân và ảnh 3x4.</p>
</li>
</ul>', CAST(N'2026-04-30T21:59:10.793' AS DateTime), 0, 1, N'Tuyển sinh 2024 - Ngành Ngôn ngữ Anh - Xét học bạ THPT', CAST(N'2024-12-31T00:00:00.000' AS DateTime), N'15.500.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (66, 52, 9, 2, 2024, 100, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<ol>
<li>
<p><strong>NGÀNH QUẢN TRỊ KINH DOANH - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2024)</strong></p>
<p><strong>1. Điều kiện xét tuyển:</strong></p>
<ul>
<li>
<p>Đã tốt nghiệp THPT hoặc bổ túc THPT.</p>
</li>
<li>
<p>Hình thức xét tuyển chính: Dựa trên kết quả học tập học bạ lớp 12. Tổng điểm trung bình của 3 môn trong tổ hợp xét tuyển đạt từ 15.0 điểm.</p>
</li>
<li>
<p>Thái độ học tập tốt, có định hướng rõ ràng về kinh doanh và quản lý.</p>
</li>
</ul>
<p><strong>2. Chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p>Cung cấp kiến thức toàn diện về quản trị: Quản trị dự án, quản trị rủi ro, quản trị bán hàng và marketing số.</p>
</li>
<li>
<p>Sinh viên được tiếp cận với các tình huống (case study) thực tế từ các doanh nghiệp tại Quận 7 và khu vực lân cận.</p>
</li>
<li>
<p>Phát triển tối đa các kỹ năng mềm thiết yếu: Kỹ năng thuyết phục khách hàng, kỹ năng làm việc nhóm, và tư duy quản lý thời gian hiệu quả.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp thực tế:</strong></p>
<ul>
<li>
<p>Làm việc tại các phòng kinh doanh, phòng dự án, phòng hành chính nhân sự của các công ty tư nhân và tập đoàn đa quốc gia.</p>
</li>
<li>
<p>Đảm nhận vị trí nhân viên tư vấn tài chính, bảo hiểm, hoặc chuyên viên nghiên cứu thị trường.</p>
</li>
<li>
<p>Cơ hội thăng tiến lên các vị trí trưởng nhóm, quản lý cửa hàng sau 1-2 năm làm việc thực tế.<strong></strong></p>
</li>
</ul>
<p><strong>4. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển theo mẫu 2024.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT &amp; Bằng tốt nghiệp THPT.</p>
</li>
<li>
<p>Giấy khai sinh và căn cước công dân (sao y).</p>
</li>
</ul>
.</li>
</ol>', CAST(N'2026-04-30T22:01:35.303' AS DateTime), 0, 1, N'Tuyển sinh 2024 - Ngành Quản trị Kinh doanh - Xét học bạ THPT', CAST(N'2024-12-31T00:00:00.000' AS DateTime), N'15.500.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (67, 52, 1, 2, 2024, 80, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH CÔNG NGHỆ THÔNG TIN - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2024)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p>Đối tượng: Thí sinh đã tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p>Hình thức xét tuyển: Dựa trên điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp xét tuyển đạt từ 15.0 điểm.</p>
</li>
<li>
<p>Ưu tiên các thí sinh có tư duy logic tốt và đam mê khám phá các công nghệ mới.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kỹ thuật lập trình:</strong> Thành thạo các ngôn ngữ phổ biến như Java, PHP, Python và C#.</p>
</li>
<li>
<p><strong>Phát triển Web &amp; Ứng dụng:</strong> Đào tạo từ cơ bản đến nâng cao về thiết kế giao diện (Front-end) và xử lý hệ thống (Back-end).</p>
</li>
<li>
<p><strong>Quản trị mạng &amp; Bảo mật:</strong> Kỹ năng thiết kế, lắp đặt và vận hành hệ thống mạng máy tính cho doanh nghiệp; triển khai các giải pháp bảo mật dữ liệu.</p>
</li>
<li>
<p><strong>Thực hành chuyên sâu:</strong> 70% thời lượng học tập tại phòng Lab với trang thiết bị hiện đại, mô phỏng môi trường làm việc thực tế tại doanh nghiệp.</p>
</li>
</ul>
<p><strong>3. Cơ hội việc làm sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Lập trình viên Web, ứng dụng di động tại các công ty phần mềm.</p>
</li>
<li>
<p>Chuyên viên quản trị hệ thống mạng và hỗ trợ kỹ thuật (IT Helpdesk) tại các cơ quan, tổ chức.</p>
</li>
<li>
<p>Chuyên viên thiết kế đồ họa quảng cáo hoặc quản trị nội dung số trên các nền tảng mạng xã hội.</p>
</li>
<li>
<p>Nhân viên kinh doanh thiết bị công nghệ và giải pháp phần mềm.</p>
</li>
</ul>
<p><strong>4. Lợi thế khi theo học tại trường:</strong></p>
<ul>
<li>
<p>Vị trí trường nằm tại Quận 7, liền kề khu đô thị Phú Mỹ Hưng và Khu chế xuất Tân Thuận, tạo điều kiện thuận lợi cho việc thực tập và tìm kiếm việc làm.</p>
</li>
<li>
<p>Chương trình học ngắn (2.5 năm), tập trung rèn nghề giúp sinh viên sớm tham gia thị trường lao động.</p>
</li>
<li>
<p>Cam kết 100% sinh viên được giới thiệu nơi thực tập và hỗ trợ tìm kiếm việc làm đúng chuyên ngành.</p>
</li>
</ul>
<p><strong>5. Hồ sơ bao gồm:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2024 theo mẫu của nhà trường.</p>
</li>
<li>
<p>Học bạ THPT (Bản sao công chứng).</p>
</li>
<li>
<p>Bằng tốt nghiệp THPT (hoặc Giấy chứng nhận tốt nghiệp tạm thời).</p>
</li>
<li>
<p>02 Bản sao CCCD và 04 ảnh 3x4.</p>
</li>
</ul>', CAST(N'2026-04-30T22:05:27.103' AS DateTime), 0, 1, N'Tuyển sinh 2024 - Ngành Công nghệ Thông tin - Xét học bạ THPT', CAST(N'2024-12-31T00:00:00.000' AS DateTime), N'16.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (68, 52, 17, 2, 2024, 100, N'B00,D08,D01', CAST(16.00 AS Decimal(4, 2)), CAST(16.50 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH ĐIỀU DƯỠNG - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2024)</strong></p>
<p><strong>1. Điều kiện xét tuyển:</strong></p>
<ul>
<li>
<p>Đối tượng: Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p>Hình thức xét tuyển: Dựa trên điểm trung bình học bạ lớp 12 (Tổng 3 môn tổ hợp đạt từ 16.5 điểm trở lên).</p>
</li>
<li>
<p>Yêu cầu: Có sức khỏe tốt, đạo đức nghề nghiệp, lòng nhân ái và sự kiên trì đặc thù của ngành Y tế.</p>
</li>
</ul>
<p><strong>2. Chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức y khoa:</strong> Trang bị nền tảng về giải phẫu, sinh lý, dược lý, vệ sinh phòng bệnh và kiểm soát nhiễm khuẩn.</p>
</li>
<li>
<p><strong>Kỹ năng chuyên môn:</strong> Thực hành thành thạo các kỹ thuật điều dưỡng cơ bản và chuyên sâu (tiêm thuốc, thay băng, đặt thông, chăm sóc vết thương, hồi sức cấp cứu).</p>
</li>
<li>
<p><strong>Chăm sóc lâm sàng:</strong> Đào tạo kỹ năng lập kế hoạch chăm sóc người bệnh, theo dõi tình trạng sức khỏe và hỗ trợ bác sĩ trong quá trình điều trị.</p>
</li>
<li>
<p><strong>Kỹ năng mềm:</strong> Phát triển kỹ năng giao tiếp với bệnh nhân, tâm lý học tiếp xúc và làm việc nhóm trong môi trường bệnh viện.</p>
</li>
</ul>
<p><strong>3. Cơ hội việc làm và Thực tập:</strong></p>
<ul>
<li>
<p><strong>Thực tập:</strong> Sinh viên được thực hành lâm sàng tại các bệnh viện đối tác lớn như Bệnh viện Quận 7, Bệnh viện Nguyễn Tri Phương, Bệnh viện Nhi Đồng...</p>
</li>
<li>
<p><strong>Vị trí công việc:</strong> Điều dưỡng viên tại các bệnh viện, trung tâm y tế, phòng khám đa khoa công lập và tư nhân.</p>
</li>
<li>
<p><strong>Cơ hội quốc tế:</strong> Có thể tham gia chương trình chuyển dịch lao động, làm việc tại Nhật Bản hoặc Đức sau khi tốt nghiệp (theo các thỏa thuận hợp tác của trường).</p>
</li>
</ul>
<p><strong>4. Tại sao nên chọn Điều dưỡng tại BKNSG?</strong></p>
<ul>
<li>
<p>Hệ thống phòng thực hành tiền lâm sàng đầy đủ thiết bị, mô hình hiện đại mô phỏng cơ thể người.</p>
</li>
<li>
<p>Giảng viên là các bác sĩ, điều dưỡng trưởng có nhiều năm kinh nghiệm lâm sàng tại các bệnh viện lớn.</p>
</li>
<li>
<p>Bằng cấp chính quy, đủ điều kiện thi chứng chỉ hành nghề và liên thông lên Đại học khối ngành Sức khỏe.</p>
</li>
</ul>
<p><strong>5. Hồ sơ xét tuyển:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển theo mẫu của trường năm 2024.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT và Bằng tốt nghiệp THPT.</p>
</li>
<li>
<p>Giấy khám sức khỏe từ cấp huyện trở lên.</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4 (phông nền xanh).</p>
</li>
</ul>', CAST(N'2026-04-30T22:19:14.970' AS DateTime), 0, 1, N'Tuyển sinh 2024 - Ngành Điều dưỡng - Xét học bạ THPT', CAST(N'2024-10-30T00:00:00.000' AS DateTime), N'18.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (69, 52, 16, 2, 2024, 120, N'B00,A00,D07', CAST(16.00 AS Decimal(4, 2)), CAST(16.50 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH DƯỢC HỌC - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2024)</strong></p>
<p><strong>1. Điều kiện xét tuyển:</strong></p>
<ul>
<li>
<p>Đối tượng: Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p>Hình thức xét tuyển: Dựa trên điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp xét tuyển đạt từ <strong>16.5 điểm</strong> trở lên.</p>
</li>
<li>
<p>Yêu cầu: Thí sinh cần có tính cẩn thận, trung thực và trách nhiệm cao – những đức tính cốt lõi của một người làm nghề Dược.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo:</strong></p>
<ul>
<li>
<p><strong>Kiến thức cơ sở:</strong> Sinh viên được học về hóa phân tích, hóa hữu cơ, giải phẫu và sinh lý người.</p>
</li>
<li>
<p><strong>Kiến thức chuyên ngành:</strong> Đào tạo sâu về Dược lý học (tác dụng của thuốc), Dược liệu học, Kỹ thuật bào chế các dạng thuốc, Kiểm nghiệm thuốc và Quản lý dược.</p>
</li>
<li>
<p><strong>Kỹ năng nghề nghiệp:</strong> Thành thạo quy trình bảo quản, cung ứng thuốc, hướng dẫn sử dụng thuốc an toàn - hợp lý - hiệu quả cho cộng đồng.</p>
</li>
<li>
<p><strong>Thực hành:</strong> Thời lượng thực hành tại phòng thí nghiệm đạt chuẩn chiếm 70%, kết hợp thực tập thực tế tại các nhà thuốc và khoa Dược bệnh viện.</p>
</li>
</ul>
<p><strong>3. Cơ hội việc làm sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Làm việc tại khoa Dược các bệnh viện, trung tâm y tế từ tuyến cơ sở đến trung ương.</p>
</li>
<li>
<p>Dược sĩ tư vấn tại các hệ thống nhà thuốc lớn (Long Châu, Pharmacity, An Khang...) hoặc tự mở nhà thuốc sau khi đủ điều kiện chứng chỉ hành nghề.</p>
</li>
<li>
<p>Chuyên viên kiểm nghiệm chất lượng thuốc tại các cơ sở sản xuất dược phẩm.</p>
</li>
<li>
<p>Trình dược viên cho các tập đoàn dược phẩm đa quốc gia hoặc doanh nghiệp sản xuất thuốc trong nước.</p>
</li>
</ul>
<p><strong>4. Lợi thế khi theo học tại BKNSG:</strong></p>
<ul>
<li>
<p>Đội ngũ giảng viên là các Dược sĩ CKI, CKII và Thạc sĩ có uy tín, kinh nghiệm lâu năm trong ngành.</p>
</li>
<li>
<p>Bằng cấp chính quy, được Bộ Y tế và Bộ LĐ-TB&amp;XH công nhận, đủ điều kiện liên thông lên Đại học Dược trên toàn quốc.</p>
</li>
<li>
<p>Trường tọa lạc tại Quận 7, giúp sinh viên dễ dàng tiếp cận các cơ hội thực tập tại hệ thống y tế hiện đại của khu vực Nam Sài Gòn.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển theo mẫu năm 2024.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT &amp; Bằng tốt nghiệp (hoặc Giấy chứng nhận tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD, Giấy khai sinh và 04 ảnh 3x4.</p>
</li>
</ul>', CAST(N'2026-04-30T22:20:38.490' AS DateTime), 0, 1, N'Tuyển sinh 2024 - Ngành Dược học - Xét học bạ THPT', CAST(N'2024-10-30T00:00:00.000' AS DateTime), N'18.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (70, 52, 10, 2, 2024, 80, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH KẾ TOÁN - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2024)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc bổ túc văn hóa.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12 của 3 môn thuộc tổ hợp xét tuyển. Tổng điểm đạt từ <strong>15.0 điểm</strong> (trung bình 5.0/môn).</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh có tính cẩn thận, trung thực và tư duy nhạy bén với các con số.</p>
</li>
</ul>
<p><strong>2. Chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức nghiệp vụ:</strong> Trang bị kiến thức từ cơ bản đến chuyên sâu về Kế toán tài chính, Kế toán quản trị, Kế toán thuế, Kiểm toán và Luật kinh tế.</p>
</li>
<li>
<p><strong>Kỹ năng công nghệ:</strong> Thành thạo các phần mềm kế toán phổ biến nhất hiện nay như MISA, FAST và kỹ năng xử lý bảng tính Excel chuyên nghiệp cho kế toán.</p>
</li>
<li>
<p><strong>Thực hành thực tế:</strong> Sinh viên được hướng dẫn lập chứng từ, ghi sổ kế toán, lập báo cáo tài chính và kê khai quyết toán thuế theo đúng quy định hiện hành của Nhà nước.</p>
</li>
<li>
<p><strong>Thời lượng:</strong> 70% thời lượng là thực hành nghề nghiệp, đảm bảo sinh viên vững tay nghề ngay khi ra trường.</p>
</li>
</ul>
<p><strong>3. Cơ hội việc làm sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Chuyên viên kế toán tổng hợp hoặc kế toán phần hành (Kế toán kho, Kế toán thanh toán, Kế toán lương...) tại các doanh nghiệp.</p>
</li>
<li>
<p>Chuyên viên tư vấn thuế, kiểm soát nội bộ cho các tổ chức, công ty tư nhân và tập đoàn.</p>
</li>
<li>
<p>Làm việc tại bộ phận tài chính - kế toán của các cơ quan hành chính sự nghiệp, ngân hàng hoặc các tổ chức tín dụng.</p>
</li>
</ul>
<p><strong>4. Tại sao nên chọn ngành Kế toán tại BKNSG?</strong></p>
<ul>
<li>
<p>Giảng viên là các chuyên gia, kế toán trưởng có nhiều năm kinh nghiệm thực chiến tại các doanh nghiệp lớn.</p>
</li>
<li>
<p>Môi trường học tập năng động, tọa lạc tại Quận 7 - trung tâm giao thương sầm uất, giúp sinh viên dễ dàng tìm kiếm cơ hội thực tập và làm việc.</p>
</li>
<li>
<p>Bằng tốt nghiệp Cao đẳng chính quy có giá trị toàn quốc, đủ điều kiện liên thông lên Đại học cùng khối ngành.</p>
</li>
</ul>
<p><strong>5. Hồ sơ bao gồm:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển theo mẫu năm 2024.</p>
</li>
<li>
<p>Học bạ THPT (bản sao công chứng).</p>
</li>
<li>
<p>Bằng tốt nghiệp hoặc Giấy chứng nhận tốt nghiệp THPT tạm thời.</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4.</p>
</li>
</ul>', CAST(N'2026-04-30T22:22:24.470' AS DateTime), 0, 1, N'Tuyển sinh 2024 - Ngành Kế toán - Xét học bạ THPT', CAST(N'2024-10-30T00:00:00.000' AS DateTime), N'15.500.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (71, 52, 23, 2, 2024, 60, N'A01,D01,D15', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH THIẾT KẾ ĐỒ HỌA - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2024)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh có tư duy thẩm mỹ, yêu thích sự sáng tạo và đam mê ứng dụng công nghệ vào nghệ thuật thị giác.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức nền tảng:</strong> Học về mỹ thuật cơ sở, phối cảnh, bố cục màu sắc, luật xa gần và lịch sử mỹ thuật/design.</p>
</li>
<li>
<p><strong>Kỹ thuật phần mềm:</strong> Làm chủ các công cụ đồ họa chuyên nghiệp thuộc bộ Adobe (Photoshop, Illustrator, InDesign, Premiere).</p>
</li>
<li>
<p><strong>Thiết kế ứng dụng:</strong> Thực hành thiết kế bộ nhận diện thương hiệu (Logo, Namecard), ấn phẩm truyền thông (Poster, Banner), dàn trang báo chí, và xử lý hậu kỳ video cơ bản.</p>
</li>
<li>
<p><strong>Đồ họa kỹ thuật:</strong> Tiếp cận kiến thức về vẽ kỹ thuật và chế bản điện tử trong in ấn.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Chuyên viên thiết kế tại các công ty quảng cáo, truyền thông (Agency) hoặc bộ phận Marketing của doanh nghiệp.</p>
</li>
<li>
<p>Nhân viên thiết kế tại các tòa soạn báo, nhà xuất bản, hoặc công ty in ấn, bao bì.</p>
</li>
<li>
<p>Chuyên viên xử lý hình ảnh, video cho các studio hoặc đơn vị sản xuất nội dung số.</p>
</li>
<li>
<p>Làm việc tự do (Freelancer) trong các lĩnh vực thiết kế logo, nhận diện thương hiệu cá nhân.</p>
</li>
</ul>
<p><strong>4. Tại sao nên chọn Thiết kế Đồ họa tại BKNSG?</strong></p>
<ul>
<li>
<p><strong>Thực hành chiếm ưu thế:</strong> 70% thời lượng học tập trên máy tính cấu hình cao tại phòng Lab hiện đại.</p>
</li>
<li>
<p><strong>Giảng viên chuyên môn:</strong> Đội ngũ thầy cô là những nhà thiết kế, chuyên gia có kinh nghiệm thực chiến trong ngành mỹ thuật công nghiệp.</p>
</li>
<li>
<p><strong>Vị trí đắc địa:</strong> Trường nằm tại Quận 7, khu vực tập trung nhiều công ty sáng tạo và sự kiện truyền thông lớn, giúp sinh viên dễ dàng tiếp cận thực tế.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2024 theo mẫu.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT và Bằng tốt nghiệp (hoặc Giấy chứng nhận tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4 (phông nền trắng).</p>
</li>
</ul>', CAST(N'2026-04-30T22:24:03.643' AS DateTime), 0, 1, N'Tuyển sinh 2024 - Ngành Thiết kế Đồ họa - Xét học bạ THPT', CAST(N'2024-10-30T00:00:00.000' AS DateTime), N'17.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (72, 52, 6, 2, 2024, 80, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH KỸ THUẬT CƠ ĐIỆN TỬ - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2024)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh có tư duy kỹ thuật, yêu thích máy móc, tự động hóa và có khả năng làm việc với các thiết bị điện tử, lập trình.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức tích hợp:</strong> Đào tạo sự kết hợp nhuần nhuyễn giữa kỹ thuật cơ khí, điện tử và công nghệ thông tin.</p>
</li>
<li>
<p><strong>Hệ thống tự động hóa:</strong> Học cách vận hành, bảo trì và lập trình cho các dây chuyền sản xuất tự động, hệ thống điều khiển khí nén - thủy lực.</p>
</li>
<li>
<p><strong>Robot công nghiệp:</strong> Nghiên cứu về cấu trúc, vận hành và lập trình điều khiển tay máy Robot, hệ thống cảm biến thông minh.</p>
</li>
<li>
<p><strong>Kỹ năng thiết kế:</strong> Sử dụng thành thạo các phần mềm thiết kế kỹ thuật (AutoCAD, SolidWorks) và lập trình điều khiển (PLC, vi điều khiển).</p>
</li>
</ul>
<p><strong>3. Cơ hội việc làm sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Kỹ thuật viên vận hành và bảo trì hệ thống sản xuất tự động tại các nhà máy, khu chế xuất.</p>
</li>
<li>
<p>Chuyên viên lắp đặt, sửa chữa và tư vấn kỹ thuật cho các doanh nghiệp cung cấp giải pháp tự động hóa.</p>
</li>
<li>
<p>Nhân viên kỹ thuật tại các bộ phận R&amp;D, thiết kế máy hoặc quản lý quy trình sản xuất công nghiệp.</p>
</li>
<li>
<p>Cơ hội làm việc tại các tập đoàn công nghệ lớn tại Khu công nghệ cao TP.HCM (Samsung, Intel, Nidec...).</p>
</li>
</ul>
<p><strong>4. Tại sao nên chọn Kỹ thuật Cơ điện tử tại BKNSG?</strong></p>
<ul>
<li>
<p><strong>Thực hành thực tế:</strong> Thời lượng thực hành chiếm 70% chương trình tại các xưởng cơ khí và phòng Lab điện tử hiện đại.</p>
</li>
<li>
<p><strong>Kết nối doanh nghiệp:</strong> Trường có mối quan hệ chặt chẽ với các doanh nghiệp tại Quận 7 và khu lân cận, đảm bảo sinh viên được thực tập trong môi trường thực tế.</p>
</li>
<li>
<p><strong>Bằng cấp uy tín:</strong> Bằng Cao đẳng chính quy giúp sinh viên dễ dàng thăng tiến hoặc liên thông lên trình độ Đại học tại các trường kỹ thuật tốp đầu.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2024 (theo mẫu của trường).</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT &amp; Bằng tốt nghiệp (hoặc Giấy chứng nhận tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4 (phông nền xanh).</p>
</li>
</ul>', CAST(N'2026-04-30T22:26:11.280' AS DateTime), 0, 1, N'Tuyển sinh 2024 - Ngành Kỹ thuật Cơ điện tử - Xét học bạ THPT', CAST(N'2024-10-30T00:00:00.000' AS DateTime), N'16.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (73, 52, 16, 2, 2023, 120, N'B00,A00,D07', CAST(15.00 AS Decimal(4, 2)), CAST(16.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH DƯỢC HỌC - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp đạt từ <strong>16.0 điểm</strong> trở lên.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh cần có sự tỉ mỉ, trung thực, tinh thần trách nhiệm và có niềm đam mê với công việc nghiên cứu, chăm sóc sức khỏe.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức cơ sở ngành:</strong> Học về hóa hữu cơ, hóa phân tích, giải phẫu, sinh lý học và thực vật dược.</p>
</li>
<li>
<p><strong>Kiến thức chuyên sâu:</strong> Tập trung vào Dược lý học, Dược liệu học, Kỹ thuật bào chế thuốc, Kiểm nghiệm thuốc và Quản lý kinh tế dược.</p>
</li>
<li>
<p><strong>Kỹ năng thực tế:</strong> Sinh viên được thực hành tại hệ thống phòng thí nghiệm hiện đại, học cách nhận biết dược liệu, bào chế các dạng thuốc cơ bản và kỹ năng tư vấn sử dụng thuốc an toàn cho bệnh nhân.</p>
</li>
<li>
<p><strong>Định hướng ứng dụng:</strong> Chương trình bám sát thực tế thị trường dược phẩm, giúp sinh viên nắm vững quy trình vận hành nhà thuốc đạt chuẩn GPP.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Làm việc tại khoa Dược của các bệnh viện, trung tâm y tế quận/huyện.</p>
</li>
<li>
<p>Dược sĩ tư vấn và bán lẻ tại các nhà thuốc tư nhân hoặc các chuỗi hệ thống nhà thuốc lớn (Long Châu, Pharmacity, An Khang...).</p>
</li>
<li>
<p>Nhân viên kinh doanh và giới thiệu thuốc (Trình dược viên) cho các doanh nghiệp dược phẩm trong và ngoài nước.</p>
</li>
<li>
<p>Làm việc tại các cơ sở sản xuất, kiểm nghiệm và quản lý chất lượng dược phẩm, mỹ phẩm, thực phẩm chức năng.</p>
</li>
</ul>
<p><strong>4. Ưu thế khi theo học tại BKNSG:</strong></p>
<ul>
<li>
<p>Đội ngũ giảng viên là các thạc sĩ, dược sĩ có trình độ chuyên môn cao và kinh nghiệm thực tiễn phong phú.</p>
</li>
<li>
<p>Hệ thống cơ sở vật chất, phòng thực hành chuyên biệt đảm bảo điều kiện học tập tốt nhất cho sinh viên khối ngành sức khỏe.</p>
</li>
<li>
<p>Vị trí tại Quận 7 giúp sinh viên có nhiều cơ hội tiếp cận thực tập tại các bệnh viện lớn và doanh nghiệp dược phẩm uy tín tại khu vực Nam Sài Gòn.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2023 theo mẫu của trường.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT và Bằng tốt nghiệp (hoặc Giấy chứng nhận tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD, Giấy khai sinh và 04 ảnh 3x4 (phông nền trắng).</p>
</li>
</ul>', CAST(N'2026-04-30T22:30:57.240' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Dược học - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'17.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (74, 52, 17, 2, 2023, 100, N'B00,D08,D01', CAST(15.00 AS Decimal(4, 2)), CAST(16.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH ĐIỀU DƯỠNG - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức xét tuyển:</strong> Dựa trên điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp xét tuyển đạt từ <strong>16.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh cần có sức khỏe tốt, tinh thần trách nhiệm và lòng nhân ái đối với người bệnh.</p>
</li>
</ul>
<p><strong>2. Chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức cơ bản:</strong> Học tập các kiến thức nền tảng về Giải phẫu - Sinh lý, Vi sinh - Ký sinh trùng, Dược lý cơ bản và Vệ sinh phòng bệnh.</p>
</li>
<li>
<p><strong>Kỹ thuật điều dưỡng:</strong> Đào tạo bài bản các quy trình chăm sóc người bệnh nội khoa, ngoại khoa, nhi khoa và sản phụ khoa. Sinh viên được huấn luyện kỹ năng sơ cấp cứu, tiêm thuốc, thay băng và quản lý buồng bệnh.</p>
</li>
<li>
<p><strong>Giao tiếp y khoa:</strong> Rèn luyện kỹ năng giao tiếp, tâm lý tiếp xúc với người bệnh và người nhà bệnh nhân, đảm bảo tiêu chuẩn y đức.</p>
</li>
<li>
<p><strong>Thực hành:</strong> 70% thời lượng thực hành tại các phòng mô phỏng tiền lâm sàng của trường và thực tập trực tiếp tại bệnh viện.</p>
</li>
</ul>
<p><strong>3. Cơ hội thực tập và việc làm:</strong></p>
<ul>
<li>
<p><strong>Bệnh viện liên kết:</strong> Sinh viên năm 2023 được bố trí thực tập lâm sàng tại các đơn vị uy tín như Bệnh viện Quận 7, Bệnh viện Nguyễn Tri Phương và các trung tâm y tế khu vực TP.HCM.</p>
</li>
<li>
<p><strong>Cơ hội việc làm:</strong> Làm việc tại các bệnh viện công lập và tư nhân, các phòng khám đa khoa, trung tâm phục hồi chức năng hoặc các trung tâm chăm sóc sức khỏe cộng đồng.</p>
</li>
<li>
<p><strong>Định hướng quốc tế:</strong> Tham gia lộ trình đào tạo tiếng Nhật/tiếng Đức để đi làm việc tại nước ngoài theo chương trình hợp tác lao động điều dưỡng của nhà trường.</p>
</li>
</ul>
<p><strong>4. Ưu điểm học tập tại BKNSG:</strong></p>
<ul>
<li>
<p>Đội ngũ giảng viên giàu kinh nghiệm, là các bác sĩ và điều dưỡng trưởng từ các bệnh viện lớn trực tiếp giảng dạy.</p>
</li>
<li>
<p>Bằng Cao đẳng Điều dưỡng chính quy có giá trị pháp lý để thi chứng chỉ hành nghề và học liên thông lên Đại học Y Dược theo quy định của Bộ Y tế.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2023 theo mẫu.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT.</p>
</li>
<li>
<p>Bằng tốt nghiệp THPT hoặc Giấy chứng nhận tốt nghiệp tạm thời.</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4.</p>
</li>
</ul>', CAST(N'2026-04-30T22:34:42.097' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Điều dưỡng - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'17.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (75, 52, 1, 2, 2023, 150, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH CÔNG NGHỆ THÔNG TIN - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh đã tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức xét tuyển:</strong> Dựa trên điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp xét tuyển đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Ưu tiên:</strong> Thí sinh có niềm đam mê với máy tính, yêu thích lập trình và có tư duy logic tốt.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức cơ bản:</strong> Trang bị nền tảng về cấu trúc dữ liệu, giải thuật, hệ điều hành và kiến trúc máy tính.</p>
</li>
<li>
<p><strong>Phát triển phần mềm:</strong> Sinh viên được đào tạo chuyên sâu các ngôn ngữ lập trình phổ biến (Java, PHP, C#, Python) để xây dựng ứng dụng Windows và Website.</p>
</li>
<li>
<p><strong>Mạng và Bảo mật:</strong> Kỹ năng thiết kế, vận hành hệ thống mạng máy tính (CCNA) và các giải pháp bảo mật thông tin cho doanh nghiệp vừa và nhỏ.</p>
</li>
<li>
<p><strong>Đồ họa ứng dụng:</strong> Kiến thức cơ bản về thiết kế giao diện (UI/UX) và xử lý hình ảnh hỗ trợ cho việc phát triển sản phẩm công nghệ.</p>
</li>
</ul>
<p><strong>3. Cơ hội việc làm sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Lập trình viên (Developer) tại các công ty gia công phần mềm.</p>
</li>
<li>
<p>Chuyên viên quản trị hệ thống mạng, kỹ thuật viên máy tính (IT Support) tại các cơ quan, trường học, doanh nghiệp.</p>
</li>
<li>
<p>Chuyên viên kiểm thử phần mềm (Tester) hoặc quản trị cơ sở dữ liệu.</p>
</li>
<li>
<p>Nhân viên triển khai giải pháp ERP hoặc tư vấn giải pháp chuyển đổi số cho doanh nghiệp.</p>
</li>
</ul>
<p><strong>4. Tại sao chọn ngành CNTT tại BKNSG năm 2023?</strong></p>
<ul>
<li>
<p><strong>Học phí ổn định:</strong> Mức học phí được đánh giá là phù hợp nhất trong khu vực Quận 7 so với chất lượng đào tạo.</p>
</li>
<li>
<p><strong>Thực hành thực tế:</strong> Nhà trường chú trọng việc học đi đôi với hành, sinh viên được thực hành trên hệ thống phòng máy cấu hình cao, cài đặt các phần mềm bản quyền chuyên dụng.</p>
</li>
<li>
<p><strong>Vị trí thuận lợi:</strong> Gần khu đô thị Phú Mỹ Hưng và Khu chế xuất Tân Thuận, nơi tập trung hàng ngàn doanh nghiệp có nhu cầu nhân lực IT lớn.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2023 theo mẫu của trường.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT &amp; Bằng tốt nghiệp (hoặc Giấy chứng nhận tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4 (phông nền trắng).</p>
</li>
</ul>', CAST(N'2026-04-30T22:35:55.050' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Công nghệ Thông tin - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'15.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (76, 52, 6, 2, 2023, 80, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH KỸ THUẬT CƠ ĐIỆN TỬ - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc bổ túc văn hóa.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh có tư duy kỹ thuật, yêu thích sự tìm tòi về máy móc, thiết bị tự động và có niềm đam mê với công nghệ robot.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Sự giao thoa kỹ thuật:</strong> Đào tạo kiến thức tích hợp giữa cơ khí chính xác, điện tử điều khiển và lập trình máy tính.</p>
</li>
<li>
<p><strong>Hệ thống điều khiển:</strong> Học cách vận hành và lập trình PLC, vi điều khiển để điều khiển các hệ thống máy móc tự động trong công nghiệp.</p>
</li>
<li>
<p><strong>Thiết kế &amp; Mô phỏng:</strong> Sử dụng thành thạo các phần mềm AutoCAD, SolidWorks để thiết kế mô hình máy và các hệ thống khí nén - thủy lực.</p>
</li>
<li>
<p><strong>Thực hành nghề nghiệp:</strong> Sinh viên dành 70% thời gian tại xưởng thực hành để trực tiếp lắp ráp, sửa chữa và vận hành các robot công nghiệp, dây chuyền sản xuất tự động.</p>
</li>
</ul>
<p><strong>3. Cơ hội việc làm sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Kỹ thuật viên bảo trì, vận hành máy móc tại các nhà máy sản xuất tự động hóa.</p>
</li>
<li>
<p>Chuyên viên lắp đặt và chuyển giao công nghệ tại các công ty cung cấp thiết bị kỹ thuật, máy công nghiệp.</p>
</li>
<li>
<p>Nhân viên kỹ thuật tại bộ phận sản xuất, quản lý chất lượng (QA/QC) trong các doanh nghiệp cơ khí điện tử.</p>
</li>
<li>
<p>Làm việc tại các tập đoàn lớn trong các khu công nghiệp, khu chế xuất Tân Thuận và Hiệp Phước.</p>
</li>
</ul>
<p><strong>4. Lợi thế khi theo học tại BKNSG năm 2023:</strong></p>
<ul>
<li>
<p><strong>Chương trình tinh gọn:</strong> Tập trung vào các kỹ năng cốt lõi doanh nghiệp cần, rút ngắn thời gian học lý thuyết.</p>
</li>
<li>
<p><strong>Môi trường năng động:</strong> Trường nằm tại khu vực Quận 7, liền kề nhiều doanh nghiệp công nghệ, tạo điều kiện thuận lợi cho sinh viên đi thực tập và làm thêm đúng chuyên môn từ năm thứ 2.</p>
</li>
<li>
<p><strong>Hỗ trợ đầu ra:</strong> Cam kết giới thiệu nơi thực tập và hỗ trợ tìm kiếm việc làm cho sinh viên có thái độ học tập tốt.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển theo mẫu năm 2023.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT &amp; Bằng tốt nghiệp (hoặc Giấy chứng nhận tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD, Giấy khai sinh và 04 ảnh 3x4.</p>
</li>
</ul>', CAST(N'2026-04-30T22:36:50.177' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Kỹ thuật Cơ điện tử - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'15.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (77, 52, 5, 2, 2023, 60, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH KỸ THUẬT ĐIỆN TỬ - VIỄN THÔNG - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp xét tuyển đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh yêu thích khoa học kỹ thuật, có tính kiên trì, tỉ mỉ và tư duy logic tốt để làm việc với các mạch điện và hệ thống truyền dẫn.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức cơ sở:</strong> Đào tạo nền tảng về linh kiện điện tử, mạch điện cơ bản, kỹ thuật số và đo lường điện tử.</p>
</li>
<li>
<p><strong>Hệ thống viễn thông:</strong> Học về kỹ thuật truyền dẫn, mạng thông tin di động (4G/5G), vi ba vệ tinh và lắp đặt hệ thống cáp quang.</p>
</li>
<li>
<p><strong>Thiết kế &amp; Lập trình:</strong> Thực hành thiết kế mạch in (PCB) bằng phần mềm chuyên dụng và lập trình vi điều khiển cho các thiết bị điện tử thông minh.</p>
</li>
<li>
<p><strong>Bảo trì &amp; Sửa chữa:</strong> Kỹ năng chẩn đoán lỗi và sửa chữa các thiết bị đầu cuối, hệ thống tổng đài và các thiết bị thu phát sóng viễn thông.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Kỹ thuật viên vận hành và bảo trì trạm phát sóng (BTS) cho các nhà mạng lớn như Viettel, VNPT, FPT.</p>
</li>
<li>
<p>Chuyên viên kỹ thuật tại các công ty sản xuất linh kiện điện tử, thiết bị thông minh.</p>
</li>
<li>
<p>Nhân viên lắp đặt và quản lý hệ thống camera giám sát, tổng đài nội bộ và mạng máy tính cho doanh nghiệp.</p>
</li>
<li>
<p>Làm việc tại bộ phận kỹ thuật của các đài phát thanh, truyền hình hoặc các công ty cung cấp giải pháp IoT (Internet vạn vật).</p>
</li>
</ul>
<p><strong>4. Tại sao nên chọn ngành này tại BKNSG?</strong></p>
<ul>
<li>
<p><strong>Thực hành thực tế:</strong> Sinh viên được làm việc trực tiếp trên các bộ thí nghiệm hiện đại, máy hiện sóng và máy đo kiểm chuyên dụng.</p>
</li>
<li>
<p><strong>Kết nối nghề nghiệp:</strong> Trường hợp tác với nhiều doanh nghiệp tại Khu chế xuất Tân Thuận (Quận 7), giúp sinh viên dễ dàng tiếp cận các thiết bị công nghệ mới và cơ hội việc làm ngay sau khi ra trường.</p>
</li>
<li>
<p><strong>Bằng cấp:</strong> Bằng tốt nghiệp Cao đẳng chính quy, đủ điều kiện tham gia thị trường lao động kỹ thuật cao hoặc liên thông lên các trường Đại học kỹ thuật lớn.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2023 theo mẫu của trường.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT &amp; Bằng tốt nghiệp (hoặc Giấy chứng nhận tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD, Giấy khai sinh và 04 ảnh 3x4 (phông nền trắng).</p>
</li>
</ul>', CAST(N'2026-04-30T22:37:54.010' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Kỹ thuật Điện tử - Viễn thông - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'15.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (78, 52, 7, 2, 2023, 50, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH XÂY DỰNG DÂN DỤNG &amp; CÔNG NGHIỆP - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc bổ túc văn hóa.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12 của 3 môn thuộc tổ hợp xét tuyển. Tổng điểm đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh có sức khỏe tốt, không ngại làm việc thực địa, có tư duy hình khối và khả năng tính toán cơ bản.</p>
</li>
</ul>
<p><strong>2. Chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức kỹ thuật:</strong> Trang bị kiến thức về cơ học cơ sở, sức bền vật liệu, cấu tạo kiến trúc và vật liệu xây dựng.</p>
</li>
<li>
<p><strong>Kỹ năng chuyên môn:</strong> Đào tạo kỹ thuật thi công bê tông, cốt thép, kỹ thuật xây tô, hoàn thiện công trình dân dụng và công nghiệp.</p>
</li>
<li>
<p><strong>Công cụ hỗ trợ:</strong> Sinh viên được học cách đọc và triển khai bản vẽ kỹ thuật trên các phần mềm chuyên dụng như AutoCAD và các phần mềm dự toán công trình.</p>
</li>
<li>
<p><strong>Quản lý dự án:</strong> Cung cấp kiến thức cơ bản về lập hồ sơ dự thầu, đo bóc khối lượng và quản lý an toàn lao động trên công trường.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Kỹ thuật viên giám sát thi công (giám sát hiện trường) tại các công trình xây dựng nhà ở, nhà xưởng.</p>
</li>
<li>
<p>Nhân viên kỹ thuật tại bộ phận quản lý dự án, ban bồi thường giải phóng mặt bằng.</p>
</li>
<li>
<p>Chuyên viên bóc tách khối lượng và lập dự toán tại các công ty tư vấn thiết kế và xây dựng.</p>
</li>
<li>
<p>Đội trưởng thi công hoặc quản lý tổ đội tại các đơn vị thầu xây dựng vừa và nhỏ.</p>
</li>
</ul>
<p><strong>4. Tại sao nên chọn ngành Xây dựng tại BKNSG?</strong></p>
<ul>
<li>
<p><strong>Học từ thực tế:</strong> Chương trình chú trọng thực hành tại xưởng và tham quan thực tế các công trình đang thi công, giúp sinh viên không bỡ ngỡ khi ra trường.</p>
</li>
<li>
<p><strong>Môi trường kết nối:</strong> Tọa lạc tại Quận 7 - nơi có tốc độ đô thị hóa cực nhanh với nhiều dự án bất động sản lớn, tạo cơ hội thực tập và làm thêm phong phú cho sinh viên.</p>
</li>
<li>
<p><strong>Bằng cấp:</strong> Bằng Cao đẳng chính quy, đảm bảo đủ điều kiện hành nghề và thuận tiện cho việc liên thông lên kỹ sư xây dựng tại các trường Đại học.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2023 (theo mẫu của trường).</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT &amp; Bằng tốt nghiệp (hoặc Giấy chứng nhận tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4 (phông nền trắng).</p>
</li>
</ul>', CAST(N'2026-04-30T22:39:02.090' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Xây dựng Dân dụng & Công nghiệp - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'15.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (79, 52, 10, 2, 2023, 80, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH KẾ TOÁN - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét tuyển dựa trên học bạ lớp 12. Tổng điểm 3 môn trong tổ hợp xét tuyển đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh cần sự cẩn thận, trung thực, yêu thích làm việc với các con số và có tư duy logic tốt.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Nghiệp vụ chuyên môn:</strong> Đào tạo từ cơ bản đến nâng cao về Kế toán tài chính, Kế toán quản trị, Kế toán thuế, và Kiểm toán đại cương.</p>
</li>
<li>
<p><strong>Kỹ năng ứng dụng:</strong> Sinh viên được thực hành trực tiếp trên các chứng từ thực tế, học cách lập sổ sách, báo cáo tài chính và quyết toán thuế theo đúng quy định hiện hành.</p>
</li>
<li>
<p><strong>Công cụ hỗ trợ:</strong> Thành thạo các phần mềm kế toán phổ biến (MISA, FAST) và xử lý dữ liệu chuyên sâu trên Excel.</p>
</li>
<li>
<p><strong>Thời lượng:</strong> Chương trình tinh gọn với 70% thời lượng là thực hành, giúp sinh viên nắm vững tay nghề ngay từ khi còn ngồi trên ghế nhà trường.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Nhân viên kế toán tại các phòng ban: Kế toán thanh toán, kế toán kho, kế toán tiền lương, hoặc kế toán tổng hợp trong các doanh nghiệp tư nhân và nhà nước.</p>
</li>
<li>
<p>Chuyên viên tư vấn thuế, nhân viên giao dịch ngân hàng hoặc kiểm soát viên nội bộ.</p>
</li>
<li>
<p>Làm việc tại bộ phận tài chính của các cơ quan hành chính sự nghiệp, trường học, bệnh viện.</p>
</li>
<li>
<p>Cơ hội thăng tiến lên vị trí Kế toán trưởng hoặc Trưởng phòng tài chính sau khi tích lũy đủ kinh nghiệm thực tế.</p>
</li>
</ul>
<p><strong>4. Tại sao nên chọn học Kế toán tại BKNSG năm 2023?</strong></p>
<ul>
<li>
<p><strong>Học phí hợp lý:</strong> Mức học phí cạnh tranh và ổn định, hỗ trợ tối đa cho sinh viên trong suốt quá trình học tập.</p>
</li>
<li>
<p><strong>Đội ngũ giảng viên:</strong> Các thầy cô có học vị cao và nhiều năm kinh nghiệm làm kế toán trưởng tại các tập đoàn lớn trực tiếp hướng dẫn.</p>
</li>
<li>
<p><strong>Vị trí thuận lợi:</strong> Trường nằm ngay trung tâm Quận 7, gần nhiều công ty và văn phòng đại diện, tạo điều kiện cực kỳ thuận lợi cho việc thực tập và tìm việc làm thêm.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2023 (theo mẫu của trường).</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT.</p>
</li>
<li>
<p>Bằng tốt nghiệp THPT hoặc Giấy chứng nhận tốt nghiệp tạm thời.</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4 (phông nền trắng).</p>
</li>
</ul>', CAST(N'2026-04-30T22:39:45.930' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Kế toán - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'15.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (80, 52, 13, 2, 2023, 100, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH LOGISTICS &amp; QUẢN LÝ CHUỖI CUNG ỨNG - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12 của 3 môn thuộc tổ hợp xét tuyển. Tổng điểm đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh có tư duy hệ thống, khả năng chịu áp lực tốt, yêu thích công việc điều phối và có khả năng giao tiếp, xử lý tình huống linh hoạt.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức cốt lõi:</strong> Đào tạo về quy trình vận tải đa phương thức, nghiệp vụ ngoại thương, quản trị kho hàng và quản trị chuỗi cung ứng toàn cầu.</p>
</li>
<li>
<p><strong>Kỹ năng nghiệp vụ:</strong> Sinh viên được thực hành nghiệp vụ giao nhận vận tải, khai báo hải quan điện tử, lập kế hoạch thu mua và kỹ năng đàm phán hợp đồng thương mại quốc tế.</p>
</li>
<li>
<p><strong>Công cụ hỗ trợ:</strong> Tiếp cận và sử dụng các phần mềm quản lý kho, quản lý đơn hàng và tin học văn phòng chuyên sâu trong ngành vận tải.</p>
</li>
<li>
<p><strong>Tiếng Anh chuyên ngành:</strong> Chú trọng đào tạo từ vựng và văn phong tiếng Anh dùng trong giao dịch quốc tế và chứng từ xuất nhập khẩu.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Nhân viên hiện trường hoặc nhân viên chứng từ tại các công ty Forwarder, công ty chuyển phát nhanh và đại lý vận tải.</p>
</li>
<li>
<p>Chuyên viên quản lý kho bãi, nhân viên kiểm soát hàng hóa tại các trung tâm phân phối và cảng biển.</p>
</li>
<li>
<p>Nhân viên thu mua (Procurement), nhân viên kinh doanh cước (Sales Logistics) hoặc chuyên viên khai báo hải quan.</p>
</li>
<li>
<p>Làm việc tại các phòng xuất nhập khẩu của các doanh nghiệp sản xuất trong và ngoài nước.</p>
</li>
</ul>
<p><strong>4. Tại sao nên chọn ngành Logistics tại BKNSG năm 2023?</strong></p>
<ul>
<li>
<p><strong>Vị trí chiến lược:</strong> Trường nằm tại Quận 7 - ngay &quot;cửa ngõ&quot; cảng biển và các khu chế xuất lớn của TP.HCM, giúp sinh viên có cơ hội thực hành và thực tập tại các bãi cảng, kho bãi thực tế.</p>
</li>
<li>
<p><strong>Thực hành thực chiến:</strong> Chương trình được thiết kế giảm lý thuyết, tăng thời lượng thực tập tại doanh nghiệp để sinh viên nắm bắt quy trình vận hành chuỗi cung ứng thực tế.</p>
</li>
<li>
<p><strong>Kết nối đầu ra:</strong> Trường ký kết hợp tác với nhiều doanh nghiệp Logistics lớn, cam kết hỗ trợ giới thiệu việc làm ngay sau khi tốt nghiệp.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2023 theo mẫu.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT &amp; Bằng tốt nghiệp (hoặc Giấy chứng nhận tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4 (phông nền trắng).</p>
</li>
</ul>', CAST(N'2026-04-30T22:41:22.320' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Logistics & Quản lý Chuỗi cung ứng - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'15.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (81, 52, 12, 2, 2023, 100, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH MARKETING - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh năng động, có khả năng giao tiếp tốt, yêu thích sự sáng tạo và nhạy bén với các xu hướng xã hội.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức cốt lõi:</strong> Đào tạo về nghiên cứu thị trường, hành vi khách hàng, quản trị thương hiệu và chiến lược marketing hỗn hợp (4P/7P).</p>
</li>
<li>
<p><strong>Digital Marketing:</strong> Thực hành các công cụ marketing hiện đại như chạy quảng cáo (Facebook/Google Ads), tối ưu hóa công cụ tìm kiếm (SEO), Content Marketing và quản trị mạng xã hội.</p>
</li>
<li>
<p><strong>Kỹ năng mềm:</strong> Rèn luyện kỹ năng thuyết trình, làm việc nhóm, đàm phán thương lượng và lập kế hoạch tổ chức sự kiện truyền thông.</p>
</li>
<li>
<p><strong>Thực hành:</strong> Sinh viên thực hiện các dự án thực tế, xây dựng kế hoạch marketing cho sản phẩm cụ thể và tham gia các kỳ thực tập tại doanh nghiệp ngay từ năm thứ 2.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Chuyên viên tại các bộ phận: Truyền thông (PR), quảng cáo, chăm sóc khách hàng, nghiên cứu thị trường.</p>
</li>
<li>
<p>Nhân viên Content Marketing, quản trị Fanpage và kênh Tiktok cho doanh nghiệp.</p>
</li>
<li>
<p>Chuyên viên tổ chức sự kiện, quản trị thương hiệu hoặc nhân viên kinh doanh (Sales).</p>
</li>
<li>
<p>Làm việc tại các công ty chuyên về quảng cáo (Agency) hoặc phòng marketing của các doanh nghiệp thuộc mọi lĩnh vực.</p>
</li>
</ul>
<p><strong>4. Tại sao nên chọn ngành Marketing tại BKNSG năm 2023?</strong></p>
<ul>
<li>
<p><strong>Chương trình thực tế:</strong> Giảm lý thuyết hàn lâm, tập trung vào các kỹ năng mà doanh nghiệp thực sự cần trong thời đại kinh tế số.</p>
</li>
<li>
<p><strong>Vị trí thuận lợi:</strong> Trường nằm gần trung tâm thương mại và tài chính Quận 7, nơi tập trung nhiều doanh nghiệp lớn, tạo điều kiện cho sinh viên dễ dàng tiếp cận các dự án thực tế.</p>
</li>
<li>
<p><strong>Học phí ổn định:</strong> Mức học phí phù hợp với điều kiện kinh tế của đa số gia đình, đi kèm cam kết chất lượng đào tạo và hỗ trợ việc làm sau ra trường.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2023 (theo mẫu của trường).</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT &amp; Bằng tốt nghiệp (hoặc Giấy chứng nhận tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4 (phông nền trắng).</p>
</li>
</ul>', CAST(N'2026-04-30T22:42:14.973' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Marketing - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'15.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (82, 52, 9, 2, 2023, 120, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH QUẢN TRỊ KINH DOANH - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh yêu thích lĩnh vực kinh doanh, có tư duy phản biện, khả năng giao tiếp và định hướng trở thành nhà quản lý trong tương lai.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức nền tảng:</strong> Cung cấp kiến thức tổng quan về quản trị học, kinh tế vi mô/vĩ mô, luật kinh tế và đạo đức kinh doanh.</p>
</li>
<li>
<p><strong>Kỹ năng quản trị:</strong> Đào tạo chuyên sâu về quản trị nhân sự, quản trị tài chính doanh nghiệp, quản trị sản xuất và quản trị bán hàng.</p>
</li>
<li>
<p><strong>Kỹ năng bổ trợ:</strong> Rèn luyện tư duy chiến lược, kỹ năng đàm phán, giải quyết vấn đề và quản trị dự án thực tế.</p>
</li>
<li>
<p><strong>Thực hành:</strong> Sinh viên được tham gia các buổi mô phỏng doanh nghiệp, thực tập tại các phòng ban chức năng để hiểu rõ quy trình vận hành của một đơn vị kinh doanh.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Chuyên viên tại các bộ phận: Kinh doanh, Marketing, Nhân sự, Hành chính hoặc Kế hoạch - Tài chính.</p>
</li>
<li>
<p>Trợ lý cho các giám đốc bộ phận, ban điều hành tại các doanh nghiệp vừa và nhỏ.</p>
</li>
<li>
<p>Chuyên viên tư vấn kinh doanh hoặc nhân viên phát triển thị trường.</p>
</li>
<li>
<p>Tự khởi nghiệp và quản lý mô hình kinh doanh cá nhân.</p>
</li>
</ul>
<p><strong>4. Tại sao nên chọn Quản trị Kinh doanh tại BKNSG năm 2023?</strong></p>
<ul>
<li>
<p><strong>Chương trình linh hoạt:</strong> Cập nhật liên tục các xu hướng kinh tế mới, giúp sinh viên không chỉ nắm vững lý thuyết mà còn thành thạo các công cụ quản lý hiện đại.</p>
</li>
<li>
<p><strong>Môi trường thực tiễn:</strong> Trường tọa lạc tại Quận 7 - &quot;lá phổi&quot; kinh tế phía Nam TP.HCM, nơi hội tụ hàng loạt tập đoàn lớn, tạo lợi thế tuyệt đối cho việc thực tập và kết nối việc làm.</p>
</li>
<li>
<p><strong>Cơ sở vật chất:</strong> Hệ thống phòng học máy lạnh, thư viện số và các khu vực thảo luận nhóm hiện đại, hỗ trợ tối đa cho việc học tập năng động.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2023 (theo mẫu của trường).</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT &amp; Bằng tốt nghiệp (hoặc Giấy chứng nhận tốt nghiệp tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4 (phông nền trắng).</p>
</li>
</ul>', CAST(N'2026-04-30T22:43:21.047' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Quản trị Kinh doanh - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'15.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (83, 52, 11, 2, 2023, 60, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH TÀI CHÍNH - NGÂN HÀNG - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh có tính cẩn thận, trung thực, khả năng tính toán tốt và tư duy nhạy bén với các biến động kinh tế thị trường.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kiến thức chuyên ngành:</strong> Đào tạo sâu về quản trị ngân hàng thương mại, tài chính doanh nghiệp, nghiệp vụ thanh toán quốc tế và kinh doanh ngoại hối.</p>
</li>
<li>
<p><strong>Nghiệp vụ thực tế:</strong> Sinh viên được hướng dẫn các quy trình thẩm định tín dụng, giao dịch kế toán ngân hàng, quản trị rủi ro và đầu tư chứng khoán cơ bản.</p>
</li>
<li>
<p><strong>Kỹ năng mềm:</strong> Rèn luyện kỹ năng giao tiếp khách hàng, kỹ năng thuyết phục, bán hàng qua điện thoại (telesales) và kỹ năng sử dụng các phần mềm tài chính chuyên dụng.</p>
</li>
<li>
<p><strong>Thực hành:</strong> 70% thời lượng là thực hành tại các phòng mô phỏng giao dịch ngân hàng, giúp sinh viên làm quen với áp lực và quy trình làm việc thực tế.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Giao dịch viên, nhân viên tư vấn tài chính hoặc chuyên viên quan hệ khách hàng tại các Ngân hàng thương mại.</p>
</li>
<li>
<p>Nhân viên bộ phận tín dụng, kế toán thanh toán hoặc nhân viên quản lý kho quỹ.</p>
</li>
<li>
<p>Chuyên viên tài chính tại các doanh nghiệp, công ty chứng khoán, công ty bảo hiểm hoặc các quỹ tín dụng.</p>
</li>
<li>
<p>Nhân viên thu hồi nợ, chuyên viên thẩm định giá hoặc làm việc tại bộ phận kế hoạch - tài chính của các đơn vị hành chính sự nghiệp.</p>
</li>
</ul>
<p><strong>4. Ưu thế khi chọn Tài chính - Ngân hàng tại BKNSG năm 2023:</strong></p>
<ul>
<li>
<p><strong>Chương trình sát thực tế:</strong> Giáo trình được biên soạn dựa trên nhu cầu tuyển dụng thực tế của các tổ chức tài chính hiện nay.</p>
</li>
<li>
<p><strong>Môi trường học tập:</strong> Tọa lạc tại Quận 7 - nơi tập trung nhiều chi nhánh ngân hàng lớn và các công ty tài chính quốc tế, mang lại lợi thế lớn trong việc tìm kiếm nơi thực tập.</p>
</li>
<li>
<p><strong>Bằng cấp:</strong> Bằng Cao đẳng chính quy giúp sinh viên nhanh chóng tham gia thị trường lao động hoặc tiếp tục học liên thông lên Đại học để nâng cao trình độ.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển 2023 (theo mẫu của trường).</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT &amp; Bằng tốt nghiệp (hoặc Giấy chứng nhận tạm thời).</p>
</li>
<li>
<p>Bản sao CCCD, Giấy khai sinh và 04 ảnh 3x4 (phông nền trắng).</p>
</li>
</ul>', CAST(N'2026-04-30T22:44:59.467' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Tài chính - Ngân hàng - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'15.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (84, 52, 20, 2, 2023, 80, N'D01,D14,D15', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH NGÔN NGỮ ANH - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2023)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc bổ túc văn hóa.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét điểm trung bình học bạ lớp 12. Tổng điểm 3 môn tổ hợp đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh có niềm đam mê học hỏi ngoại ngữ, mong muốn làm việc trong môi trường đa văn hóa và giao tiếp tốt.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Kỹ năng ngôn ngữ:</strong> Đào tạo chuyên sâu 4 kỹ năng Nghe - Nói - Đọc - Viết theo chuẩn năng lực ngoại ngữ bậc 4 (B2 - CEFR).</p>
</li>
<li>
<p><strong>Tiếng Anh chuyên ngành:</strong> Tập trung vào các lĩnh vực thực tiễn như Tiếng Anh thương mại, Tiếng Anh du lịch, Tiếng Anh văn phòng và kỹ thuật Biên - Phiên dịch cơ bản.</p>
</li>
<li>
<p><strong>Kỹ năng nghề nghiệp:</strong> Trang bị kiến thức về văn hóa các nước nói tiếng Anh, kỹ năng soạn thảo văn bản, hợp đồng bằng tiếng Anh và kỹ năng giao tiếp trong kinh doanh quốc tế.</p>
</li>
<li>
<p><strong>Phương pháp học:</strong> Tăng cường thời lượng thực hành giao tiếp trực tiếp với giảng viên kinh nghiệm, giúp sinh viên tự tin phản xạ trong tình huống thực tế.</p>
</li>
</ul>
<p><strong>3. Cơ hội nghề nghiệp sau tốt nghiệp:</strong></p>
<ul>
<li>
<p>Chuyên viên hành chính, thư ký, trợ lý đối ngoại tại các công ty nước ngoài hoặc các tập đoàn đa quốc gia.</p>
</li>
<li>
<p>Nhân viên điều phối dự án, nhân viên kinh doanh xuất nhập khẩu hoặc chuyên viên tại các tổ chức phi chính phủ.</p>
</li>
<li>
<p>Biên dịch viên tại các tòa soạn, công ty dịch thuật hoặc hướng dẫn viên du lịch quốc tế.</p>
</li>
<li>
<p>Giảng dạy tiếng Anh cơ bản tại các trung tâm ngoại ngữ (sau khi bổ sung chứng chỉ nghiệp vụ sư phạm).</p>
</li>
</ul>
<p><strong>4. Tại sao nên chọn Ngôn ngữ Anh tại BKNSG năm 2023?</strong></p>
<ul>
<li>
<p><strong>Học phí tiết kiệm:</strong> Mức học phí được duy trì ổn định, phù hợp với năng lực tài chính của nhiều gia đình nhưng vẫn đảm bảo chất lượng giảng dạy.</p>
</li>
<li>
<p><strong>Vị trí đắc địa:</strong> Trường nằm tại trung tâm Quận 7, khu vực tập trung nhiều công ty nước ngoài và khách sạn quốc tế, tạo cơ hội thực tập ngay tại môi trường nói tiếng Anh chuyên nghiệp.</p>
</li>
<li>
<p><strong>Bằng cấp chính quy:</strong> Sinh viên tốt nghiệp nhận bằng Cao đẳng chính quy, đủ điều kiện học liên thông lên Đại học tại các trường thành viên hoặc các trường liên kết.</p>
</li>
</ul>
<p><strong>5. Thành phần hồ sơ:</strong></p>
<ul>
<li>
<p>Phiếu đăng ký xét tuyển theo mẫu năm 2023.</p>
</li>
<li>
<p>Bản sao công chứng Học bạ THPT.</p>
</li>
<li>
<p>Bằng tốt nghiệp THPT hoặc Giấy chứng nhận tốt nghiệp tạm thời.</p>
</li>
<li>
<p>Bản sao CCCD và 04 ảnh 3x4 (phông nền trắng).</p>
</li>
</ul>', CAST(N'2026-04-30T22:46:35.200' AS DateTime), 0, 1, N'Tuyển sinh 2023 - Ngành Ngôn ngữ Anh - Xét học bạ THPT', CAST(N'2023-12-31T00:00:00.000' AS DateTime), N'15.000.000 VNĐ/năm')
INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (85, 52, 12, 2, 2024, 80, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH MARKETING - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2024)</strong></p>
