INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (88, 52, 2, 2, 2024, 80, N'A00,A01,D01', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'47 Đường số 2, Khu dân cư ven sông, P. Bình Thuận, Quận 7, TP.HCM', N'<p><strong>NGÀNH KỸ THUẬT PHẦN MỀM - CAO ĐẲNG BÁCH KHOA NAM SÀI GÒN (HỆ CHÍNH QUY 2024)</strong></p>
<p><strong>1. Điều kiện và Phương thức xét tuyển:</strong></p>
<ul>
<li>
<p><strong>Đối tượng:</strong> Thí sinh tốt nghiệp THPT hoặc tương đương.</p>
</li>
<li>
<p><strong>Hình thức:</strong> Xét tuyển dựa trên điểm trung bình học bạ lớp 12. Tổng điểm 3 môn trong tổ hợp đạt từ <strong>15.0 điểm</strong>.</p>
</li>
<li>
<p><strong>Yêu cầu:</strong> Thí sinh có tư duy logic, yêu thích lập trình, ham học hỏi các công nghệ mới và có khả năng tập trung cao.</p>
</li>
</ul>
<p><strong>2. Nội dung chương trình đào tạo trọng tâm:</strong></p>
<ul>
<li>
<p><strong>Ngôn ngữ lập trình:</strong> Làm chủ các ngôn ngữ phổ biến nhất hiện nay như Java, C#, Python, JavaScript và các Framework hiện đại.</p>
</li>
<li>
<p><strong>Phát triển ứng dụng:</strong> Đào tạo quy trình xây dựng phần mềm hoàn chỉnh, từ ứng dụng Desktop, ứng dụng di động (Android/iOS) đến các hệ thống Web chuyên sâu.</p>
</li>
<li>
<p><strong>Cơ sở dữ liệu:</strong> Kỹ năng thiết kế và quản trị cơ sở dữ liệu (SQL Server, MySQL, MongoDB), đảm bảo hệ thống vận hành mượt mà và an toàn.</p>
</li>
<li>
<p><strong>Kiểm thử &amp; Chất lượng:</strong> Học cách kiểm thử phần mềm (Tester/QA), quản lý dự án theo mô hình Agile/Scrum và quy trình bảo trì phần mềm chuyên nghiệp.</p>
