INSERT [dbo].[tbl_TinTuyenSinh] ([MaTin], [MaTruong], [MaChuyenNganh], [MaPhuongThuc], [NamTuyenSinh], [ChiTieu], [ToHopMonHoc], [DiemChuanNamTruoc], [DiemChuanNamNay], [ChenhLechDiem], [LoaiHinhDaoTao], [CoSoDaoTao], [MoTa], [NgayDang], [LuotXem], [TrangThai], [TieuDe], [HanNop], [HocPhi]) VALUES (118, 53, 2, 4, 2024, 100, N'', CAST(15.00 AS Decimal(4, 2)), CAST(15.00 AS Decimal(4, 2)), NULL, N'Chính quy', N'Số 189, Đường Cao Bang, Phường Gia Cẩm, TP. Việt Trì, Tỉnh Phú Thọ', N'<p><strong>NGÀNH KỸ THUẬT PHẦN MỀM - CAO ĐẲNG NGHỀ PHÚ THỌ (HỆ CHÍNH QUY 2024)</strong></p>
