INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (1, N'Đại học Bách khoa Hà Nội', N'Số 1 Đại Cồ Việt, Hai Bà Trưng, Hà Nội', N'TP Hà Nội', 1, 1, N'0327978484', N'https://hust.edu.vn', N'/Resources/Images/truong/bach-khoa-ha-noi_logo_7e370bcc.png', N'/Resources/Images/truong/bach-khoa-ha-noi_cover_640bc0d8.jpg', N'<p>Đại học B&amp;amp;aacute;ch khoa H&amp;amp;agrave; Nội l&amp;amp;agrave; một trong những cơ sở gi&amp;amp;aacute;o dục đại học kỹ thuật &amp;amp;ndash; c&amp;amp;ocirc;ng nghệ h&amp;amp;agrave;ng đầu tại Việt Nam, được th&amp;amp;agrave;nh lập từ năm 1956 v&amp;amp;agrave; c&amp;amp;oacute; bề d&amp;amp;agrave;y lịch sử ph&amp;amp;aacute;t triển hơn 65 năm. Trường nổi tiếng với chất lượng đ&amp;amp;agrave;o tạo vượt trội trong c&amp;amp;aacute;c lĩnh vực mũi nhọn như C&amp;amp;ocirc;ng nghệ th&amp;amp;ocirc;ng tin, Kỹ thuật điện &amp;amp;ndash; điện tử, Cơ kh&amp;amp;iacute;, Tự động h&amp;amp;oacute;a, H&amp;amp;oacute;a học, Vật liệu v&amp;amp;agrave; Kinh tế &amp;amp;ndash; Quản l&amp;amp;yacute;. Chương tr&amp;amp;igrave;nh đ&amp;amp;agrave;o tạo tại đ&amp;amp;acirc;y lu&amp;amp;ocirc;n được cập nhật theo xu hướng quốc tế, ch&amp;amp;uacute; trọng kết hợp giữa l&amp;amp;yacute; thuyết v&amp;amp;agrave; thực h&amp;amp;agrave;nh, gi&amp;amp;uacute;p sinh vi&amp;amp;ecirc;n ph&amp;amp;aacute;t triển to&amp;amp;agrave;n diện về kiến thức chuy&amp;amp;ecirc;n m&amp;amp;ocirc;n, tư duy s&amp;amp;aacute;ng tạo v&amp;amp;agrave; kỹ năng l&amp;amp;agrave;m việc thực tế. B&amp;amp;ecirc;n cạnh đ&amp;amp;oacute;, Đại học B&amp;amp;aacute;ch khoa H&amp;amp;agrave; Nội sở hữu đội ngũ giảng vi&amp;amp;ecirc;n gi&amp;amp;agrave;u kinh nghiệm, trong đ&amp;amp;oacute; c&amp;amp;oacute; nhiều gi&amp;amp;aacute;o sư, tiến sĩ đầu ng&amp;amp;agrave;nh, c&amp;amp;ugrave;ng hệ thống cơ sở vật chất hiện đại gồm c&amp;amp;aacute;c ph&amp;amp;ograve;ng th&amp;amp;iacute; nghiệm, trung t&amp;amp;acirc;m nghi&amp;amp;ecirc;n cứu v&amp;amp;agrave; khu học tập ti&amp;amp;ecirc;n tiến. Trường cũng активно mở rộng hợp t&amp;amp;aacute;c quốc tế với nhiều trường đại học v&amp;amp;agrave; tổ chức lớn tr&amp;amp;ecirc;n thế giới, mang đến cơ hội học tập, trao đổi v&amp;amp;agrave; l&amp;amp;agrave;m việc trong m&amp;amp;ocirc;i trường to&amp;amp;agrave;n cầu cho sinh vi&amp;amp;ecirc;n. Kh&amp;amp;ocirc;ng chỉ nổi bật về học thuật, m&amp;amp;ocirc;i trường học tập tại đ&amp;amp;acirc;y c&amp;amp;ograve;n rất năng động với nhiều c&amp;amp;acirc;u lạc bộ, hoạt động ngoại kh&amp;amp;oacute;a v&amp;amp;agrave; phong tr&amp;amp;agrave;o sinh vi&amp;amp;ecirc;n s&amp;amp;ocirc;i nổi, gi&amp;amp;uacute;p sinh vi&amp;amp;ecirc;n r&amp;amp;egrave;n luyện kỹ năng mềm v&amp;amp;agrave; ph&amp;amp;aacute;t triển bản th&amp;amp;acirc;n. Với uy t&amp;amp;iacute;n v&amp;amp;agrave; chất lượng đ&amp;amp;atilde; được khẳng định, Đại học B&amp;amp;aacute;ch khoa H&amp;amp;agrave; Nội lu&amp;amp;ocirc;n l&amp;amp;agrave; điểm đến mơ ước của nhiều thế hệ học sinh, đồng thời l&amp;amp;agrave; nơi đ&amp;amp;agrave;o tạo ra nguồn nh&amp;amp;acirc;n lực chất lượng cao, đ&amp;amp;oacute;ng g&amp;amp;oacute;p quan trọng cho sự ph&amp;amp;aacute;t triển kinh tế &amp;amp;ndash; x&amp;amp;atilde; hội của đất nước.</p>', N'Hơn 32.000 sinh viên', 1, N'bach-khoa-ha-noi', 1, CAST(N'2026-04-27T22:44:03.620' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (2, N'Đại học Quốc gia Hà Nội', N'Số 144, đường Xuân Thủy, phường Cầu Giấy, Hà Nội,  Việt Nam', N'Hà Nội', 1, 1, N'024 3754 7670', N'https://vnu.edu.vn', N'/Resources/Images/truong/dai-hoc-quoc-gia-ha-noi_logo_44d48405.jpg', N'/Resources/Images/truong/dai-hoc-quoc-gia-ha-noi_cover_b3f251e0.jpg', N'Đại học Quốc gia Hà Nội (VNU) là một trong những hệ thống đại học trọng điểm quốc gia hàng đầu Việt Nam, được thành lập với mục tiêu đào tạo nguồn nhân lực chất lượng cao, nghiên cứu khoa học và chuyển giao tri thức phục vụ phát triển đất nước. Với vị thế đặc biệt trực thuộc Chính phủ, Đại học Quốc gia Hà Nội có quyền tự chủ cao trong đào tạo, nghiên cứu và hợp tác quốc tế, đồng thời giữ vai trò tiên phong trong hệ thống giáo dục đại học Việt Nam.

Đại học Quốc gia Hà Nội không phải là một trường đơn lẻ mà là một hệ thống gồm nhiều trường đại học thành viên, viện nghiên cứu và khoa trực thuộc, tiêu biểu như: Trường Đại học Khoa học Tự nhiên, Trường Đại học Khoa học Xã hội và Nhân văn, Trường Đại học Công nghệ, Trường Đại học Kinh tế, Trường Đại học Ngoại ngữ… Nhờ đó, VNU cung cấp hệ thống ngành học đa dạng, bao phủ từ khoa học tự nhiên, kỹ thuật – công nghệ đến khoa học xã hội, kinh tế và ngoại ngữ.

Chương trình đào tạo tại đây được xây dựng theo định hướng chuẩn quốc tế, chú trọng phát triển tư duy nghiên cứu, khả năng sáng tạo và kỹ năng hội nhập cho sinh viên. Nhiều chương trình đào tạo chất lượng cao, tài năng, tiên tiến được giảng dạy bằng tiếng Anh, giúp sinh viên có cơ hội tiếp cận với môi trường học tập hiện đại và mở rộng cơ hội nghề nghiệp trong tương lai.

Đại học Quốc gia Hà Nội sở hữu đội ngũ giảng viên, nhà khoa học hàng đầu cả nước, trong đó có nhiều giáo sư, phó giáo sư, tiến sĩ có uy tín trong và ngoài nước. Bên cạnh đó, hệ thống cơ sở vật chất, phòng thí nghiệm, trung tâm nghiên cứu được đầu tư đồng bộ, đặc biệt là khu đô thị đại học tại Hòa Lạc đang được phát triển theo mô hình đại học thông minh, hiện đại bậc nhất Việt Nam.

Ngoài hoạt động học tập và nghiên cứu, môi trường sinh viên tại VNU cũng rất năng động với nhiều câu lạc bộ học thuật, kỹ năng, nghệ thuật và các chương trình giao lưu quốc tế. Đây là điều kiện thuận lợi để sinh viên phát triển toàn diện cả về kiến thức chuyên môn lẫn kỹ năng mềm.

Với uy tín và chất lượng đã được khẳng định qua nhiều năm, Đại học Quốc gia Hà Nội luôn nằm trong nhóm các cơ sở giáo dục đại học hàng đầu khu vực, là nơi đào tạo ra nhiều nhà khoa học, chuyên gia, lãnh đạo và nhân lực chất lượng cao, góp phần quan trọng vào sự phát triển bền vững của Việt Nam trong thời kỳ hội nhập quốc tế.', N'Hơn 45.000 sinh viên', 1, N'dai-hoc-quoc-gia-ha-noi', 1, CAST(N'2026-03-29T22:52:44.127' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (3, N'Đại học Kinh tế Quốc dân', N'207 Giải Phóng, Hai Bà Trưng, Hà Nội', N'Hà Nội', 1, 1, N'024 3628 0280', N'https://neu.edu.vn', N'/Resources/Images/truong/kinh-te-quoc-dan_logo_859d4d72.png', N'/Resources/Images/truong/kinh-te-quoc-dan_cover_d34b96e2.jpg', N'Đại học Kinh tế Quốc dân (NEU) là một trong những trường đại học hàng đầu tại Việt Nam trong lĩnh vực kinh tế, quản lý và kinh doanh, trực thuộc Bộ Giáo dục và Đào tạo. Được thành lập từ năm 1956, trường có bề dày lịch sử lâu đời và giữ vai trò quan trọng trong việc đào tạo nguồn nhân lực chất lượng cao cho nền kinh tế quốc dân.

Trường nổi bật với hệ thống ngành đào tạo đa dạng, bao gồm các lĩnh vực như Kinh tế học, Quản trị kinh doanh, Tài chính – Ngân hàng, Kế toán, Marketing, Thương mại điện tử, Kinh doanh quốc tế và nhiều ngành mới đáp ứng xu thế hội nhập như Kinh tế số, Phân tích dữ liệu kinh doanh. Chương trình đào tạo được xây dựng theo hướng hiện đại, gắn liền với thực tiễn, chú trọng phát triển tư duy chiến lược, kỹ năng phân tích và năng lực quản lý cho sinh viên.

Đại học Kinh tế Quốc dân cũng là một trong những trường tiên phong triển khai các chương trình đào tạo chất lượng cao, chương trình tiên tiến và liên kết quốc tế với nhiều trường đại học uy tín trên thế giới. Điều này giúp sinh viên có cơ hội học tập trong môi trường quốc tế, tiếp cận với kiến thức mới và nâng cao khả năng sử dụng ngoại ngữ, đặc biệt là tiếng Anh trong lĩnh vực kinh tế – kinh doanh.

Bên cạnh đội ngũ giảng viên có trình độ cao, giàu kinh nghiệm, trường còn sở hữu hệ thống cơ sở vật chất hiện đại với giảng đường lớn, thư viện điện tử, trung tâm nghiên cứu và khu học tập tiên tiến. Đặc biệt, khuôn viên trường tại Hà Nội được đánh giá là một trong những cơ sở đào tạo khang trang và hiện đại hàng đầu trong khối ngành kinh tế tại Việt Nam.

Ngoài học tập, sinh viên tại NEU còn được tham gia vào nhiều hoạt động ngoại khóa, câu lạc bộ học thuật, sự kiện doanh nghiệp và các cuộc thi lớn về kinh tế – kinh doanh. Đây là môi trường lý tưởng giúp sinh viên phát triển toàn diện về kỹ năng mềm, mở rộng mối quan hệ và tích lũy kinh nghiệm thực tế.

Với uy tín và chất lượng đào tạo đã được khẳng định qua nhiều năm, Đại học Kinh tế Quốc dân luôn nằm trong top các trường đào tạo kinh tế hàng đầu Việt Nam, là cái nôi của nhiều nhà lãnh đạo, chuyên gia kinh tế và doanh nhân thành đạt, đóng góp tích cực vào sự phát triển của nền kinh tế đất nước.', N'Hơn 48.000 sinh viên', 1, N'kinh-te-quoc-dan', 1, CAST(N'2026-03-29T22:47:02.777' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (4, N'Đại học Y Hà Nội', N'1 Tôn Thất Tùng, Đống Đa, Hà Nội', N'Hà Nội', 1, 1, N'024 3852 6722', N'https://hmu.edu.vn', N'/Resources/Images/truong/y-ha-noi_logo_677bf055.jpg', N'/Resources/Images/truong/y-ha-noi_cover_c5e5cad7.jpg', N'Đại học Y Hà Nội là một trong những trường đại học y khoa hàng đầu và lâu đời nhất tại Việt Nam, được thành lập từ năm 1902 với tiền thân là Trường Y khoa Đông Dương. Trải qua hơn một thế kỷ hình thành và phát triển, trường đã khẳng định vị thế tiên phong trong lĩnh vực đào tạo nhân lực y tế chất lượng cao, nghiên cứu khoa học và chăm sóc sức khỏe cộng đồng.

Đại học Y Hà Nội nổi bật với các ngành đào tạo chuyên sâu như Y đa khoa, Răng – Hàm – Mặt, Y học dự phòng, Điều dưỡng, Xét nghiệm y học, Y học cổ truyền và nhiều chuyên ngành y khoa khác. Chương trình đào tạo tại trường có tính đặc thù cao, kết hợp chặt chẽ giữa lý thuyết và thực hành lâm sàng tại các bệnh viện lớn, giúp sinh viên không chỉ nắm vững kiến thức chuyên môn mà còn rèn luyện kỹ năng nghề nghiệp và y đức – yếu tố cốt lõi trong ngành y.

Trường sở hữu đội ngũ giảng viên là các giáo sư, bác sĩ, chuyên gia đầu ngành có nhiều năm kinh nghiệm trong giảng dạy và điều trị. Đồng thời, hệ thống cơ sở vật chất, phòng thí nghiệm, trung tâm nghiên cứu và đặc biệt là mạng lưới bệnh viện thực hành liên kết giúp sinh viên có môi trường học tập thực tế, tiếp cận trực tiếp với bệnh nhân và các tình huống y khoa đa dạng.

Bên cạnh đó, Đại học Y Hà Nội còn активно mở rộng hợp tác quốc tế với nhiều trường đại học, tổ chức y tế uy tín trên thế giới, tạo điều kiện cho sinh viên tham gia các chương trình trao đổi, nghiên cứu và nâng cao trình độ chuyên môn theo chuẩn quốc tế.

Không chỉ chú trọng đào tạo chuyên môn, nhà trường còn đề cao việc rèn luyện đạo đức nghề nghiệp, tinh thần trách nhiệm và lòng nhân ái của người thầy thuốc. Với uy tín và chất lượng đào tạo hàng đầu, Đại học Y Hà Nội là lựa chọn mơ ước của nhiều thí sinh theo đuổi ngành y, đồng thời là cái nôi đào tạo ra hàng ngàn bác sĩ, chuyên gia y tế xuất sắc, đóng góp to lớn cho sự nghiệp chăm sóc và bảo vệ sức khỏe nhân dân.', N'Hơn 10.000 sinh viên', 1, N'y-ha-noi', 1, CAST(N'2026-03-29T22:58:18.960' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (5, N'Học viện Công nghệ Bưu chính Viễn thông', N'Km10, Đường Nguyễn Trãi, Hà Đông, Hà Nội', N'Hà Nội', 1, 1, N'024 3755 2016', N'https://ptit.edu.vn', N'/Resources/Images/truong/hoc-vien-buu-chinh-vien-thong_logo_c4cdf484.png', N'/Resources/Images/truong/hoc-vien-buu-chinh-vien-thong_cover_200214e3.jpg', N'Học viện Công nghệ Bưu chính Viễn thông (PTIT) là một trong những cơ sở đào tạo hàng đầu tại Việt Nam trong lĩnh vực công nghệ thông tin, điện tử – viễn thông và truyền thông số. Trường trực thuộc Bộ Thông tin và Truyền thông Việt Nam, có vai trò quan trọng trong việc đào tạo nguồn nhân lực chất lượng cao phục vụ cho sự phát triển của ngành công nghệ và hạ tầng số quốc gia.

Học viện được thành lập từ năm 1997 trên nền tảng của các cơ sở đào tạo lâu đời trong ngành bưu chính – viễn thông, với hai cơ sở chính tại Hà Nội và TP.HCM. PTIT nổi bật với các ngành đào tạo mũi nhọn như Công nghệ thông tin, An toàn thông tin, Kỹ thuật điện tử – viễn thông, Truyền thông đa phương tiện, Công nghệ Internet vạn vật (IoT) và Khoa học dữ liệu. Chương trình đào tạo được thiết kế theo hướng thực tiễn, bám sát nhu cầu doanh nghiệp và xu hướng công nghệ mới như AI, Big Data, chuyển đổi số.

Đội ngũ giảng viên của Học viện bao gồm nhiều giáo sư, tiến sĩ có chuyên môn cao, giàu kinh nghiệm giảng dạy và nghiên cứu. Bên cạnh đó, nhà trường cũng hợp tác chặt chẽ với các tập đoàn công nghệ lớn trong và ngoài nước, tạo điều kiện cho sinh viên được tham gia thực tập, dự án thực tế và cơ hội việc làm ngay sau khi tốt nghiệp.

Cơ sở vật chất của PTIT được đầu tư hiện đại với hệ thống phòng lab, trung tâm nghiên cứu và hạ tầng công nghệ tiên tiến, đáp ứng tốt nhu cầu học tập và sáng tạo của sinh viên. Ngoài ra, môi trường học tập tại đây rất năng động với nhiều câu lạc bộ công nghệ, hoạt động học thuật và các cuộc thi sáng tạo, giúp sinh viên phát triển kỹ năng mềm và tư duy đổi mới.

Với định hướng trở thành trường đại học nghiên cứu hàng đầu về công nghệ và truyền thông, Học viện Công nghệ Bưu chính Viễn thông ngày càng khẳng định vị thế của mình trong hệ thống giáo dục đại học Việt Nam, đồng thời là lựa chọn lý tưởng cho những sinh viên đam mê công nghệ và mong muốn phát triển sự nghiệp trong lĩnh vực số hóa.', N'Hơn 25.000 sinh viên', 1, N'hoc-vien-buu-chinh-vien-thong', 1, CAST(N'2026-03-29T22:59:46.517' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (6, N'Đại học Đà Nẵng', N'41 Lê Duẩn, Hải Châu, Đà Nẵng', N'Đà Nẵng', 2, 1, N'0236 382 2041', N'https://ud.edu.vn', N'/Resources/Images/truong/dai-hoc-da-nang_logo_ed73eafe.png', N'/Resources/Images/truong/dai-hoc-da-nang_cover_b9e3246d.jpg', N'Đại học Đà Nẵng là một trong những đại học vùng trọng điểm quốc gia tại Việt Nam, đóng vai trò quan trọng trong đào tạo nguồn nhân lực chất lượng cao và nghiên cứu khoa học cho khu vực miền Trung – Tây Nguyên. Được thành lập năm 1994 trên cơ sở tổ chức lại các trường đại học thành viên, Đại học Đà Nẵng hoạt động theo mô hình đại học đa ngành, đa lĩnh vực với nhiều trường đại học thành viên và đơn vị trực thuộc.

Hiện nay, Đại học Đà Nẵng bao gồm nhiều trường thành viên tiêu biểu như Trường Đại học Bách khoa - Đại học Đà Nẵng, Trường Đại học Kinh tế - Đại học Đà Nẵng, Trường Đại học Ngoại ngữ - Đại học Đà Nẵng, Trường Đại học Sư phạm - Đại học Đà Nẵng cùng nhiều viện nghiên cứu và trung tâm đào tạo khác. Hệ thống đào tạo đa dạng, bao phủ các lĩnh vực như kỹ thuật – công nghệ, kinh tế – quản lý, sư phạm, ngoại ngữ, khoa học tự nhiên và xã hội, đáp ứng nhu cầu học tập phong phú của sinh viên.

Chương trình đào tạo của Đại học Đà Nẵng được xây dựng theo hướng hiện đại, gắn liền với thực tiễn và nhu cầu của thị trường lao động. Nhiều chương trình chất lượng cao và chương trình liên kết quốc tế được triển khai, tạo điều kiện cho sinh viên tiếp cận kiến thức tiên tiến, nâng cao trình độ ngoại ngữ và cơ hội hội nhập toàn cầu. Bên cạnh đó, nhà trường luôn chú trọng phát triển hoạt động nghiên cứu khoa học, đổi mới sáng tạo và hợp tác với doanh nghiệp, góp phần thúc đẩy chuyển giao công nghệ và phát triển kinh tế khu vực.

Đại học Đà Nẵng sở hữu hệ thống cơ sở vật chất ngày càng được đầu tư hiện đại với các khu giảng đường, phòng thí nghiệm, thư viện và ký túc xá phục vụ tốt cho việc học tập và sinh hoạt của sinh viên. Môi trường học tập tại đây năng động, thân thiện với nhiều hoạt động ngoại khóa, câu lạc bộ học thuật, văn hóa – nghệ thuật và thể thao, giúp sinh viên phát triển toàn diện cả về kiến thức, kỹ năng và nhân cách.

Với vị thế là trung tâm đào tạo lớn của miền Trung, Đại học Đà Nẵng đã và đang đào tạo hàng chục nghìn cử nhân, kỹ sư, thạc sĩ và tiến sĩ mỗi năm, đóng góp quan trọng vào sự phát triển kinh tế – xã hội của khu vực và cả nước, đồng thời từng bước khẳng định vị thế trong hệ thống giáo dục đại học khu vực và quốc tế.', N'Hơn 55.000 sinh viên', 1, N'dai-hoc-da-nang', 1, CAST(N'2026-03-29T22:38:54.863' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (7, N'Đại học Huế', N'Số 3 Lê Lợi, phường Vĩnh Ninh, quận Thuận Hóa, Huế, Việt Nam', N'Thừa Thiên Huế', 2, 1, N'0234 382 2735', N'https://hueuni.edu.vn', N'/Resources/Images/truong/dai-hoc-hue_logo_67b62a5a.png', N'/Resources/Images/truong/dai-hoc-hue_cover_d1f75edc.jpg', N'Đại học Huế là một trong những đại học vùng trọng điểm quốc gia tại Việt Nam, trực thuộc Bộ Giáo dục và Đào tạo, có vai trò quan trọng trong đào tạo nguồn nhân lực chất lượng cao cho khu vực miền Trung – Tây Nguyên và cả nước. Được thành lập từ năm 1957 và tái cấu trúc theo mô hình đại học vùng từ năm 1994, Đại học Huế hiện là một hệ thống giáo dục đa ngành, đa lĩnh vực với nhiều trường đại học thành viên và khoa trực thuộc.

Hệ thống của Đại học Huế bao gồm nhiều đơn vị đào tạo uy tín như Trường Đại học Khoa học Huế, Trường Đại học Sư phạm Huế, Trường Đại học Y Dược Huế, Trường Đại học Kinh tế Huế, Trường Đại học Ngoại ngữ Huế cùng nhiều khoa, viện và trung tâm nghiên cứu khác. Nhờ đó, trường cung cấp đa dạng ngành học từ khoa học tự nhiên, kỹ thuật, y dược, sư phạm đến kinh tế, xã hội và nhân văn.

Đại học Huế nổi bật với chất lượng đào tạo gắn liền với nghiên cứu khoa học và phục vụ cộng đồng. Đội ngũ giảng viên gồm nhiều giáo sư, phó giáo sư, tiến sĩ có trình độ cao, giàu kinh nghiệm giảng dạy và nghiên cứu. Cơ sở vật chất của trường ngày càng được đầu tư hiện đại, bao gồm hệ thống giảng đường, phòng thí nghiệm, bệnh viện thực hành (đối với khối ngành y dược) và thư viện phục vụ học tập, nghiên cứu hiệu quả.

Bên cạnh hoạt động học thuật, môi trường sinh viên tại Đại học Huế mang đậm bản sắc văn hóa cố đô, kết hợp hài hòa giữa truyền thống và hiện đại. Sinh viên có nhiều cơ hội tham gia các hoạt động ngoại khóa, nghiên cứu khoa học, giao lưu quốc tế và các chương trình trao đổi với nhiều trường đại học trên thế giới. Điều này giúp sinh viên phát triển toàn diện cả về kiến thức chuyên môn, kỹ năng mềm và tư duy hội nhập.

Với uy tín lâu năm và hệ thống đào tạo toàn diện, Đại học Huế không chỉ là trung tâm giáo dục lớn của miền Trung mà còn là nơi đào tạo ra nhiều thế hệ trí thức, bác sĩ, nhà giáo, nhà nghiên cứu và chuyên gia đóng góp quan trọng cho sự phát triển kinh tế – xã hội của đất nước.', N'Hơn 40.000 sinh viên', 1, N'dai-hoc-hue', 1, CAST(N'2026-03-29T22:45:40.373' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (8, N'Đại học Bách khoa TP.HCM', N'268 Lý Thường Kiệt, Quận 10, TP.HCM', N'TP Hồ Chí Minh', 3, 1, N'0838651670', N'https://hcmut.edu.vn', N'/Resources/Images/truong/bach-khoa-tphcm_logo_bd04788d.png', N'/Resources/Images/truong/bach-khoa-tphcm_cover_213b9dd1.jpg', N'<p>Đại học B&amp;aacute;ch khoa TP.HCM (HCMUT) l&amp;agrave; một trong những trường đại học kỹ thuật &amp;ndash; c&amp;ocirc;ng nghệ h&amp;agrave;ng đầu tại Việt Nam, trực thuộc Đại học Quốc gia TP.HCM. Được th&amp;agrave;nh lập từ năm 1957, trường c&amp;oacute; bề d&amp;agrave;y lịch sử ph&amp;aacute;t triển l&amp;acirc;u đời v&amp;agrave; giữ vai tr&amp;ograve; ti&amp;ecirc;n phong trong đ&amp;agrave;o tạo, nghi&amp;ecirc;n cứu khoa học cũng như chuyển giao c&amp;ocirc;ng nghệ tại khu vực ph&amp;iacute;a Nam v&amp;agrave; cả nước. Trường nổi bật với hệ thống ng&amp;agrave;nh đ&amp;agrave;o tạo đa dạng v&amp;agrave; chuy&amp;ecirc;n s&amp;acirc;u trong c&amp;aacute;c lĩnh vực mũi nhọn như C&amp;ocirc;ng nghệ th&amp;ocirc;ng tin, Kỹ thuật điện &amp;ndash; điện tử, Cơ kh&amp;iacute;, X&amp;acirc;y dựng, H&amp;oacute;a học, M&amp;ocirc;i trường, Quản l&amp;yacute; c&amp;ocirc;ng nghiệp v&amp;agrave; nhiều ng&amp;agrave;nh kỹ thuật hiện đại kh&amp;aacute;c. Chương tr&amp;igrave;nh đ&amp;agrave;o tạo được thiết kế theo định hướng ứng dụng v&amp;agrave; hội nhập quốc tế, trong đ&amp;oacute; c&amp;oacute; nhiều chương tr&amp;igrave;nh chất lượng cao, chương tr&amp;igrave;nh ti&amp;ecirc;n tiến giảng dạy bằng tiếng Anh, gi&amp;uacute;p sinh vi&amp;ecirc;n dễ d&amp;agrave;ng tiếp cận với m&amp;ocirc;i trường học tập v&amp;agrave; l&amp;agrave;m việc to&amp;agrave;n cầu. Đại học B&amp;aacute;ch khoa TP.HCM sở hữu đội ngũ giảng vi&amp;ecirc;n tr&amp;igrave;nh độ cao, bao gồm nhiều gi&amp;aacute;o sư, ph&amp;oacute; gi&amp;aacute;o sư, tiến sĩ được đ&amp;agrave;o tạo trong v&amp;agrave; ngo&amp;agrave;i nước. B&amp;ecirc;n cạnh đ&amp;oacute;, cơ sở vật chất của trường được đầu tư hiện đại với hệ thống ph&amp;ograve;ng th&amp;iacute; nghiệm, xưởng thực h&amp;agrave;nh, trung t&amp;acirc;m nghi&amp;ecirc;n cứu v&amp;agrave; thư viện ti&amp;ecirc;n tiến, đ&amp;aacute;p ứng tốt nhu cầu học tập v&amp;agrave; nghi&amp;ecirc;n cứu của sinh vi&amp;ecirc;n. Ngo&amp;agrave;i hoạt động học thuật, trường c&amp;ograve;n c&amp;oacute; m&amp;ocirc;i trường sinh vi&amp;ecirc;n năng động với h&amp;agrave;ng trăm c&amp;acirc;u lạc bộ, đội nh&amp;oacute;m về học thuật, kỹ năng, nghệ thuật v&amp;agrave; thể thao. C&amp;aacute;c hoạt động n&amp;agrave;y gi&amp;uacute;p sinh vi&amp;ecirc;n ph&amp;aacute;t triển to&amp;agrave;n diện cả về chuy&amp;ecirc;n m&amp;ocirc;n lẫn kỹ năng mềm như l&amp;agrave;m việc nh&amp;oacute;m, tư duy s&amp;aacute;ng tạo v&amp;agrave; khả năng th&amp;iacute;ch nghi. Với uy t&amp;iacute;n được khẳng định qua nhiều năm, Đại học B&amp;aacute;ch khoa TP.HCM lu&amp;ocirc;n nằm trong top c&amp;aacute;c trường kỹ thuật h&amp;agrave;ng đầu Việt Nam, l&amp;agrave; nơi đ&amp;agrave;o tạo ra nhiều kỹ sư, chuy&amp;ecirc;n gia v&amp;agrave; nh&amp;agrave; quản l&amp;yacute; giỏi, đ&amp;oacute;ng g&amp;oacute;p quan trọng cho sự ph&amp;aacute;t triển của nền kinh tế v&amp;agrave; c&amp;ocirc;ng nghiệp h&amp;oacute;a &amp;ndash; hiện đại h&amp;oacute;a đất nước.</p>', N'Hơn 40.000 sinh viên', 1, N'bach-khoa-tphcm', 1, CAST(N'2026-04-27T22:52:13.827' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (9, N'Đại học Kinh tế TP.HCM', N'59C Nguyễn Đình Chiểu, phường Xuân Hòa, Thành phố Hồ Chí Minh, Việt Nam', N'TP. Hồ Chí Minh', 3, 1, N'028 3829 8946', N'https://ueh.edu.vn', N'/Resources/Images/truong/kinh-te-tphcm_logo_6bd80ec1.jpg', N'/Resources/Images/truong/kinh-te-tphcm_cover_804a4506.jpg', N'Đại học Kinh tế TP.HCM (UEH) là một trong những trường đại học hàng đầu tại Việt Nam trong lĩnh vực kinh tế, quản lý và kinh doanh, trực thuộc hệ thống giáo dục quốc dân. Được thành lập từ năm 1976, UEH đã trải qua gần 50 năm phát triển và không ngừng khẳng định vị thế của mình trong đào tạo nguồn nhân lực chất lượng cao, nghiên cứu khoa học và tư vấn chính sách kinh tế cho khu vực phía Nam cũng như cả nước.

Trường đào tạo đa dạng các ngành thuộc khối kinh tế – xã hội như Kinh tế học, Quản trị kinh doanh, Tài chính – Ngân hàng, Kế toán, Marketing, Thương mại điện tử, Luật kinh tế và Quản lý công. Chương trình đào tạo được thiết kế theo định hướng hiện đại, gắn liền với thực tiễn doanh nghiệp và hội nhập quốc tế, trong đó có nhiều chương trình chất lượng cao và chương trình liên kết quốc tế được giảng dạy hoàn toàn bằng tiếng Anh, giúp sinh viên nâng cao năng lực cạnh tranh trong môi trường toàn cầu.

Đại học Kinh tế TP.HCM sở hữu đội ngũ giảng viên có trình độ chuyên môn cao, nhiều người được đào tạo tại các quốc gia phát triển như Mỹ, Anh, Úc, Pháp… Bên cạnh đó, UEH chú trọng đầu tư cơ sở vật chất hiện đại với hệ thống giảng đường thông minh, thư viện điện tử, trung tâm nghiên cứu và không gian học tập sáng tạo, mang đến môi trường học tập chuyên nghiệp và năng động cho sinh viên.

Không chỉ nổi bật về học thuật, UEH còn được biết đến với môi trường sinh viên năng động, sáng tạo với nhiều hoạt động ngoại khóa, câu lạc bộ học thuật, kỹ năng và các cuộc thi khởi nghiệp. Nhà trường thường xuyên hợp tác với doanh nghiệp lớn, tạo điều kiện cho sinh viên thực tập, trải nghiệm thực tế và có cơ hội việc làm ngay sau khi tốt nghiệp.

Với uy tín và chất lượng đào tạo đã được khẳng định, Đại học Kinh tế TP.HCM không chỉ là lựa chọn hàng đầu của sinh viên yêu thích lĩnh vực kinh tế – kinh doanh mà còn là nơi đào tạo ra nhiều nhà lãnh đạo, chuyên gia kinh tế và doanh nhân thành đạt, đóng góp tích cực vào sự phát triển bền vững của nền kinh tế Việt Nam.', N'Hơn 50.000 sinh viên', 1, N'kinh-te-tphcm', 1, CAST(N'2026-03-29T22:50:23.600' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (10, N'Đại học Y Dược TP.HCM', N'217 Hồng Bàng, Quận 5, TP.HCM', N'TP. Hồ Chí Minh', 3, 1, N'028 3855 4269', N'https://ump.edu.vn', N'/Resources/Images/truong/y-duoc-tphcm_logo_3bd58830.png', N'/Resources/Images/truong/y-duoc-tphcm_cover_95dbdb0f.jpg', N'Đại học Y Dược TP.HCM là một trong những trường đại học hàng đầu Việt Nam trong lĩnh vực đào tạo y khoa và khoa học sức khỏe, trực thuộc Đại học Quốc gia TP.HCM. Trường có lịch sử hình thành từ năm 1947 và đã trải qua nhiều giai đoạn phát triển, trở thành trung tâm đào tạo, nghiên cứu và chăm sóc sức khỏe uy tín hàng đầu khu vực phía Nam.

Đại học Y Dược TP.HCM đào tạo đa dạng các chuyên ngành thuộc khối khoa học sức khỏe như Y đa khoa, Răng – Hàm – Mặt, Dược học, Điều dưỡng, Y học dự phòng, Xét nghiệm y học, Y học cổ truyền… với chương trình học được xây dựng bài bản, kết hợp chặt chẽ giữa lý thuyết và thực hành lâm sàng. Sinh viên được tiếp cận trực tiếp với môi trường bệnh viện, tham gia thực tập tại các cơ sở y tế lớn, từ đó nâng cao kỹ năng chuyên môn và khả năng xử lý tình huống thực tế.

Nhà trường sở hữu đội ngũ giảng viên là các giáo sư, bác sĩ, chuyên gia đầu ngành giàu kinh nghiệm, đồng thời có hệ thống bệnh viện, phòng thí nghiệm và trung tâm nghiên cứu hiện đại phục vụ hiệu quả cho công tác đào tạo và nghiên cứu khoa học. Bên cạnh đó, trường cũng активно mở rộng hợp tác quốc tế với nhiều tổ chức, trường đại học y khoa danh tiếng trên thế giới, tạo điều kiện cho sinh viên và giảng viên giao lưu, học tập và nghiên cứu trong môi trường quốc tế.

Không chỉ chú trọng đào tạo chuyên môn, Đại học Y Dược TP.HCM còn đề cao y đức và trách nhiệm xã hội, hướng tới việc đào tạo đội ngũ cán bộ y tế vừa giỏi chuyên môn, vừa giàu lòng nhân ái. Với uy tín lâu năm và chất lượng đào tạo vượt trội, trường luôn là lựa chọn hàng đầu của những thí sinh có nguyện vọng theo đuổi ngành y dược, đồng thời đóng góp quan trọng vào sự phát triển của hệ thống y tế Việt Nam.', N'Hơn 13.000 sinh viên', 1, N'y-duoc-tphcm', 1, CAST(N'2026-03-29T22:56:21.420' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (11, N'Đại học FPT', N'Khu Công nghệ cao Hòa Lạc, Thạch Thất, Hà Nội', N'Hà Nội', 1, 2, N'1900 6600', N'https://fpt.edu.vn', N'/Resources/Images/truong/dai-hoc-fpt_logo_390e8e31.png', N'/Resources/Images/truong/dai-hoc-fpt_cover_103e9b69.jpg', N'Đại học FPT là một trong những trường đại học tư thục hàng đầu tại Việt Nam, trực thuộc Tập đoàn FPT – tập đoàn công nghệ lớn và uy tín trong lĩnh vực công nghệ thông tin và viễn thông. Được thành lập vào năm 2006, trường định hướng đào tạo theo mô hình gắn liền với doanh nghiệp, chú trọng thực tiễn và khả năng làm việc ngay sau khi tốt nghiệp.

Đại học FPT nổi bật với các ngành đào tạo mang tính xu hướng và ứng dụng cao như Công nghệ thông tin, Kỹ thuật phần mềm, Trí tuệ nhân tạo (AI), An toàn thông tin, Thiết kế đồ họa, Truyền thông đa phương tiện, Quản trị kinh doanh và Ngôn ngữ (Anh, Nhật, Hàn…). Chương trình học được thiết kế theo chuẩn quốc tế, giảng dạy bằng tiếng Anh ở nhiều chuyên ngành, giúp sinh viên có lợi thế cạnh tranh trong môi trường toàn cầu.

Một điểm khác biệt lớn của Đại học FPT là mô hình đào tạo “học đi đôi với hành”. Sinh viên sẽ được tham gia các kỳ thực tập thực tế tại doanh nghiệp ngay từ năm 3, đặc biệt có cơ hội làm việc tại các công ty thuộc hệ sinh thái của FPT. Điều này giúp sinh viên tích lũy kinh nghiệm thực tế, nâng cao kỹ năng chuyên môn và dễ dàng tìm được việc làm sau khi ra trường.

Bên cạnh đó, trường còn chú trọng phát triển kỹ năng mềm, ngoại ngữ và tư duy sáng tạo cho sinh viên thông qua các hoạt động ngoại khóa, câu lạc bộ và chương trình trao đổi quốc tế. Môi trường học tập tại Đại học FPT được đánh giá là hiện đại, năng động với cơ sở vật chất khang trang, khuôn viên xanh và thiết kế theo phong cách quốc tế.

Với triết lý đào tạo gắn liền thực tiễn và doanh nghiệp, cùng mạng lưới hợp tác rộng lớn trong và ngoài nước, Đại học FPT đang ngày càng khẳng định vị thế là một trong những trường đại học tiên phong trong đào tạo nguồn nhân lực chất lượng cao, đặc biệt trong lĩnh vực công nghệ và kinh tế số tại Việt Nam.', N'Hơn 20.000 sinh viên', 1, N'dai-hoc-fpt', 1, CAST(N'2026-03-29T22:43:28.357' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (12, N'Đại học RMIT Việt Nam', N'Cổng chính, 702 Đường Nguyễn Văn Linh, Tân Hưng, Quận 7, Hồ Chí Minh 700000, Thành phố Hồ Chí Minh', N'TP. Hồ Chí Minh', 3, 3, N'028 3776 1300', N'https://rmit.edu.vn', N'/Resources/Images/truong/rmit-viet-nam_logo_c672cc2f.png', N'/Resources/Images/truong/rmit-viet-nam_cover_ccba53c8.jpg', N'Đại học RMIT Việt Nam là cơ sở đào tạo quốc tế tại Việt Nam, trực thuộc RMIT University – một trong những trường đại học danh tiếng của Úc. Chính thức hoạt động tại Việt Nam từ năm 2000, RMIT là trường đại học 100% vốn nước ngoài đầu tiên tại Việt Nam, mang đến môi trường học tập chuẩn quốc tế và bằng cấp được công nhận toàn cầu.

Trường cung cấp các chương trình đào tạo đa dạng, tập trung vào các lĩnh vực như Kinh doanh, Công nghệ thông tin, Truyền thông, Thiết kế, Marketing, Tài chính và Quản trị. Toàn bộ chương trình học được giảng dạy bằng tiếng Anh, áp dụng phương pháp giáo dục hiện đại, chú trọng tư duy phản biện, kỹ năng thực hành và khả năng làm việc trong môi trường quốc tế. Sinh viên tại RMIT không chỉ học kiến thức chuyên môn mà còn được rèn luyện kỹ năng mềm, kỹ năng lãnh đạo và tư duy sáng tạo – những yếu tố quan trọng trong thời đại toàn cầu hóa.

Đại học RMIT Việt Nam sở hữu hệ thống cơ sở vật chất hiện đại bậc nhất, với các khu học xá lớn tại TP.HCM và Hà Nội. Các phòng học, thư viện, khu tự học, phòng mô phỏng doanh nghiệp, studio thiết kế và khu thể thao đều được đầu tư theo tiêu chuẩn quốc tế, tạo điều kiện tối ưu cho việc học tập và phát triển toàn diện của sinh viên.

Ngoài ra, RMIT còn có mạng lưới kết nối doanh nghiệp rộng lớn, giúp sinh viên có nhiều cơ hội thực tập, tham gia dự án thực tế và tiếp cận với nhà tuyển dụng ngay từ khi còn trên ghế nhà trường. Trường cũng thường xuyên tổ chức các hoạt động ngoại khóa, sự kiện quốc tế và chương trình trao đổi sinh viên, mang lại trải nghiệm học tập đa văn hóa và năng động.

Với môi trường học tập hiện đại, chương trình đào tạo chuẩn quốc tế và bằng cấp có giá trị toàn cầu, Đại học RMIT Việt Nam là lựa chọn hàng đầu cho những sinh viên mong muốn theo đuổi con đường học tập quốc tế ngay tại Việt Nam và phát triển sự nghiệp trong môi trường toàn cầu.', N'Hơn 7.000 sinh viên', 1, N'rmit-viet-nam', 1, CAST(N'2026-03-29T22:55:13.310' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (13, N'Đại học Mở Hà Nội', N'B101, phố Nguyễn Hiền, phường Bạch Mai, Hà Nội, Việt Nam', N'Hà Nội', 1, 1, N'024 3868 2321', N'http://www.hou.edu.vn/', N'/Resources/Images/truong/dai-hoc-mo-ha-noi_logo_b6c3c742.jpg', N'/Resources/Images/truong/dai-hoc-mo-ha-noi_cover_4b7c0e22.jpg', N'<p>Trường Đại học Mở H&agrave; Nội l&agrave; một trường đại học c&ocirc;ng lập trực thuộc Bộ Gi&aacute;o dục v&agrave; Đ&agrave;o tạo, được th&agrave;nh lập v&agrave;o năm 1993, với định hướng ph&aacute;t triển theo m&ocirc; h&igrave;nh gi&aacute;o dục mở v&agrave; linh hoạt. Trường ra đời nhằm đ&aacute;p ứng nhu cầu học tập đa dạng của x&atilde; hội, đặc biệt l&agrave; tạo cơ hội tiếp cận gi&aacute;o dục đại học cho nhiều đối tượng kh&aacute;c nhau, kh&ocirc;ng bị giới hạn bởi thời gian, độ tuổi hay điều kiện c&aacute; nh&acirc;n.</p>
<p>Một trong những điểm nổi bật của trường l&agrave; triển khai nhiều h&igrave;nh thức đ&agrave;o tạo như ch&iacute;nh quy, đ&agrave;o tạo từ xa (E-learning) v&agrave; vừa học vừa l&agrave;m. Nhờ đ&oacute;, sinh vi&ecirc;n c&oacute; thể chủ động lựa chọn phương thức học tập ph&ugrave; hợp với ho&agrave;n cảnh của m&igrave;nh. Trường hiện đ&agrave;o tạo nhiều ng&agrave;nh nghề thuộc c&aacute;c lĩnh vực như C&ocirc;ng nghệ th&ocirc;ng tin, Kinh tế, Luật, Ngoại ngữ, Du lịch v&agrave; Thiết kế, g&oacute;p phần cung cấp nguồn nh&acirc;n lực chất lượng cho x&atilde; hội.</p>
<p>B&ecirc;n cạnh đ&oacute;, Trường Đại học Mở H&agrave; Nội c&ograve;n ch&uacute; trọng ứng dụng c&ocirc;ng nghệ trong giảng dạy, x&acirc;y dựng hệ thống học tập trực tuyến hiện đại v&agrave; khuyến kh&iacute;ch tinh thần tự học, học tập suốt đời cho sinh vi&ecirc;n. Trải qua nhiều năm ph&aacute;t triển, trường đ&atilde; đ&agrave;o tạo h&agrave;ng trăm ngh&igrave;n cử nh&acirc;n, kỹ sư v&agrave; thạc sĩ, từng bước khẳng định vị thế l&agrave; một trong những cơ sở gi&aacute;o dục đại học uy t&iacute;n tại Việt Nam, ph&ugrave; hợp với xu hướng học tập linh hoạt trong thời đại số.</p>', N'Hơn 35.000 sinh viên', 1, N'dai-hoc-mo-ha-noi', 1, CAST(N'2026-04-22T20:58:09.023' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (14, N'Đại học Quốc gia Thành phố Hồ Chí Minh', N'Phường Linh Xuân và phường Đông Hòa, Thành phố Hồ Chí Minh,  Việt Nam', N'Thành phố Hồ Chí Minh', 3, 1, N'028 3724 2160', N'http://vnuhcm.edu.vn/', N'/Resources/Images/truong/dai-hoc-quoc-gia-thanh-pho-ho-chi-minh_logo_cccceeb5.png', N'/Resources/Images/truong/dai-hoc-quoc-gia-thanh-pho-ho-chi-minh_cover_0789b193.webp', N'<p>Đại học Quốc gia Th&agrave;nh phố Hồ Ch&iacute; Minh l&agrave; một trong những hệ thống đại học lớn v&agrave; uy t&iacute;n h&agrave;ng đầu tại Việt Nam, được th&agrave;nh lập năm 1995 theo m&ocirc; h&igrave;nh đại học đa ng&agrave;nh, đa lĩnh vực. Trường c&oacute; vai tr&ograve; quan trọng trong đ&agrave;o tạo nguồn nh&acirc;n lực chất lượng cao, nghi&ecirc;n cứu khoa học v&agrave; chuyển giao c&ocirc;ng nghệ phục vụ ph&aacute;t triển kinh tế &ndash; x&atilde; hội của đất nước.</p>
<p>Đại học Quốc gia TP.HCM bao gồm nhiều trường đại học th&agrave;nh vi&ecirc;n như Đại học B&aacute;ch Khoa, Đại học Khoa học Tự nhi&ecirc;n, Đại học Khoa học X&atilde; hội v&agrave; Nh&acirc;n văn, Đại học Quốc tế, Đại học C&ocirc;ng nghệ Th&ocirc;ng tin&hellip; với hệ thống ng&agrave;nh học phong ph&uacute; trải rộng từ kỹ thuật, c&ocirc;ng nghệ, kinh tế đến khoa học x&atilde; hội v&agrave; ngoại ngữ. Nhờ quy m&ocirc; lớn v&agrave; chương tr&igrave;nh đ&agrave;o tạo b&agrave;i bản, nơi đ&acirc;y thu h&uacute;t đ&ocirc;ng đảo sinh vi&ecirc;n giỏi tr&ecirc;n cả nước.</p>
<p>B&ecirc;n cạnh đ&oacute;, trường c&ograve;n nổi bật với m&ocirc;i trường học tập hiện đại, cơ sở vật chất đồng bộ tại khu đ&ocirc; thị đại học ở Thủ Đức, c&ugrave;ng với nhiều hoạt động nghi&ecirc;n cứu khoa học, hợp t&aacute;c quốc tế v&agrave; đổi mới s&aacute;ng tạo. Với định hướng trở th&agrave;nh trung t&acirc;m đ&agrave;o tạo v&agrave; nghi&ecirc;n cứu h&agrave;ng đầu khu vực, Đại học Quốc gia TP.HCM ng&agrave;y c&agrave;ng khẳng định vị thế quan trọng trong hệ thống gi&aacute;o dục đại học Việt Nam.</p>', N'Hơn 100.450 sinh viên', 1, N'dai-hoc-quoc-gia-thanh-pho-ho-chi-minh', 1, CAST(N'2026-04-22T21:00:22.330' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (15, N'Đại học Ngoại thương', N'91 Chùa Láng, Láng, Hà Nội, Việt Nam', N'Hà Nội', 1, 1, N'035 253 0798', N'http://www.ftu.edu.vn/', N'/Resources/Images/truong/dai-hoc-ngoai-thuong_logo_0bc8741b.png', N'/Resources/Images/truong/dai-hoc-ngoai-thuong_cover_4ddde878.jpg', N'<p>Đại học Ngoại thương l&agrave; một trong những trường đại học h&agrave;ng đầu tại Việt Nam trong lĩnh vực kinh tế, thương mại v&agrave; kinh doanh quốc tế. Trường được th&agrave;nh lập năm 1960, trực thuộc Bộ Gi&aacute;o dục v&agrave; Đ&agrave;o tạo, nổi tiếng với chất lượng đ&agrave;o tạo cao v&agrave; m&ocirc;i trường học tập năng động, cạnh tranh.</p>
<p>Đại học Ngoại thương đ&agrave;o tạo nhiều ng&agrave;nh như Kinh tế quốc tế, Quản trị kinh doanh, T&agrave;i ch&iacute;nh &ndash; Ng&acirc;n h&agrave;ng, Marketing v&agrave; Thương mại điện tử. Chương tr&igrave;nh học của trường c&oacute; t&iacute;nh thực tiễn cao, thường xuy&ecirc;n cập nhật theo xu hướng hội nhập to&agrave;n cầu, gi&uacute;p sinh vi&ecirc;n c&oacute; nền tảng kiến thức vững chắc v&agrave; khả năng th&iacute;ch nghi tốt với thị trường lao động.</p>
<p>B&ecirc;n cạnh đ&oacute;, trường c&ograve;n được biết đến với hoạt động ngoại kh&oacute;a s&ocirc;i nổi, nhiều c&acirc;u lạc bộ học thuật v&agrave; kỹ năng, gi&uacute;p sinh vi&ecirc;n ph&aacute;t triển to&agrave;n diện cả về chuy&ecirc;n m&ocirc;n lẫn kỹ năng mềm. Sinh vi&ecirc;n tốt nghiệp từ Đại học Ngoại thương thường c&oacute; cơ hội việc l&agrave;m cao, đặc biệt trong c&aacute;c doanh nghiệp lớn, c&ocirc;ng ty đa quốc gia v&agrave; tổ chức quốc tế. Với uy t&iacute;n l&acirc;u năm, trường lu&ocirc;n nằm trong top những lựa chọn h&agrave;ng đầu của th&iacute; sinh tr&ecirc;n cả nước.</p>', N'Hơn 20.000 sinh viên', 1, N'dai-hoc-ngoai-thuong', 1, CAST(N'2026-04-22T20:59:56.957' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (16, N'Đại học Tôn Đức Thắng (TDTU)', N'19 Nguyễn Hữu Thọ, phường Tân Hưng, TP. Hồ Chí Minh.', N'TP. Hồ Chí Minh', 3, 1, N'1900 2024', N'https://www.tdtu.edu.vn/', N'/Resources/Images/truong/dai-hoc-ton-duc-thang-tdtu_logo_e48e4330.png', N'/Resources/Images/truong/dai-hoc-ton-duc-thang-tdtu_cover_0ce2c277.jpg', N'<p>Trường Đại học T&ocirc;n Đức Thắng l&agrave; một trường đại học c&ocirc;ng lập c&oacute; trụ sở tại TP. Hồ Ch&iacute; Minh, trực thuộc Tổng Li&ecirc;n đo&agrave;n Lao động Việt Nam, được biết đến với định hướng ph&aacute;t triển theo m&ocirc; h&igrave;nh đại học ứng dụng hiện đại. Trường đ&agrave;o tạo đa ng&agrave;nh, bao gồm c&aacute;c lĩnh vực như kinh tế, kỹ thuật, c&ocirc;ng nghệ th&ocirc;ng tin, khoa học x&atilde; hội v&agrave; nghệ thuật, trong đ&oacute; ch&uacute; trọng gắn kết giữa l&yacute; thuyết v&agrave; thực h&agrave;nh nhằm đ&aacute;p ứng nhu cầu thực tế của thị trường lao động. B&ecirc;n cạnh đ&oacute;, trường c&ograve;n đẩy mạnh nghi&ecirc;n cứu khoa học, hợp t&aacute;c quốc tế với nhiều đối t&aacute;c tr&ecirc;n thế giới, g&oacute;p phần n&acirc;ng cao chất lượng đ&agrave;o tạo. Cơ sở vật chất của trường được đầu tư đồng bộ, hiện đại với m&ocirc;i trường học tập kỷ luật, chuy&ecirc;n nghiệp v&agrave; năng động. Hiện nay, quy m&ocirc; của trường đạt khoảng hơn 23.000 sinh vi&ecirc;n, được xem l&agrave; một trong những trường đại học c&oacute; quy m&ocirc; lớn v&agrave; chất lượng đ&agrave;o tạo tốt tại Việt Nam.</p>', N'Hơn 23.000 sinh viên', 1, N'dai-hoc-ton-duc-thang-tdtu', 1, CAST(N'2026-04-22T21:00:43.087' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (17, N'Đại học Duy Tân', N'254 Nguyễn Văn Linh, phường Thanh Khê, Đà Nẵng, Việt Nam', N'Đà Nẵng', 2, 2, N'0236 3650 403', N'http://www.duytan.edu.vn/', N'/Resources/Images/truong/dai-hoc-duy-tan_logo_5a26d10c.png', N'/Resources/Images/truong/dai-hoc-duy-tan_cover_c3c767a5.jpg', N'<p>Trường Đại học Duy T&acirc;n l&agrave; một trong những trường đại học tư thục đầu ti&ecirc;n tại Việt Nam, được th&agrave;nh lập năm 1994 tại th&agrave;nh phố Đ&agrave; Nẵng. Trường đ&agrave;o tạo đa ng&agrave;nh, bao gồm c&ocirc;ng nghệ th&ocirc;ng tin, kỹ thuật, kinh tế, du lịch, y dược v&agrave; khoa học x&atilde; hội, với định hướng gắn liền giữa đ&agrave;o tạo v&agrave; nhu cầu thực tiễn của x&atilde; hội. Đại học Duy T&acirc;n đặc biệt ch&uacute; trọng hợp t&aacute;c quốc tế, triển khai nhiều chương tr&igrave;nh li&ecirc;n kết với c&aacute;c trường đại học uy t&iacute;n tr&ecirc;n thế giới, gi&uacute;p sinh vi&ecirc;n tiếp cận chương tr&igrave;nh đ&agrave;o tạo ti&ecirc;n tiến. (<a title="KHOA Đ&Agrave;O TẠO QUỐC TẾ - ĐẠI HỌC DUY T&Acirc;N" href="https://is.duytan.edu.vn/?utm_source=chatgpt.com">KHOA Đ&Agrave;O TẠO QUỐC TẾ</a>)</p>
<p>B&ecirc;n cạnh đ&oacute;, trường đầu tư mạnh v&agrave;o cơ sở vật chất như hệ thống thư viện, ph&ograve;ng th&iacute; nghiệm, ph&ograve;ng thực h&agrave;nh hiện đại v&agrave; khu học tập tiện nghi nhằm phục vụ tốt cho việc học tập v&agrave; nghi&ecirc;n cứu của sinh vi&ecirc;n. (<a title="Khoa Y - Đại học Duy T&acirc;n" href="https://med.duytan.edu.vn/?utm_source=chatgpt.com">Khoa Y</a>) M&ocirc;i trường học tập tại đ&acirc;y hướng đến sự năng động, s&aacute;ng tạo, đồng thời ch&uacute; trọng ph&aacute;t triển kỹ năng thực h&agrave;nh v&agrave; khả năng l&agrave;m việc trong m&ocirc;i trường quốc tế.</p>
<p>Hiện nay, Đại học Duy T&acirc;n c&oacute; quy m&ocirc; đ&agrave;o tạo lớn với h&agrave;ng chục ngh&igrave;n sinh vi&ecirc;n theo học mỗi năm (ước t&iacute;nh tr&ecirc;n 20.000 sinh vi&ecirc;n), được xem l&agrave; một trong những trường đại học tư thục c&oacute; quy m&ocirc; v&agrave; chất lượng đ&agrave;o tạo kh&aacute; nổi bật tại khu vực miền Trung Việt Nam.</p>', N'Hơn 36.991 sinh viên', 1, N'dai-hoc-duy-tan', 1, CAST(N'2026-04-22T20:57:57.460' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (18, N'Đại học Sư phạm Hà Nội', N'136 đường Xuân Thủy, phường Cầu Giấy, Hà Nội,  Việt Nam', N'Hà Nội', 1, 1, N'', N'https://hnue.edu.vn/', N'/Resources/Images/truong/dai-hoc-su-pham-ha-noi_logo_7bc5b85e.png', N'/Resources/Images/truong/dai-hoc-su-pham-ha-noi_cover_37397c11.jpg', N'<p>Trường Đại học Sư phạm H&agrave; Nội l&agrave; một trong những cơ sở đ&agrave;o tạo gi&aacute;o vi&ecirc;n h&agrave;ng đầu Việt Nam, giữ vai tr&ograve; n&ograve;ng cốt trong việc ph&aacute;t triển nguồn nh&acirc;n lực chất lượng cao cho ng&agrave;nh gi&aacute;o dục. Với bề d&agrave;y lịch sử l&acirc;u đời, trường kh&ocirc;ng chỉ nổi bật trong đ&agrave;o tạo c&aacute;c ng&agrave;nh sư phạm như To&aacute;n, Văn, Anh, L&yacute;, H&oacute;a&hellip; m&agrave; c&ograve;n mở rộng sang nhiều ng&agrave;nh ngo&agrave;i sư phạm nhằm đ&aacute;p ứng nhu cầu đa dạng của x&atilde; hội.</p>
<p>B&ecirc;n cạnh hoạt động giảng dạy, trường c&ograve;n l&agrave; trung t&acirc;m nghi&ecirc;n cứu khoa học uy t&iacute;n, đặc biệt trong lĩnh vực khoa học gi&aacute;o dục v&agrave; khoa học cơ bản, đ&oacute;ng g&oacute;p nhiều c&ocirc;ng tr&igrave;nh c&oacute; gi&aacute; trị cho nền gi&aacute;o dục quốc gia. Đội ngũ giảng vi&ecirc;n c&oacute; tr&igrave;nh độ cao, gi&agrave;u kinh nghiệm c&ugrave;ng m&ocirc;i trường học tập nghi&ecirc;m t&uacute;c, học thuật đ&atilde; tạo n&ecirc;n uy t&iacute;n vững chắc cho nh&agrave; trường.</p>
<p>H&agrave;ng năm, trường tuyển sinh với quy m&ocirc; lớn, đ&agrave;o tạo h&agrave;ng ngh&igrave;n sinh vi&ecirc;n, cung cấp đội ngũ gi&aacute;o vi&ecirc;n v&agrave; chuy&ecirc;n gia gi&aacute;o dục cho cả nước. C&oacute; thể n&oacute;i, Đại học Sư phạm H&agrave; Nội kh&ocirc;ng chỉ l&agrave; nơi đ&agrave;o tạo nghề gi&aacute;o m&agrave; c&ograve;n l&agrave; c&aacute;i n&ocirc;i bồi dưỡng tri thức, g&oacute;p phần quan trọng v&agrave;o sự ph&aacute;t triển bền vững của nền gi&aacute;o dục Việt Nam.</p>', N'Hơn 4.995 sinh viên', 1, N'dai-hoc-su-pham-ha-noi', 1, CAST(N'2026-04-22T21:00:33.067' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (19, N'Học viện Tài chính', N'58 phố Lê Văn Hiến, phường Đông Ngạc, Hà Nội, Việt Nam', N'TP Hà Nội', 1, 1, N'0967684086', N'http://www.hvtc.edu.vn/', N'/Resources/Images/truong/hoc-vien-tai-chinh_logo_29584b8f.png', N'/Resources/Images/truong/hoc-vien-tai-chinh_cover_bb28abb6.jpg', N'<p>Học viện Tài chính là một trong những cơ sở đào tạo hàng đầu tại Việt Nam trong lĩnh vực tài chính, kế toán, kiểm toán và quản trị kinh doanh, trực thuộc Bộ Tài chính. Trường có trụ sở tại Hà Nội và được đánh giá cao về chất lượng đào tạo chuyên sâu, đặc biệt trong các ngành liên quan đến kinh tế – tài chính.</p>
<p>Học viện đào tạo đa dạng các chuyên ngành như tài chính doanh nghiệp, ngân hàng, kế toán, kiểm toán, hải quan và bảo hiểm, với chương trình học gắn liền thực tiễn, giúp sinh viên có nền tảng kiến thức vững chắc và kỹ năng nghề nghiệp tốt. Bên cạnh đó, trường còn chú trọng hợp tác quốc tế, triển khai nhiều chương trình liên kết đào tạo với các trường đại học nước ngoài, tạo cơ hội cho sinh viên tiếp cận môi trường học tập hiện đại.</p>
<p>Môi trường học tập tại Học viện Tài chính được đánh giá là năng động nhưng cũng khá cạnh tranh, đòi hỏi sinh viên có ý thức tự học cao. Đội ngũ giảng viên giàu kinh nghiệm cùng cơ sở vật chất ngày càng được cải thiện đã góp phần nâng cao chất lượng đào tạo. Hàng năm, trường tuyển sinh hàng nghìn sinh viên, với tổng quy mô đào tạo lớn, là nguồn cung nhân lực chất lượng cho ngành tài chính – kế toán của cả nước.</p>', N'Hơn 20.000 sinh viên', 1, N'hoc-vien-tai-chinh', 1, CAST(N'2026-04-28T21:36:06.303' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (20, N'Học viện Ngân hàng', N'12 Chùa Bộc, phường Quang Trung, Đống Đa, Hà Nội, Việt Nam', N'TP Hà Nội', 1, 1, N'0818956595', N'http://www.hvnh.edu.vn/', N'/Resources/Images/truong/hoc-vien-ngan-hang_logo_d21d3366.jpg', N'/Resources/Images/truong/hoc-vien-ngan-hang_cover_caae63a3.jpg', N'<p>Học viện Ng&amp;acirc;n h&amp;agrave;ng l&amp;agrave; một cơ sở đ&amp;agrave;o tạo uy t&amp;iacute;n trực thuộc Ng&amp;acirc;n h&amp;agrave;ng Nh&amp;agrave; nước Việt Nam, chuy&amp;ecirc;n s&amp;acirc;u trong c&amp;aacute;c lĩnh vực t&amp;agrave;i ch&amp;iacute;nh, ng&amp;acirc;n h&amp;agrave;ng, kế to&amp;aacute;n, kiểm to&amp;aacute;n v&amp;agrave; quản trị kinh doanh. Trường c&amp;oacute; trụ sở ch&amp;iacute;nh tại H&amp;agrave; Nội v&amp;agrave; được đ&amp;aacute;nh gi&amp;aacute; l&amp;agrave; một trong những nơi đ&amp;agrave;o tạo nguồn nh&amp;acirc;n lực chất lượng cao cho ng&amp;agrave;nh t&amp;agrave;i ch&amp;iacute;nh &amp;ndash; ng&amp;acirc;n h&amp;agrave;ng của cả nước.</p>
<p>Học viện cung cấp nhiều chương tr&amp;igrave;nh đ&amp;agrave;o tạo từ đại học đến sau đại học, trong đ&amp;oacute; nổi bật l&amp;agrave; c&amp;aacute;c ng&amp;agrave;nh như T&amp;agrave;i ch&amp;iacute;nh &amp;ndash; Ng&amp;acirc;n h&amp;agrave;ng, Kế to&amp;aacute;n, Kiểm to&amp;aacute;n, Quản trị kinh doanh v&amp;agrave; C&amp;ocirc;ng nghệ th&amp;ocirc;ng tin. Chương tr&amp;igrave;nh học được x&amp;acirc;y dựng theo hướng gắn liền với thực tiễn, kết hợp l&amp;yacute; thuyết v&amp;agrave; kỹ năng nghề nghiệp, gi&amp;uacute;p sinh vi&amp;ecirc;n c&amp;oacute; khả năng th&amp;iacute;ch nghi tốt với m&amp;ocirc;i trường l&amp;agrave;m việc sau khi tốt nghiệp.</p>
<p>Ngo&amp;agrave;i ra, trường c&amp;ograve;n ch&amp;uacute; trọng hợp t&amp;aacute;c quốc tế với nhiều đối t&amp;aacute;c nước ngo&amp;agrave;i, triển khai c&amp;aacute;c chương tr&amp;igrave;nh li&amp;ecirc;n kết đ&amp;agrave;o tạo v&amp;agrave; trao đổi sinh vi&amp;ecirc;n. M&amp;ocirc;i trường học tập tại đ&amp;acirc;y năng động, c&amp;oacute; t&amp;iacute;nh cạnh tranh v&amp;agrave; y&amp;ecirc;u cầu cao về t&amp;iacute;nh tự học. Với quy m&amp;ocirc; đ&amp;agrave;o tạo h&amp;agrave;ng chục ngh&amp;igrave;n sinh vi&amp;ecirc;n, Học viện Ng&amp;acirc;n h&amp;agrave;ng l&amp;agrave; một trong những lựa chọn h&amp;agrave;ng đầu cho những ai định hướng theo lĩnh vực t&amp;agrave;i ch&amp;iacute;nh &amp;ndash; ng&amp;acirc;n h&amp;agrave;ng tại Việt Nam.</p>', N'Hơn 4690 sinh viên', 1, N'hoc-vien-ngan-hang', 1, CAST(N'2026-04-27T21:45:48.270' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (22, N'Đại học Thương mại', N'79 đường Hồ Tùng Mậu, phường Từ Liêm, Hà Nội,  Việt Nam', N'TP Hà Nội', 1, 1, N'0364005207', N'http://tmu.edu.vn/', N'/Resources/Images/truong/dai-hoc-thuong-mai_logo_3e19f995.jpg', N'/Resources/Images/truong/dai-hoc-thuong-mai_cover_a2765249.jpg', N'<p>Trường Đại học Thương mại l&amp;agrave; một trường đại học c&amp;ocirc;ng lập uy t&amp;iacute;n tại H&amp;agrave; Nội, trực thuộc Bộ Gi&amp;aacute;o dục v&amp;agrave; Đ&amp;agrave;o tạo, chuy&amp;ecirc;n đ&amp;agrave;o tạo c&amp;aacute;c lĩnh vực kinh tế, thương mại v&amp;agrave; quản trị kinh doanh. Trường c&amp;oacute; thế mạnh nổi bật trong c&amp;aacute;c ng&amp;agrave;nh như Kinh doanh thương mại, Marketing, Quản trị kinh doanh, T&amp;agrave;i ch&amp;iacute;nh &amp;ndash; Ng&amp;acirc;n h&amp;agrave;ng, Kế to&amp;aacute;n v&amp;agrave; Thương mại điện tử, đ&amp;aacute;p ứng tốt nhu cầu nh&amp;acirc;n lực trong nền kinh tế hiện đại.</p>
<p>Chương tr&amp;igrave;nh đ&amp;agrave;o tạo của trường được x&amp;acirc;y dựng theo hướng ứng dụng, gắn liền với thực tiễn doanh nghiệp, gi&amp;uacute;p sinh vi&amp;ecirc;n kh&amp;ocirc;ng chỉ nắm vững kiến thức chuy&amp;ecirc;n m&amp;ocirc;n m&amp;agrave; c&amp;ograve;n ph&amp;aacute;t triển kỹ năng nghề nghiệp như giao tiếp, l&amp;agrave;m việc nh&amp;oacute;m v&amp;agrave; tư duy kinh doanh. B&amp;ecirc;n cạnh đ&amp;oacute;, trường активно mở rộng hợp t&amp;aacute;c quốc tế, tạo điều kiện cho sinh vi&amp;ecirc;n tham gia c&amp;aacute;c chương tr&amp;igrave;nh trao đổi v&amp;agrave; tiếp cận m&amp;ocirc;i trường học tập ti&amp;ecirc;n tiến.</p>
<p>M&amp;ocirc;i trường học tập tại Đại học Thương mại năng động, hiện đại với nhiều hoạt động ngoại kh&amp;oacute;a, c&amp;acirc;u lạc bộ v&amp;agrave; cơ hội thực tập tại doanh nghiệp. Với quy m&amp;ocirc; đ&amp;agrave;o tạo lớn, mỗi năm tuyển sinh h&amp;agrave;ng ngh&amp;igrave;n sinh vi&amp;ecirc;n, trường được đ&amp;aacute;nh gi&amp;aacute; l&amp;agrave; một trong những cơ sở đ&amp;agrave;o tạo kinh tế h&amp;agrave;ng đầu khu vực ph&amp;iacute;a Bắc, cung cấp nguồn nh&amp;acirc;n lực chất lượng cao cho lĩnh vực thương mại v&amp;agrave; dịch vụ.</p>', N'Hơn 5020 sinh viên', 1, N'dai-hoc-thuong-mai', 1, CAST(N'2026-04-27T21:58:54.700' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (23, N'Đại học Thủ đô Hà Nội', N'Số 98 phố Dương Quảng Hàm, phường Nghĩa Đô.', N'TP Hà Nội', 1, 1, N'0968270089', N'https://hnmu.edu.vn/', N'/Resources/Images/truong/dai-hoc-thu-do-ha-noi_logo_a1b41d23.jpg', N'/Resources/Images/truong/dai-hoc-thu-do-ha-noi_cover_6628de4a.jpg', N'<p>Trường Đại học Thủ đ&amp;ocirc; H&amp;agrave; Nội l&amp;agrave; một trường đại học c&amp;ocirc;ng lập trực thuộc Ủy ban Nh&amp;acirc;n d&amp;acirc;n th&amp;agrave;nh phố H&amp;agrave; Nội, c&amp;oacute; nhiệm vụ đ&amp;agrave;o tạo nguồn nh&amp;acirc;n lực chất lượng cao phục vụ cho Thủ đ&amp;ocirc; v&amp;agrave; cả nước. Trường ph&amp;aacute;t triển theo định hướng đa ng&amp;agrave;nh, trong đ&amp;oacute; nổi bật với c&amp;aacute;c lĩnh vực sư phạm, kinh tế, c&amp;ocirc;ng nghệ th&amp;ocirc;ng tin, du lịch v&amp;agrave; ngoại ngữ.</p>
<p>Chương tr&amp;igrave;nh đ&amp;agrave;o tạo của trường được x&amp;acirc;y dựng theo hướng ứng dụng, ch&amp;uacute; trọng kết hợp giữa l&amp;yacute; thuyết v&amp;agrave; thực h&amp;agrave;nh nhằm gi&amp;uacute;p sinh vi&amp;ecirc;n c&amp;oacute; kỹ năng nghề nghiệp vững v&amp;agrave;ng sau khi tốt nghiệp. B&amp;ecirc;n cạnh đ&amp;oacute;, nh&amp;agrave; trường cũng quan t&amp;acirc;m đến việc ph&amp;aacute;t triển kỹ năng mềm, tư duy s&amp;aacute;ng tạo v&amp;agrave; khả năng th&amp;iacute;ch ứng với m&amp;ocirc;i trường l&amp;agrave;m việc hiện đại.</p>
<p>M&amp;ocirc;i trường học tập tại Đại học Thủ đ&amp;ocirc; H&amp;agrave; Nội được đ&amp;aacute;nh gi&amp;aacute; l&amp;agrave; năng động, th&amp;acirc;n thiện, với nhiều hoạt động ngoại kh&amp;oacute;a v&amp;agrave; cơ hội trải nghiệm thực tế. Với quy m&amp;ocirc; đ&amp;agrave;o tạo h&amp;agrave;ng ngh&amp;igrave;n sinh vi&amp;ecirc;n mỗi năm, trường đang từng bước khẳng định vị thế l&amp;agrave; một cơ sở đ&amp;agrave;o tạo uy t&amp;iacute;n, g&amp;oacute;p phần cung cấp nguồn nh&amp;acirc;n lực chất lượng cho sự ph&amp;aacute;t triển của H&amp;agrave; Nội v&amp;agrave; khu vực ph&amp;iacute;a Bắc.</p>', N'Hơn 2420 sinh viên', 1, N'dai-hoc-thu-do-ha-noi', 1, CAST(N'2026-04-27T22:29:18.180' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (24, N'Đại Học Sư Phạm TPHCM', N'280 An Dương Vương, phường Chợ Quán, Thành phố Hồ Chí Minh,  Việt Nam', N'TP Hồ Chí Minh', 3, 1, N'0838355077', N'http://hcmue.edu.vn/', N'/Resources/Images/truong/dai-hoc-su-pham-tphcm_logo_018bfe83.png', N'/Resources/Images/truong/dai-hoc-su-pham-tphcm_cover_6f33c5a4.jpg', N'<p>Trường Đại học Sư phạm Thành phố Hồ Chí Minh là một trong những trường đại học sư phạm trọng điểm của Việt Nam, đặc biệt giữ vai trò quan trọng trong việc đào tạo giáo viên cho khu vực phía Nam. Trường trực thuộc Bộ Giáo dục và Đào tạo, có lịch sử phát triển lâu đời và uy tín cao trong hệ thống giáo dục đại học.</p>
<p>Nhà trường đào tạo đa ngành, trong đó thế mạnh nổi bật vẫn là các ngành sư phạm như Toán, Ngữ văn, Tiếng Anh, Vật lý, Hóa học, Sinh học…, đồng thời mở rộng sang nhiều ngành ngoài sư phạm để đáp ứng nhu cầu xã hội. Chương trình đào tạo được xây dựng theo hướng chuyên sâu, chú trọng nền tảng kiến thức học thuật kết hợp với kỹ năng giảng dạy và thực hành nghề nghiệp, giúp sinh viên sau khi tốt nghiệp có thể đáp ứng tốt yêu cầu công việc.</p>
<p>Bên cạnh đó, trường còn là trung tâm nghiên cứu khoa học có uy tín, đặc biệt trong lĩnh vực khoa học giáo dục và khoa học cơ bản, với nhiều đề tài và công trình có giá trị. Môi trường học tập tại đây nghiêm túc, kỷ luật nhưng cũng năng động, tạo điều kiện cho sinh viên phát triển toàn diện cả về chuyên môn lẫn kỹ năng mềm. Hàng năm, trường tuyển sinh với quy mô lớn, đào tạo hàng chục nghìn sinh viên, góp phần cung cấp nguồn nhân lực chất lượng cao cho ngành giáo dục và xã hội.</p>', N'Hơn 23000 sinh viên', 1, N'dai-hoc-su-pham-tphcm', 1, CAST(N'2026-04-28T20:19:41.033' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (25, N'Đại Học Giao Thông Vận Tải', N'Số 450-451 Lê Văn Việt, phường Tăng Nhơn Phú, Thành phố Hồ Chí Minh,  Việt Nam', N'TP Hồ Chí Minh', 3, 1, N'0837663311', N'https://www.utc.edu.vn/', N'/Resources/Images/truong/dai-hoc-giao-thong-van-tai_logo_d6356637.jpg', N'/Resources/Images/truong/dai-hoc-giao-thong-van-tai_cover_ba58f190.jpg', N'<p>Trường Đại học Giao thông Vận tải là một trong những trường đại học kỹ thuật trọng điểm của Việt Nam, trực thuộc Bộ Giao thông Vận tải, có vai trò quan trọng trong đào tạo nguồn nhân lực phục vụ lĩnh vực giao thông, xây dựng và phát triển hạ tầng quốc gia. Với lịch sử lâu đời, trường đã đào tạo nhiều thế hệ kỹ sư, cán bộ kỹ thuật và chuyên gia đang làm việc trong các công trình trọng điểm trên cả nước.</p>
<p>Trường đào tạo đa ngành, trong đó thế mạnh nổi bật là các lĩnh vực như Kỹ thuật xây dựng công trình giao thông (cầu, đường, hầm), Kỹ thuật cơ khí, Kỹ thuật ô tô, Công nghệ thông tin, Logistics và Kinh tế vận tải. Chương trình đào tạo được thiết kế theo hướng ứng dụng, kết hợp chặt chẽ giữa lý thuyết và thực hành, giúp sinh viên có khả năng làm việc thực tế cao ngay sau khi tốt nghiệp. Ngoài ra, sinh viên còn được tham gia thực tập tại các doanh nghiệp, công trình và dự án lớn để tích lũy kinh nghiệm.</p>
<p>Bên cạnh đào tạo, trường còn là trung tâm nghiên cứu khoa học và chuyển giao công nghệ hàng đầu trong lĩnh vực giao thông – hạ tầng, tham gia tư vấn và triển khai nhiều dự án lớn của quốc gia như đường cao tốc, cầu, hệ thống vận tải đô thị. Đội ngũ giảng viên có trình độ cao, nhiều người là chuyên gia đầu ngành, góp phần nâng cao chất lượng giảng dạy và nghiên cứu.</p>
<p>Môi trường học tập tại trường mang tính kỹ thuật cao, đòi hỏi sinh viên phải có tư duy logic, khả năng tính toán và sự kiên trì. Tuy nhiên, đây cũng là môi trường năng động với nhiều hoạt động học thuật, câu lạc bộ và cơ hội phát triển kỹ năng. Với quy mô đào tạo lớn, mỗi năm tuyển sinh hàng nghìn sinh viên, Trường Đại học Giao thông Vận tải được đánh giá là một trong những cái nôi đào tạo kỹ sư uy tín, đóng góp quan trọng vào sự phát triển hạ tầng và kinh tế của Việt Nam.</p>', N'Hơn 21388 sinh viên', 1, N'dai-hoc-giao-thong-van-tai', 1, CAST(N'2026-04-28T20:25:25.170' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (26, N'Đại Học Y Dược Thái Bình', N'Số 373, phố Lý Bôn, phường Trần Lãm, Hưng Yên,  Việt Nam', N'Tỉnh Hưng Yên', 1, 1, N'0873838545', N'http://www.tbump.edu.vn/', N'/Resources/Images/truong/dai-hoc-y-duoc-thai-binh_logo_3c74c524.png', N'/Resources/Images/truong/dai-hoc-y-duoc-thai-binh_cover_1029365c.jpg', N'<p>Trường Đại học Y Dược Thái Bình là một trường đại học công lập trực thuộc Bộ Y tế, chuyên đào tạo nguồn nhân lực trong lĩnh vực y khoa và chăm sóc sức khỏe. Trường có trụ sở tại tỉnh Thái Bình và được xem là một trong những cơ sở đào tạo y dược uy tín ở khu vực phía Bắc.</p>
<p>Nhà trường đào tạo nhiều ngành như Y đa khoa, Dược học, Điều dưỡng, Y học dự phòng và các chuyên ngành liên quan đến chăm sóc sức khỏe. Chương trình đào tạo mang tính chuyên sâu, kết hợp chặt chẽ giữa lý thuyết và thực hành lâm sàng, giúp sinh viên có kiến thức vững vàng và kỹ năng nghề nghiệp tốt. Sinh viên được thực tập tại các bệnh viện, cơ sở y tế lớn để tích lũy kinh nghiệm thực tế ngay trong quá trình học.</p>
<p>Bên cạnh đào tạo, trường còn chú trọng nghiên cứu khoa học trong lĩnh vực y học, góp phần nâng cao chất lượng khám chữa bệnh và chăm sóc sức khỏe cộng đồng. Đội ngũ giảng viên là các bác sĩ, chuyên gia có trình độ cao và giàu kinh nghiệm. Môi trường học tập nghiêm túc, kỷ luật, đòi hỏi sinh viên phải có sự chăm chỉ và tinh thần trách nhiệm cao.</p>
<p>Với quy mô đào tạo hàng nghìn sinh viên mỗi năm, Trường Đại học Y Dược Thái Bình đã và đang cung cấp nguồn nhân lực y tế chất lượng cho nhiều tỉnh thành trên cả nước, đóng góp quan trọng vào sự phát triển của ngành y tế Việt Nam.</p>', N'Hơn 7500 sinh viên', 1, N'dai-hoc-y-duoc-thai-binh', 1, CAST(N'2026-04-28T21:35:56.590' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (27, N'Học Viện Kỹ Thuật Mật Mã', N'141 đường Chiến Thắng, phường Định Công, Hà Nội, Việt Nam', N'TP Hà Nội', 1, 1, N'0986622772', N'http://actvn.edu.vn/', N'/Resources/Images/truong/hoc-vien-ky-thuat-mat-ma_logo_515c7c87.jpg', N'/Resources/Images/truong/hoc-vien-ky-thuat-mat-ma_cover_f3f26c8d.jpg', N'<p>Học viện Kỹ thuật Mật mã là một cơ sở đào tạo đặc thù trực thuộc Ban Cơ yếu Chính phủ, chuyên sâu trong lĩnh vực an toàn thông tin, mật mã và công nghệ thông tin. Đây là một trong những đơn vị hàng đầu tại Việt Nam đào tạo nguồn nhân lực chất lượng cao phục vụ cho các cơ quan nhà nước, quốc phòng và các doanh nghiệp trong lĩnh vực bảo mật thông tin.</p>
<p>Học viện đào tạo các ngành mũi nhọn như An toàn thông tin, Công nghệ thông tin, Kỹ thuật điện tử – viễn thông, với chương trình học mang tính chuyên sâu, chú trọng cả lý thuyết nền tảng và kỹ năng thực hành. Sinh viên được tiếp cận với các kiến thức về bảo mật hệ thống, mã hóa dữ liệu, an ninh mạng và các công nghệ hiện đại, đáp ứng nhu cầu ngày càng cao trong thời đại chuyển đổi số.</p>
<p>Bên cạnh đào tạo, học viện còn là trung tâm nghiên cứu khoa học quan trọng trong lĩnh vực mật mã và an toàn thông tin, tham gia nhiều dự án bảo mật cấp quốc gia. Đội ngũ giảng viên gồm nhiều chuyên gia đầu ngành, có trình độ cao và kinh nghiệm thực tế. Môi trường học tập tại đây mang tính kỷ luật, yêu cầu sinh viên có tư duy logic tốt và khả năng học tập nghiêm túc.</p>
<p>Với quy mô đào tạo không quá lớn nhưng chất lượng cao, Học viện Kỹ thuật Mật mã được đánh giá là một trong những lựa chọn hàng đầu cho những ai muốn theo đuổi lĩnh vực an ninh mạng và công nghệ bảo mật tại Việt Nam.</p>', N'Hơn 520 học sinh', 1, N'hoc-vien-ky-thuat-mat-ma', 1, CAST(N'2026-04-28T20:37:47.620' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (28, N'Đại Học Công Nghiệp Hà Nội', N'298 Cầu Diễn, phường Tây Tựu, thành phố Hà Nội.', N'TP Hà Nội', 1, 1, N'0834560255', N'https://www.haui.edu.vn/vn', N'/Resources/Images/truong/dai-hoc-cong-nghiep-ha-noi_logo_71655361.png', N'/Resources/Images/truong/dai-hoc-cong-nghiep-ha-noi_cover_e2c490d3.jpg', N'<p>Trường Đại học Công nghiệp Hà Nội là một trường đại học công lập trực thuộc Bộ Công Thương, có thế mạnh trong đào tạo các ngành kỹ thuật, công nghệ và kinh tế ứng dụng. Trường có trụ sở tại Hà Nội và được đánh giá là một trong những cơ sở đào tạo thực hành tốt, gắn liền với nhu cầu của doanh nghiệp và thị trường lao động.</p>
<p>Nhà trường đào tạo đa dạng các ngành như Công nghệ thông tin, Kỹ thuật cơ khí, Điện – điện tử, Tự động hóa, Kế toán, Quản trị kinh doanh và Thương mại điện tử. Chương trình đào tạo được xây dựng theo hướng ứng dụng, chú trọng thực hành, giúp sinh viên không chỉ nắm vững kiến thức mà còn có kỹ năng làm việc thực tế. Sinh viên có nhiều cơ hội thực tập tại các doanh nghiệp, khu công nghiệp và tập đoàn lớn ngay trong quá trình học.</p>
<p>Bên cạnh đào tạo, trường còn đẩy mạnh hoạt động nghiên cứu khoa học, chuyển giao công nghệ và hợp tác quốc tế với nhiều trường đại học, doanh nghiệp nước ngoài. Môi trường học tập năng động, thực tế, phù hợp với những sinh viên muốn sớm đi làm và có kỹ năng nghề nghiệp vững vàng.</p>
<p>Với quy mô đào tạo lớn, lên tới hàng chục nghìn sinh viên, Trường Đại học Công nghiệp Hà Nội là một trong những trường có số lượng sinh viên đông và chất lượng đào tạo ổn định, đóng góp nguồn nhân lực quan trọng cho ngành công nghiệp và kinh tế của Việt Nam.</p>', N'Hơn 35000 sinh viên', 1, N'dai-hoc-cong-nghiep-ha-noi', 1, CAST(N'2026-04-28T20:41:26.510' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (29, N'Đại Học Y Dược Hải Phòng', N'72A, đường Nguyễn Bỉnh Khiêm, quận Ngô Quyền, Thành phố Hải Phòng, Việt Nam.', N'TP Hải Phòng', 1, 1, N'0853731907', N'http://www.hpmu.edu.vn/', N'/Resources/Images/truong/dai-hoc-y-duoc-hai-phong_logo_41cb0fec.jpg', N'/Resources/Images/truong/dai-hoc-y-duoc-hai-phong_cover_0dd878b9.jpg', N'<p>Trường Đại học Y Dược Hải Phòng là một trường đại học công lập trực thuộc Bộ Y tế, có vai trò quan trọng trong đào tạo nguồn nhân lực y tế cho khu vực phía Bắc, đặc biệt là vùng duyên hải Bắc Bộ. Trường đặt tại thành phố Hải Phòng và có bề dày kinh nghiệm trong đào tạo bác sĩ, dược sĩ và cán bộ y tế chất lượng cao.</p>
<p>Nhà trường đào tạo nhiều ngành như Y đa khoa, Dược học, Điều dưỡng, Y học dự phòng và các chuyên ngành liên quan đến chăm sóc sức khỏe. Chương trình đào tạo mang tính chuyên sâu, chú trọng kết hợp giữa lý thuyết và thực hành lâm sàng, giúp sinh viên nắm vững kiến thức chuyên môn và có kỹ năng nghề nghiệp vững vàng. Sinh viên được thực tập tại các bệnh viện lớn, trực tiếp tham gia vào quá trình khám chữa bệnh để tích lũy kinh nghiệm thực tế.</p>
<p>Bên cạnh công tác đào tạo, trường còn là trung tâm nghiên cứu khoa học trong lĩnh vực y học, đóng góp nhiều đề tài có giá trị cho việc nâng cao chất lượng chăm sóc sức khỏe cộng đồng. Đội ngũ giảng viên gồm các bác sĩ, chuyên gia có trình độ cao và giàu kinh nghiệm thực tiễn.</p>
<p>Môi trường học tập tại trường nghiêm túc, kỷ luật và đòi hỏi sự chăm chỉ, trách nhiệm cao từ sinh viên. Với quy mô đào tạo hàng nghìn sinh viên mỗi năm, Trường Đại học Y Dược Hải Phòng đang ngày càng khẳng định vị thế là một trong những cơ sở đào tạo y dược uy tín, cung cấp nguồn nhân lực quan trọng cho ngành y tế Việt Nam.</p>', N'Hơn 1600 sinh viên', 1, N'dai-hoc-y-duoc-hai-phong', 1, CAST(N'2026-04-28T20:55:57.110' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (30, N'Đại Học Công Nghiệp TPHCM', N'12 Nguyễn Văn Bảo, phường Hạnh Thông, Thành phố Hồ Chí Minh, Việt Nam', N'TP Hồ Chí Minh', 1, 1, N'0838940390', N'http://www.iuh.edu.vn/', N'/Resources/Images/truong/dai-hoc-cong-nghiep-tphcm_logo_0fe7d185.jpg', N'/Resources/Images/truong/dai-hoc-cong-nghiep-tphcm_cover_d9ed88c5.jpg', N'<p>Trường Đại học Công nghiệp Thành phố Hồ Chí Minh là một trường đại học công lập trực thuộc Bộ Công Thương, có quy mô lớn và uy tín trong đào tạo các ngành kỹ thuật, công nghệ và kinh tế tại khu vực phía Nam. Trường có trụ sở chính tại TP. Hồ Chí Minh và nhiều cơ sở đào tạo khác, thu hút đông đảo sinh viên trên cả nước.</p>
<p>Nhà trường đào tạo đa ngành, trong đó nổi bật là các lĩnh vực như Công nghệ thông tin, Kỹ thuật cơ khí, Điện – điện tử, Tự động hóa, Công nghệ thực phẩm, Kế toán, Quản trị kinh doanh và Du lịch. Chương trình đào tạo được thiết kế theo hướng ứng dụng, chú trọng thực hành, giúp sinh viên vừa có kiến thức chuyên môn vững chắc vừa có kỹ năng làm việc thực tế. Sinh viên có nhiều cơ hội tham gia thực tập tại doanh nghiệp, khu công nghiệp và các tập đoàn lớn trong quá trình học.</p>
<p>Bên cạnh đào tạo, trường còn đẩy mạnh nghiên cứu khoa học, chuyển giao công nghệ và hợp tác quốc tế với nhiều đối tác nước ngoài, góp phần nâng cao chất lượng giảng dạy và mở rộng cơ hội học tập cho sinh viên. Môi trường học tập năng động, hiện đại, với nhiều hoạt động ngoại khóa và câu lạc bộ giúp sinh viên phát triển toàn diện.</p>
<p>Với quy mô đào tạo lên tới hàng chục nghìn sinh viên, Trường Đại học Công nghiệp TP.HCM là một trong những trường có số lượng sinh viên đông và chất lượng đào tạo ổn định, đóng vai trò quan trọng trong việc cung cấp nguồn nhân lực cho ngành công nghiệp và kinh tế của Việt Nam.</p>', N'Hơn 36000 sinh viên', 1, N'dai-hoc-cong-nghiep-tphcm', 1, CAST(N'2026-04-28T21:07:50.673' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (31, N'Đại Học Kỹ Thuật Y Tế Hải Dương', N'Số 1 Vũ Hựu, thành phố Hải Dương, tỉnh Hải Dương, Việt Nam', N'TP Hải Phòng', 1, 1, N'0803891799', N'http://www.hmtu.edu.vn/', N'/Resources/Images/truong/dai-hoc-ky-thuat-y-te-hai-duong_logo_c557f546.jpg', N'/Resources/Images/truong/dai-hoc-ky-thuat-y-te-hai-duong_cover_d8c304c3.jpg', N'<p>Trường Đại học Kỹ thuật Y tế Hải Dương là một trường đại học công lập trực thuộc Bộ Y tế, chuyên đào tạo nguồn nhân lực trong lĩnh vực kỹ thuật y học và chăm sóc sức khỏe. Trường có trụ sở tại tỉnh Hải Dương và được xem là một trong những cơ sở đào tạo hàng đầu tại Việt Nam về các ngành kỹ thuật y sinh và công nghệ y tế.</p>
<p>Nhà trường đào tạo đa dạng các ngành như Xét nghiệm y học, Điều dưỡng, Kỹ thuật hình ảnh y học, Kỹ thuật phục hồi chức năng và một số ngành liên quan đến công nghệ y sinh. Chương trình đào tạo mang tính chuyên sâu, kết hợp chặt chẽ giữa lý thuyết và thực hành, đặc biệt chú trọng kỹ năng thao tác với thiết bị y tế hiện đại. Sinh viên được thực tập tại các bệnh viện lớn, trực tiếp tham gia vào quá trình chẩn đoán và chăm sóc người bệnh.</p>
<p>Bên cạnh đào tạo, trường còn tích cực nghiên cứu khoa học và ứng dụng công nghệ trong y học, góp phần nâng cao chất lượng khám chữa bệnh. Đội ngũ giảng viên gồm các bác sĩ, kỹ sư y sinh và chuyên gia có trình độ cao, giàu kinh nghiệm thực tiễn.</p>
<p>Môi trường học tập tại trường nghiêm túc, kỷ luật và yêu cầu cao về trách nhiệm nghề nghiệp, phù hợp với những sinh viên theo đuổi lĩnh vực y tế. Với quy mô đào tạo hàng nghìn sinh viên mỗi năm, Trường Đại học Kỹ thuật Y tế Hải Dương đang ngày càng khẳng định vị thế là một trong những trường đào tạo kỹ thuật y học uy tín tại Việt Nam.</p>', N'Hơn 700 sinh viên', 1, N'dai-hoc-ky-thuat-y-te-hai-duong', 1, CAST(N'2026-04-28T21:36:20.353' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (32, N'Đại Học Giao Thông Vận Tải TPHCM', N'Số 2, đường Võ Oanh, Phường 25, quận Bình Thạnh, Thành phố Hồ Chí Minh, Việt Nam', N'TP Hồ Chí Minh', 3, 1, N'0838991373', N'http://ut.edu.vn/', N'/Resources/Images/truong/dai-hoc-giao-thong-van-tai-tphcm_logo_cd3a67cb.png', N'/Resources/Images/truong/dai-hoc-giao-thong-van-tai-tphcm_cover_ea94fded.jpg', N'<p>Trường Đại học Giao thông Vận tải Thành phố Hồ Chí Minh là một trường đại học công lập trực thuộc Bộ Giao thông Vận tải, có vai trò quan trọng trong đào tạo nguồn nhân lực cho lĩnh vực giao thông, vận tải và logistics tại khu vực phía Nam. Trường có trụ sở tại TP. Hồ Chí Minh và được đánh giá là một trong những cơ sở đào tạo uy tín trong nhóm ngành kỹ thuật – vận tải.</p>
<p>Nhà trường đào tạo đa ngành, trong đó nổi bật là các lĩnh vực như Kỹ thuật xây dựng công trình giao thông, Kỹ thuật tàu thủy, Logistics và quản lý chuỗi cung ứng, Kinh tế vận tải, Công nghệ thông tin và Cơ khí. Chương trình đào tạo được thiết kế theo hướng ứng dụng, kết hợp giữa lý thuyết và thực hành, giúp sinh viên có khả năng thích nghi tốt với môi trường làm việc thực tế. Sinh viên có nhiều cơ hội thực tập tại các cảng biển, doanh nghiệp vận tải, công ty logistics và các dự án hạ tầng lớn.</p>
<p>Bên cạnh đào tạo, trường còn chú trọng nghiên cứu khoa học và hợp tác với doanh nghiệp, đặc biệt trong lĩnh vực vận tải biển, logistics và phát triển hạ tầng giao thông. Đội ngũ giảng viên có chuyên môn cao, nhiều người có kinh nghiệm thực tế trong ngành.</p>
<p>Môi trường học tập tại trường năng động, mang tính kỹ thuật và thực tiễn cao, phù hợp với những sinh viên yêu thích lĩnh vực giao thông – vận tải. Với quy mô đào tạo hàng chục nghìn sinh viên, Trường Đại học Giao thông Vận tải TP.HCM đang ngày càng khẳng định vị thế là một trong những trường đào tạo hàng đầu trong lĩnh vực giao thông và logistics tại Việt Nam.</p>', N'Hơn 36.000 sinh viên', 1, N'dai-hoc-giao-thong-van-tai-tphcm', 1, CAST(N'2026-04-28T21:20:33.063' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (33, N'Đại học Kinh tế – Kỹ thuật Công nghiệp', N'456 đường Minh Khai, phường Vĩnh Tuy, quận Hai Bà Trưng, Hà Nội, Việt Nam', N'TP Hà Nội', 1, 1, N'0962698288', N'http://www.uneti.edu.vn/', N'/Resources/Images/truong/dai-hoc-kinh-te-ky-thuat-cong-nghiep_logo_e6569152.png', N'/Resources/Images/truong/dai-hoc-kinh-te-ky-thuat-cong-nghiep_cover_8fd727cf.jpg', N'<p>Trường Đại học Kinh tế – Kỹ thuật Công nghiệp là một trường đại học công lập trực thuộc Bộ Công Thương, có định hướng đào tạo đa ngành gắn liền giữa kinh tế và kỹ thuật. Trường có cơ sở tại Hà Nội và Nam Định, đóng vai trò quan trọng trong việc cung cấp nguồn nhân lực cho lĩnh vực công nghiệp và sản xuất tại Việt Nam.</p>
<p>Nhà trường đào tạo nhiều ngành học như Công nghệ thông tin, Kỹ thuật cơ khí, Điện – điện tử, Công nghệ may, Kế toán, Tài chính – Ngân hàng và Quản trị kinh doanh. Điểm nổi bật của trường là chương trình đào tạo mang tính ứng dụng cao, kết hợp giữa kiến thức kỹ thuật và kinh tế, giúp sinh viên có thể làm việc linh hoạt trong nhiều môi trường khác nhau, đặc biệt là doanh nghiệp sản xuất và công nghiệp.</p>
<p>Bên cạnh hoạt động giảng dạy, trường còn chú trọng nghiên cứu khoa học, chuyển giao công nghệ và hợp tác với doanh nghiệp nhằm nâng cao chất lượng đào tạo. Sinh viên có cơ hội tham gia thực tập tại các khu công nghiệp, nhà máy và doanh nghiệp lớn để tích lũy kinh nghiệm thực tế.</p>
<p>Môi trường học tập tại trường năng động, thực tế, phù hợp với những sinh viên muốn sớm tiếp cận công việc sau khi ra trường. Với quy mô đào tạo lớn, hàng chục nghìn sinh viên theo học, Trường Đại học Kinh tế – Kỹ thuật Công nghiệp đang ngày càng khẳng định vị thế là một cơ sở đào tạo uy tín trong khối ngành công nghiệp và kinh tế tại Việt Nam.</p>', N'Hơn 6.800 sinh viên', 1, N'dai-hoc-kinh-te-ky-thuat-cong-nghiep', 1, CAST(N'2026-04-28T21:49:29.673' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (34, N'Đại Học Công Thương TPHCM', N'140 Lê Trọng Tấn, phường Tây Thạnh, quận Tân Phú, Thành phố Hồ Chí Minh,  Việt Nam', N'TP Hồ Chí Minh', 3, 1, N'0862706275', N'https://huit.edu.vn/', N'/Resources/Images/truong/dai-hoc-cong-thuong-tphcm_logo_d9c09ff4.png', N'/Resources/Images/truong/dai-hoc-cong-thuong-tphcm_cover_9442d269.jpg', N'<p>Trường Đại học Công Thương Thành phố Hồ Chí Minh là một trường đại học công lập trực thuộc Bộ Công Thương, có thế mạnh trong đào tạo các ngành kinh tế, kỹ thuật và công nghệ gắn với lĩnh vực công nghiệp – thương mại. Trường có trụ sở tại TP. Hồ Chí Minh và được đánh giá là một trong những cơ sở đào tạo uy tín trong khối ngành ứng dụng tại khu vực phía Nam.</p>
<p>Nhà trường đào tạo đa dạng các ngành như Công nghệ thực phẩm, Công nghệ thông tin, Kỹ thuật điện – điện tử, Cơ khí, Quản trị kinh doanh, Marketing, Kế toán và Tài chính – Ngân hàng. Chương trình đào tạo được xây dựng theo hướng thực tiễn, chú trọng kết hợp giữa lý thuyết và thực hành, giúp sinh viên có kỹ năng nghề nghiệp vững vàng và khả năng thích nghi tốt với môi trường làm việc. Sinh viên có nhiều cơ hội thực tập tại các doanh nghiệp, nhà máy và tập đoàn lớn trong lĩnh vực công nghiệp và thương mại.</p>
<p>Bên cạnh đào tạo, trường còn tích cực nghiên cứu khoa học, chuyển giao công nghệ và hợp tác quốc tế, góp phần nâng cao chất lượng giảng dạy và mở rộng cơ hội học tập cho sinh viên. Môi trường học tập năng động, hiện đại với nhiều hoạt động ngoại khóa và câu lạc bộ giúp sinh viên phát triển toàn diện.</p>
<p>Với quy mô đào tạo lớn, hàng chục nghìn sinh viên theo học mỗi năm, Trường Đại học Công Thương TP.HCM đang ngày càng khẳng định vị thế là một trong những trường đào tạo nguồn nhân lực chất lượng cho lĩnh vực công nghiệp, thương mại và dịch vụ tại Việt Nam.</p>', N'Hơn 7000 sinh viên', 1, N'dai-hoc-cong-thuong-tphcm', 1, CAST(N'2026-04-28T21:54:11.790' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (35, N'Đại học Phenikaa', N'Đường Nguyễn Trác - Phường Dương Nội - Hà Nội, Hà Nội, Việt Nam', N'TP Hà Nội', 1, 2, N'0862918118', N'https://phenikaa-uni.edu.vn/vi', N'/Resources/Images/truong/dai-hoc-phenikaa_logo_4838602d.png', N'/Resources/Images/truong/dai-hoc-phenikaa_cover_f9b6fadf.webp', N'<p>Đại học Phenikaa là một trường đại học tư thục tại Hà Nội, phát triển theo mô hình đại học đa ngành, gắn kết chặt chẽ giữa đào tạo, nghiên cứu khoa học và doanh nghiệp. Trường được đầu tư bởi Tập đoàn Phenikaa và định hướng trở thành đại học đổi mới sáng tạo, nơi kết hợp giữa học thuật và thực tiễn để đáp ứng nhu cầu của xã hội hiện đại.</p>
<p>Trường đào tạo đa dạng các lĩnh vực như kỹ thuật, công nghệ thông tin, kinh tế, khoa học xã hội, ngoại ngữ và y dược. Chương trình học được thiết kế theo hướng ứng dụng, chú trọng thực hành và nghiên cứu, giúp sinh viên phát triển toàn diện cả kiến thức chuyên môn lẫn kỹ năng nghề nghiệp. Ngoài ra, sinh viên còn có cơ hội tiếp cận hệ sinh thái doanh nghiệp của tập đoàn, từ đó nâng cao khả năng thực tập và việc làm sau khi tốt nghiệp. (<a href="https://giadinh.phenikaa.com/dai-hoc-phenikaa-va-mo-hinh-dai-hoc-doi-moi-sang-tao-chien-luoc-dot-pha-phat-trien-ben-vung-vuon-tam/?utm_source=chatgpt.com" title="ĐẠI HỌC PHENIKAA VÀ MÔ HÌNH ĐẠI HỌC ĐỔI MỚI SÁNG TẠO, CHIẾN LƯỢC ĐỘT PHÁ PHÁT TRIỂN BỀN VỮNG – VƯƠN TẦM - Phenikaa">Phenikaa</a>)</p>
<p>Một điểm nổi bật của trường là tốc độ phát triển rất nhanh. Từ một trường mới với vài trăm sinh viên, đến nay Đại học Phenikaa đã đào tạo <strong>gần 25.000 sinh viên</strong> với hơn 100 chương trình đào tạo từ đại học đến tiến sĩ. (<a href="https://www.qdnd.vn/giao-duc-khoa-hoc/tin-tuc/dai-hoc-phenikaa-chinh-thuc-thanh-lap-mo-ra-giai-doan-phat-trien-moi-824306?utm_source=chatgpt.com" title="Đại học Phenikaa chính thức thành lập, mở ra giai đoạn phát triển mới">Quân đội nhân dân</a>) Đây cũng là một trong những đại học tư thục trẻ nhất tại Việt Nam được chuyển đổi lên mô hình “đại học” đa lĩnh vực. (<a href="https://kinhdoanhvaphattrien.vn/truong-dai-hoc-phenikaa-tro-thanh-dai-hoc-thu-10-cua-viet-nam-42365.html?utm_source=chatgpt.com" title="Trường Đại học Phenikaa trở thành &#39;Đại học&#39; thứ 10 của Việt Nam">Kinh doanh và Phát triển</a>)</p>
<p>Môi trường học tập tại đây năng động, hiện đại, định hướng sáng tạo và gắn với doanh nghiệp, phù hợp với những sinh viên muốn học theo hướng thực tiễn và có nhiều cơ hội nghề nghiệp sau khi ra trường.</p>', N'Hơn 12.000 sinh viên', 1, N'dai-hoc-phenikaa', 1, CAST(N'2026-04-28T21:58:17.013' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (36, N'Học Viện Cảnh Sát Nhân Dân', N'Đường Phạm Văn Nghị, phường Đông Ngạc, thành phố Hà Nội, Việt Nam', N'TP Hà Nội', 1, 1, N'0838362811', N'http://www.hvcsnd.edu.vn/', N'/Resources/Images/truong/hoc-vien-canh-sat-nhan-dan_logo_8c29b404.png', N'/Resources/Images/truong/hoc-vien-canh-sat-nhan-dan_cover_34c7645d.png', N'<p>Học viện Cảnh sát Nhân dân là một cơ sở đào tạo đặc thù trực thuộc Bộ Công an, giữ vai trò quan trọng trong việc đào tạo cán bộ, sĩ quan cảnh sát cho lực lượng Công an nhân dân Việt Nam. Trường có bề dày lịch sử từ năm 1975 (tiền thân là Trường Sĩ quan Cảnh sát) và được xem là một trong những học viện trọng điểm của ngành công an. (<a href="https://hvcsnd.edu.vn/dao-tao/dao-tao-dai-hoc?utm_source=chatgpt.com" title="Đào tạo - Học viện Cảnh sát nhân dân">Học viện Cảnh sát Nhân dân</a>)</p>
<p>Học viện đào tạo nhiều chương trình từ đại học đến sau đại học, bao gồm các lĩnh vực như điều tra tội phạm, cảnh sát hình sự, quản lý trật tự xã hội, an ninh và các chuyên ngành nghiệp vụ khác. Chương trình học mang tính đặc thù cao, kết hợp giữa kiến thức pháp luật, nghiệp vụ công an và rèn luyện thể chất, võ thuật, kỷ luật nghiêm ngặt nhằm đáp ứng yêu cầu công việc thực tế. (<a href="https://tienphong.vn/can-canh-hoc-vien-canh-sat-miet-mai-luyen-vo-post805499.tpo?utm_source=chatgpt.com" title="Cận cảnh học viên cảnh sát miệt mài luyện võ | Báo điện tử Tiền Phong">Báo điện tử Tiền Phong</a>)</p>
<p>Bên cạnh đào tạo, học viện còn là trung tâm nghiên cứu khoa học lớn trong lĩnh vực tội phạm học, điều tra và an ninh, tham gia nhiều đề tài cấp ngành và cấp quốc gia. Với đội ngũ giảng viên đông đảo, trình độ cao và hệ thống cơ sở vật chất được đầu tư, học viện có khả năng đào tạo số lượng lớn học viên mỗi năm, được đánh giá là một trong những cơ sở đào tạo có quy mô lớn nhất trong khối các trường thuộc Bộ Công an. (<a href="https://hvcsnd.edu.vn/hoc-vien-canh-sat-nhan-dan-viet-nam-voi-be-day-kinh-nghiem-va-nhiem-vu-hop-tac-dao-tao-quoc-te-7876?utm_source=chatgpt.com" title="Học viện Cảnh sát nhân dân Việt Nam với bề dầy kinh nghiệm và nhiệm vụ hợp tác đào tạo quốc tế - Học viện Cảnh sát nhân dân">Học viện Cảnh sát Nhân dân</a>)</p>
<p>Môi trường học tập tại đây rất kỷ luật, mang tính quân sự hóa cao, đòi hỏi học viên phải có ý chí, sức khỏe và tinh thần trách nhiệm. Có thể nói, Học viện Cảnh sát Nhân dân không chỉ đào tạo kiến thức mà còn rèn luyện bản lĩnh, đạo đức và tác phong của người chiến sĩ công an trong quá trình bảo vệ an ninh trật tự và phục vụ xã hội.</p>', N'Hơn 10.000 sinh viên', 1, N'hoc-vien-canh-sat-nhan-dan', 1, CAST(N'2026-04-28T22:01:43.620' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (37, N'Học Viện Hải Quân', N'30 Trần Phú, Vĩnh Nguyên, Nha Trang, Khánh Hòa', N'Tỉnh Khánh Hoà', 2, 1, N'0882881102', N'http://hocvienhaiquan.edu.vn/', N'/Resources/Images/truong/hoc-vien-hai-quan_logo_eb4ff503.jpg', N'/Resources/Images/truong/hoc-vien-hai-quan_cover_9170a7d2.jpg', N'<p>Học viện Hải quân là một cơ sở đào tạo sĩ quan quân đội trực thuộc Quân chủng Hải quân – Bộ Quốc phòng, có nhiệm vụ đào tạo cán bộ chỉ huy, kỹ sư và sĩ quan phục vụ trong lực lượng Hải quân nhân dân Việt Nam. Trường đặt tại thành phố Nha Trang và được xem là trung tâm đào tạo quan trọng trong lĩnh vực quốc phòng trên biển.</p>
<p>Học viện đào tạo các chuyên ngành đặc thù như Chỉ huy tham mưu hải quân, Kỹ thuật tàu thủy, Vũ khí – khí tài hải quân, Điện – điện tử và các lĩnh vực liên quan đến tác chiến trên biển. Chương trình đào tạo mang tính chuyên sâu, kết hợp giữa kiến thức quân sự, kỹ thuật và rèn luyện thể chất, giúp học viên có đủ năng lực thực hiện nhiệm vụ bảo vệ chủ quyền biển đảo.</p>
<p>Bên cạnh công tác đào tạo, học viện còn là trung tâm nghiên cứu khoa học quân sự, tham gia nhiều đề tài liên quan đến chiến lược, kỹ thuật và công nghệ trong lĩnh vực hải quân. Đội ngũ giảng viên là các sĩ quan, chuyên gia có trình độ cao và nhiều kinh nghiệm thực tiễn.</p>
<p>Môi trường học tập tại đây mang tính quân sự hóa cao, kỷ luật nghiêm ngặt, đòi hỏi học viên phải có ý chí, sức khỏe và tinh thần trách nhiệm cao. Sinh viên theo học thường được hưởng chế độ của quân đội và có định hướng nghề nghiệp rõ ràng sau khi tốt nghiệp. Có thể nói, Học viện Hải quân là cái nôi đào tạo những sĩ quan nòng cốt góp phần bảo vệ chủ quyền biển đảo và an ninh quốc gia của Việt Nam.</p>', N'Hơn 200 sinh viên', 1, N'hoc-vien-hai-quan', 1, CAST(N'2026-04-28T22:06:17.883' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (38, N'Học Viện Hàng không Việt Nam', N'104 Đ. Nguyễn Văn Trỗi, Phường 8, Phú Nhuận, Hồ Chí Minh', N'TP Hồ Chí Minh', 3, 1, N'0838442251', N'https://vaa.edu.vn/', N'/Resources/Images/truong/hoc-vien-hang-khong-viet-nam_logo_38b21c05.jpg', N'/Resources/Images/truong/hoc-vien-hang-khong-viet-nam_cover_a80714cb.jpg', N'<p>Học viện Hàng không Việt Nam là một cơ sở đào tạo công lập trực thuộc Bộ Giao thông Vận tải, chuyên đào tạo nguồn nhân lực chất lượng cao cho ngành hàng không dân dụng tại Việt Nam. Trường có trụ sở chính tại TP. Hồ Chí Minh và đóng vai trò quan trọng trong việc cung cấp nhân lực cho các hãng hàng không, sân bay và doanh nghiệp dịch vụ hàng không.</p>
<p>Học viện đào tạo đa dạng các ngành như Quản lý hoạt động bay, Kỹ thuật hàng không, Quản trị kinh doanh vận tải hàng không, Logistics và Công nghệ thông tin. Chương trình đào tạo được xây dựng theo hướng ứng dụng, kết hợp giữa kiến thức chuyên môn và kỹ năng thực hành, giúp sinh viên đáp ứng tốt yêu cầu công việc trong môi trường hàng không hiện đại.</p>
<p>Bên cạnh đó, trường còn đẩy mạnh hợp tác với các hãng hàng không, doanh nghiệp trong và ngoài nước, tạo điều kiện cho sinh viên thực tập và tiếp cận thực tế nghề nghiệp ngay trong quá trình học. Đội ngũ giảng viên có chuyên môn cao, nhiều người có kinh nghiệm làm việc thực tế trong ngành hàng không.</p>
<p>Môi trường học tập tại học viện năng động, hiện đại, mang tính chuyên ngành rõ rệt, phù hợp với những sinh viên yêu thích lĩnh vực hàng không và dịch vụ vận tải. Với quy mô đào tạo hàng nghìn sinh viên mỗi năm, Học viện Hàng không Việt Nam đang ngày càng khẳng định vị thế là một trong những cơ sở đào tạo uy tín trong lĩnh vực hàng không tại Việt Nam.</p>', N'Hơn 3020 sinh viên', 0, N'hoc-vien-hang-khong-viet-nam', 1, CAST(N'2026-04-28T22:11:10.510' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (39, N'Học Viện Phòng Không – Không Quân', N'3FXM+XXR, Kim Sơn, Đoài Phương, Hà Nội', N'TP Hà Nội', 1, 1, N'0833614577', N'http://hocvienpkkq.com/', N'/Resources/Images/truong/hoc-vien-phong-khong-khong-quan_logo_704e7f46.jpg', N'/Resources/Images/truong/hoc-vien-phong-khong-khong-quan_cover_af083d37.png', N'<p>Học viện Phòng không – Không quân là một cơ sở đào tạo sĩ quan quân đội trực thuộc Quân chủng Phòng không – Không quân, Bộ Quốc phòng, có nhiệm vụ đào tạo cán bộ chỉ huy, sĩ quan và kỹ sư phục vụ trong lực lượng phòng không và không quân của Việt Nam. Đây là một trong những học viện quân sự quan trọng, giữ vai trò nòng cốt trong việc xây dựng và phát triển lực lượng bảo vệ vùng trời quốc gia.</p>
<p>Học viện đào tạo các chuyên ngành đặc thù như Chỉ huy tham mưu phòng không – không quân, Kỹ thuật hàng không, Ra-đa, Tên lửa phòng không, Điện tử – viễn thông quân sự… Chương trình đào tạo mang tính chuyên sâu, kết hợp giữa kiến thức quân sự, kỹ thuật hiện đại và huấn luyện thực hành, giúp học viên có đủ năng lực thực hiện nhiệm vụ tác chiến và bảo vệ an ninh vùng trời.</p>
<p>Bên cạnh công tác đào tạo, học viện còn là trung tâm nghiên cứu khoa học quân sự, tham gia nhiều đề tài về công nghệ quốc phòng, vũ khí và chiến lược tác chiến trên không. Đội ngũ giảng viên gồm các sĩ quan, chuyên gia có trình độ cao, giàu kinh nghiệm thực tiễn trong lĩnh vực phòng không – không quân.</p>
<p>Môi trường học tập tại đây mang tính kỷ luật cao, quân sự hóa, đòi hỏi học viên phải có thể lực tốt, ý chí vững vàng và tinh thần trách nhiệm cao. Sinh viên theo học thường được hưởng chế độ của quân đội và có định hướng công việc rõ ràng sau khi tốt nghiệp. Có thể nói, Học viện Phòng không – Không quân là nơi đào tạo những sĩ quan nòng cốt, góp phần quan trọng trong việc bảo vệ chủ quyền vùng trời và an ninh quốc gia của Việt Nam.</p>', N'Hơn 5000 sinh viên', 1, N'hoc-vien-phong-khong-khong-quan', 1, CAST(N'2026-04-28T22:20:59.267' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (40, N'Đại Học Cảnh Sát Nhân Dân', N'số 36 đường Nguyễn Hữu Thọ, phường Tân Phong, quận 7, thành phố Hồ Chí Minh', N'TP Hồ Chí Minh', 3, 1, N'0843836281', N'http://www.pup.edu.vn/', N'/Resources/Images/truong/dai-hoc-canh-sat-nhan-dan_logo_50b186b4.png', N'/Resources/Images/truong/dai-hoc-canh-sat-nhan-dan_cover_672a3f82.jpg', N'<p>Trường Đại học Cảnh sát Nhân dân là một cơ sở đào tạo thuộc Bộ Công an, có nhiệm vụ đào tạo cán bộ, sĩ quan cảnh sát cho lực lượng Công an nhân dân Việt Nam, đặc biệt phục vụ khu vực phía Nam. Trường có trụ sở tại TP. Hồ Chí Minh và được xem là một trong những đơn vị đào tạo trọng điểm trong khối các trường công an.</p>
<p>Nhà trường đào tạo nhiều chuyên ngành nghiệp vụ như Điều tra tội phạm, Cảnh sát hình sự, Cảnh sát quản lý hành chính về trật tự xã hội, Phòng chống tội phạm công nghệ cao… Chương trình đào tạo mang tính đặc thù cao, kết hợp giữa kiến thức pháp luật, nghiệp vụ công an và rèn luyện thể chất, võ thuật, kỷ luật nghiêm ngặt nhằm đáp ứng yêu cầu công tác thực tế.</p>
<p>Bên cạnh đào tạo, trường còn chú trọng nghiên cứu khoa học trong lĩnh vực tội phạm học, điều tra và quản lý an ninh trật tự. Đội ngũ giảng viên là các sĩ quan, chuyên gia có trình độ cao và nhiều kinh nghiệm thực tiễn trong ngành công an.</p>
<p>Môi trường học tập tại đây mang tính quân sự hóa cao, kỷ luật nghiêm khắc, yêu cầu sinh viên phải có ý chí, sức khỏe và tinh thần trách nhiệm. Sinh viên theo học thường được hưởng chế độ của ngành công an và có định hướng nghề nghiệp rõ ràng sau khi tốt nghiệp. Có thể nói, Trường Đại học Cảnh sát Nhân dân là nơi đào tạo lực lượng nòng cốt góp phần bảo đảm an ninh trật tự và an toàn xã hội tại Việt Nam.</p>', N'Hơn 4.000 sinh viên', 1, N'dai-hoc-canh-sat-nhan-dan', 1, CAST(N'2026-04-29T14:33:32.637' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (41, N'Đại Học Y Tế Công Cộng', N'1A đường Đức Thắng, phường Đức Thắng, quận Bắc Từ Liêm, Hà Nội, Việt Nam', N'TP Hà Nội', 1, 1, N'0332592223', N'http://www.huph.edu.vn/', N'/Resources/Images/truong/dai-hoc-y-te-cong-cong_logo_f4f912aa.jpg', N'/Resources/Images/truong/dai-hoc-y-te-cong-cong_cover_44dfc670.png', N'<p>Trường Đại học Y tế Công cộng là một trường đại học công lập trực thuộc Bộ Y tế, chuyên đào tạo và nghiên cứu trong lĩnh vực y tế công cộng, quản lý y tế và chăm sóc sức khỏe cộng đồng. Trường có trụ sở tại Hà Nội và được xem là cơ sở đào tạo hàng đầu tại Việt Nam trong lĩnh vực y học dự phòng và y tế cộng đồng.</p>
<p>Nhà trường đào tạo các ngành đặc thù như Y tế công cộng, Dinh dưỡng, Khoa học dữ liệu trong y tế, Quản lý bệnh viện và các chương trình liên quan đến chính sách y tế. Chương trình đào tạo mang tính ứng dụng cao, tập trung vào việc phòng bệnh, nâng cao sức khỏe cộng đồng và quản lý hệ thống y tế, khác với các trường đào tạo bác sĩ lâm sàng.</p>
<p>Bên cạnh giảng dạy, trường còn là trung tâm nghiên cứu khoa học uy tín, tham gia nhiều dự án trong nước và quốc tế về dịch tễ học, sức khỏe môi trường, dinh dưỡng và chính sách y tế. Đội ngũ giảng viên có trình độ cao, nhiều người tham gia tư vấn cho các chương trình y tế quốc gia và tổ chức quốc tế.</p>
<p>Môi trường học tập tại trường mang tính học thuật, hiện đại và hướng tới cộng đồng, phù hợp với những sinh viên muốn theo đuổi lĩnh vực chăm sóc sức khỏe ở tầm vĩ mô. Với quy mô đào tạo hàng nghìn sinh viên, Trường Đại học Y tế Công cộng đóng vai trò quan trọng trong việc cung cấp nguồn nhân lực cho hệ thống y tế dự phòng và quản lý y tế tại Việt Nam.</p>', N'Hơn 850 sinh viên', 0, N'dai-hoc-y-te-cong-cong', 1, CAST(N'2026-04-29T14:37:59.133' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (42, N'Học viện Ngoại giao', N'số 69 phố Chùa Láng, phường Láng Thượng, thành phố Hà Nội, nước  Việt Nam', N'TP Hà Nội', 1, 1, N'0818956595', N'http://dav.edu.vn', N'/Resources/Images/truong/hoc-vien-ngoai-giao_logo_0f8178c2.png', N'/Resources/Images/truong/hoc-vien-ngoai-giao_cover_43fc7ea7.png', N'<p>Học viện Ngoại giao là một cơ sở đào tạo và nghiên cứu trực thuộc Bộ Ngoại giao, có vai trò hàng đầu trong việc đào tạo nguồn nhân lực chất lượng cao cho lĩnh vực đối ngoại, quan hệ quốc tế và chính sách toàn cầu của Việt Nam. Trường có trụ sở tại Hà Nội và được đánh giá là một trong những học viện uy tín trong khối ngành khoa học xã hội và quốc tế.</p>
<p>Học viện đào tạo nhiều ngành như Quan hệ quốc tế, Truyền thông quốc tế, Kinh tế quốc tế, Luật quốc tế và Ngôn ngữ Anh, với chương trình học mang tính học thuật cao, cập nhật theo xu hướng toàn cầu và chú trọng phát triển tư duy phân tích, kỹ năng ngoại ngữ và khả năng hội nhập quốc tế. Sinh viên tại đây thường có cơ hội tham gia các hội thảo quốc tế, chương trình trao đổi và thực tập tại các cơ quan ngoại giao, tổ chức quốc tế.</p>
<p>Bên cạnh đào tạo, học viện còn là trung tâm nghiên cứu chiến lược và chính sách đối ngoại, tham gia tư vấn cho Nhà nước trong nhiều vấn đề quốc tế quan trọng. Đội ngũ giảng viên gồm nhiều chuyên gia, nhà nghiên cứu và nhà ngoại giao giàu kinh nghiệm.</p>
<p>Môi trường học tập tại học viện năng động, mang tính quốc tế cao, đòi hỏi sinh viên có khả năng ngoại ngữ tốt, tư duy mở và sự nhạy bén với các vấn đề toàn cầu. Với quy mô đào tạo không quá lớn nhưng chất lượng cao, Học viện Ngoại giao được xem là cái nôi đào tạo nhiều nhà ngoại giao, chuyên gia và cán bộ làm việc trong lĩnh vực quốc tế của Việt Nam.</p>', N'Hơn 7.000 viên sinh viên', 1, N'hoc-vien-ngoai-giao', 1, CAST(N'2026-04-29T14:42:06.623' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (43, N'Đại Học Y Dược Cần Thơ', N'179 Đ. Nguyễn Văn Cừ, P, Tân An, Cần Thơ', N'TP Cần Thơ', 3, 1, N'0927397302', N'http://ctump.edu.vn/', N'/Resources/Images/truong/dai-hoc-y-duoc-can-tho_logo_3939ff2b.png', N'/Resources/Images/truong/dai-hoc-y-duoc-can-tho_cover_593a1a90.jpg', N'<p>Trường Đại học Y Dược Cần Thơ là một trường đại học công lập trực thuộc Bộ Y tế, giữ vai trò quan trọng trong đào tạo nguồn nhân lực y tế cho khu vực Đồng bằng sông Cửu Long và cả nước. Trường có trụ sở tại thành phố Cần Thơ và được xem là một trong những cơ sở đào tạo y dược uy tín tại miền Nam.</p>
<p>Nhà trường đào tạo đa dạng các ngành như Y đa khoa, Răng – Hàm – Mặt, Dược học, Điều dưỡng, Y học dự phòng và các chuyên ngành liên quan đến chăm sóc sức khỏe. Chương trình đào tạo mang tính chuyên sâu, kết hợp giữa lý thuyết và thực hành lâm sàng, giúp sinh viên có nền tảng kiến thức vững chắc và kỹ năng nghề nghiệp tốt. Sinh viên được thực tập tại các bệnh viện lớn trong khu vực, trực tiếp tham gia vào công tác khám chữa bệnh để tích lũy kinh nghiệm thực tế.</p>
<p>Bên cạnh đào tạo, trường còn là trung tâm nghiên cứu khoa học trong lĩnh vực y học, tham gia nhiều đề tài về chăm sóc sức khỏe cộng đồng, phòng chống dịch bệnh và nâng cao chất lượng điều trị. Đội ngũ giảng viên gồm các bác sĩ, dược sĩ và chuyên gia có trình độ cao, giàu kinh nghiệm thực tiễn.</p>
<p>Môi trường học tập tại trường nghiêm túc, kỷ luật và đòi hỏi sự chăm chỉ, trách nhiệm cao từ sinh viên. Với quy mô đào tạo hàng nghìn sinh viên mỗi năm, Trường Đại học Y Dược Cần Thơ đang ngày càng khẳng định vị thế là một trong những trung tâm đào tạo y dược quan trọng, góp phần cung cấp nguồn nhân lực chất lượng cho ngành y tế khu vực phía Nam và cả nước.</p>', N'Hơn 2.460 sinh viên', 1, N'dai-hoc-y-duoc-can-tho', 1, CAST(N'2026-04-29T14:49:31.917' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (44, N'Đại học Thủ Dầu Một', N'06 Trần Văn Ơn, Phú Lợi, Hồ Chí Minh', N'TP Hồ Chí Minh', 3, 1, N'0743822518', N'http://tdmu.edu.vn/', N'/Resources/Images/truong/dai-hoc-thu-dau-mot_logo_a8d7d182.png', N'/Resources/Images/truong/dai-hoc-thu-dau-mot_cover_7ff73999.jpg', N'<p>Trường Đại học Thủ Dầu Một là một trường đại học công lập trực thuộc Ủy ban Nhân dân tỉnh Bình Dương, có định hướng đào tạo đa ngành gắn liền với nhu cầu phát triển kinh tế – xã hội của khu vực Đông Nam Bộ. Trường được đánh giá là một trong những cơ sở giáo dục trẻ nhưng phát triển nhanh, với môi trường học tập hiện đại và năng động.</p>
<p>Nhà trường đào tạo nhiều lĩnh vực như Công nghệ thông tin, Kỹ thuật, Kinh tế, Quản trị kinh doanh, Ngoại ngữ, Du lịch, Sư phạm và Khoa học xã hội. Chương trình đào tạo được thiết kế theo hướng ứng dụng, chú trọng thực hành và kỹ năng nghề nghiệp, giúp sinh viên có khả năng làm việc ngay sau khi tốt nghiệp. Đặc biệt, nhờ nằm trong khu vực phát triển công nghiệp mạnh, sinh viên có nhiều cơ hội thực tập và việc làm tại các khu công nghiệp và doanh nghiệp lớn ở Bình Dương và TP. Hồ Chí Minh.</p>
<p>Bên cạnh đào tạo, trường còn chú trọng nghiên cứu khoa học, hợp tác quốc tế và liên kết với doanh nghiệp nhằm nâng cao chất lượng giảng dạy. Môi trường học tập tại đây thân thiện, năng động, với nhiều hoạt động ngoại khóa và câu lạc bộ giúp sinh viên phát triển toàn diện.</p>
<p>Với quy mô đào tạo hàng chục nghìn sinh viên, Trường Đại học Thủ Dầu Một đang từng bước khẳng định vị thế là một cơ sở đào tạo uy tín trong khu vực phía Nam, góp phần cung cấp nguồn nhân lực chất lượng cho quá trình công nghiệp hóa và phát triển kinh tế của tỉnh Bình Dương và cả nước.</p>', N'Hơn 4.300 sinh viên', 1, N'dai-hoc-thu-dau-mot', 1, CAST(N'2026-04-29T14:52:38.093' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (45, N'Đại Học Thăng Long', N'Đường Nghiêm Xuân Yêm, Định Công, Hà Nội, Việt Nam', N'TP Hà Nội', 1, 2, N'0364005207', N'http://thanglong.edu.vn/', N'/Resources/Images/truong/dai-hoc-thang-long_logo_14a6685e.jpg', N'/Resources/Images/truong/dai-hoc-thang-long_cover_104ffab6.jpg', N'<p>Trường Đại học Thăng Long là một trong những trường đại học tư thục đầu tiên tại Việt Nam, có trụ sở tại Hà Nội và được đánh giá cao về môi trường học tập hiện đại, thân thiện. Trường phát triển theo định hướng đào tạo đa ngành, gắn liền với nhu cầu thực tiễn của xã hội và thị trường lao động.</p>
<p>Nhà trường đào tạo nhiều lĩnh vực như Công nghệ thông tin, Kinh tế, Quản trị kinh doanh, Tài chính – Ngân hàng, Ngôn ngữ, Truyền thông và Y tế. Chương trình đào tạo được thiết kế theo hướng ứng dụng, chú trọng kỹ năng thực hành, kỹ năng mềm và khả năng làm việc thực tế, giúp sinh viên dễ dàng thích nghi với môi trường doanh nghiệp sau khi tốt nghiệp.</p>
<p>Bên cạnh đó, trường còn chú trọng đầu tư cơ sở vật chất hiện đại, không gian học tập xanh – sạch – đẹp, tạo điều kiện thuận lợi cho sinh viên học tập và sinh hoạt. Môi trường học tập tại Đại học Thăng Long năng động, cởi mở, khuyến khích sự sáng tạo và phát triển cá nhân.</p>
<p>Với quy mô đào tạo hàng nghìn sinh viên mỗi năm, Trường Đại học Thăng Long được xem là một trong những trường đại học tư thục uy tín tại Hà Nội, phù hợp với những sinh viên mong muốn học tập trong môi trường hiện đại, thực tế và định hướng nghề nghiệp rõ ràng.</p>', N'Hơn 2.820 sinh viên', 1, N'dai-hoc-thang-long', 1, CAST(N'2026-04-29T14:57:24.120' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (46, N'Đại Học Thủy Lợi', N'Số 175 Tây Sơn, Phường Kim Liên, Hà Nội, Việt Nam', N'TP Hà Nội', 1, 1, N'0838522201', N'http://tlu.edu.vn/', N'/Resources/Images/truong/dai-hoc-thuy-loi_logo_57b5ca2f.jpg', N'/Resources/Images/truong/dai-hoc-thuy-loi_cover_b5156665.jpg', N'<p>Trường Đại học Thủy lợi là một trường đại học công lập trực thuộc Bộ Nông nghiệp và Môi trường (trước đây là Bộ Nông nghiệp và Phát triển nông thôn), có thế mạnh hàng đầu trong đào tạo các ngành liên quan đến thủy lợi, tài nguyên nước và kỹ thuật xây dựng. Trường có trụ sở chính tại Hà Nội và cơ sở tại TP. Hồ Chí Minh, đóng vai trò quan trọng trong việc đào tạo nguồn nhân lực phục vụ phát triển hạ tầng và quản lý tài nguyên nước của Việt Nam.</p>
<p>Nhà trường đào tạo đa ngành, trong đó nổi bật là các lĩnh vực như Kỹ thuật tài nguyên nước, Kỹ thuật xây dựng công trình thủy, Thủy điện, Môi trường, Công nghệ thông tin, Kinh tế xây dựng và Quản lý dự án. Chương trình đào tạo được xây dựng theo hướng ứng dụng, kết hợp giữa lý thuyết và thực hành, giúp sinh viên có khả năng tham gia vào các công trình thực tế như đập, hồ chứa, hệ thống thủy lợi và công trình phòng chống thiên tai.</p>
<p>Bên cạnh đào tạo, trường còn là trung tâm nghiên cứu khoa học uy tín trong lĩnh vực tài nguyên nước, biến đổi khí hậu và phòng chống thiên tai, tham gia nhiều dự án lớn cấp quốc gia. Đội ngũ giảng viên có trình độ cao, nhiều người là chuyên gia đầu ngành trong lĩnh vực thủy lợi và xây dựng.</p>
<p>Môi trường học tập tại trường mang tính kỹ thuật cao, yêu cầu sinh viên có tư duy logic, khả năng tính toán và sự kiên trì. Tuy nhiên, đây cũng là môi trường năng động với nhiều hoạt động học thuật và cơ hội thực tập tại các công trình lớn. Với quy mô đào tạo hàng chục nghìn sinh viên, Trường Đại học Thủy lợi được đánh giá là một trong những cơ sở đào tạo kỹ thuật uy tín, góp phần quan trọng vào phát triển hạ tầng và quản lý tài nguyên nước của Việt Nam.</p>', N'Hơn 5.320 sinh viên', 1, N'dai-hoc-thuy-loi', 1, CAST(N'2026-04-29T15:04:33.317' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (47, N'Học Viện Nông Nghiệp Việt Nam', N'Đường Ngô Xuân Quảng, xã Gia Lâm, Hà Nội,  Việt Nam', N'TP Hà Nội', 1, 1, N'0912079928', N'http://www.vnua.edu.vn/', N'/Resources/Images/truong/hoc-vien-nong-nghiep-viet-nam_logo_2f71b428.png', N'/Resources/Images/truong/hoc-vien-nong-nghiep-viet-nam_cover_28b75711.jpg', N'<p>Học viện Nông nghiệp Việt Nam là một cơ sở đào tạo và nghiên cứu hàng đầu trong lĩnh vực nông nghiệp, trực thuộc Bộ Nông nghiệp và Môi trường, có trụ sở tại Hà Nội. Trường giữ vai trò quan trọng trong việc đào tạo nguồn nhân lực chất lượng cao phục vụ phát triển nông nghiệp, nông thôn và kinh tế sinh học của Việt Nam.</p>
<p>Học viện đào tạo đa ngành, không chỉ trong các lĩnh vực truyền thống như Trồng trọt, Chăn nuôi, Thú y, Thủy sản mà còn mở rộng sang Công nghệ sinh học, Công nghệ thực phẩm, Kinh tế nông nghiệp, Quản lý đất đai, Môi trường và Công nghệ thông tin. Chương trình đào tạo được xây dựng theo hướng ứng dụng, gắn liền với thực tiễn sản xuất và nhu cầu thị trường, giúp sinh viên có khả năng làm việc trong nhiều lĩnh vực khác nhau.</p>
<p>Bên cạnh đào tạo, học viện còn là trung tâm nghiên cứu khoa học lớn, tham gia nhiều đề tài về giống cây trồng, vật nuôi, công nghệ sinh học và phát triển nông nghiệp bền vững. Trường có hệ thống phòng thí nghiệm, trang trại thực nghiệm và cơ sở nghiên cứu hiện đại, tạo điều kiện cho sinh viên học tập và nghiên cứu.</p>
<p>Môi trường học tập tại học viện năng động, thực tế, phù hợp với những sinh viên yêu thích lĩnh vực nông nghiệp, công nghệ sinh học và phát triển bền vững. Với quy mô đào tạo lớn, hàng chục nghìn sinh viên theo học, Học viện Nông nghiệp Việt Nam là một trong những trung tâm đào tạo và nghiên cứu nông nghiệp uy tín, góp phần quan trọng vào sự phát triển của ngành nông nghiệp Việt Nam.</p>', N'Hơn 5.991 sinh viên', 1, N'hoc-vien-nong-nghiep-viet-nam', 1, CAST(N'2026-04-29T15:07:51.767' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (48, N'Đại Học Luật Hà Nội', N'87 Đường Nguyễn Chí Thanh, phường Giảng Võ, thành phố Hà Nội, Việt Nam', N'TP Hà Nội', 1, 1, N'0838352630', N'http://www.hlu.edu.vn/', N'/Resources/Images/truong/dai-hoc-luat-ha-noi_logo_46a1eb91.jpg', N'/Resources/Images/truong/dai-hoc-luat-ha-noi_cover_55359bac.jpg', N'<p>Trường Đại học Luật Hà Nội là một trường đại học công lập trực thuộc Bộ Tư pháp, được xem là một trong những cơ sở đào tạo luật hàng đầu tại Việt Nam. Trường có trụ sở tại Hà Nội, với bề dày lịch sử và uy tín cao trong đào tạo nguồn nhân lực pháp lý cho các cơ quan nhà nước, tổ chức và doanh nghiệp.</p>
<p>Nhà trường đào tạo đa dạng các chuyên ngành như Luật kinh tế, Luật dân sự, Luật hình sự, Luật hành chính và Luật quốc tế. Chương trình đào tạo mang tính học thuật cao, chú trọng xây dựng nền tảng kiến thức pháp lý vững chắc, đồng thời phát triển kỹ năng phân tích, tranh luận và áp dụng pháp luật vào thực tiễn. Sinh viên còn có cơ hội tham gia các phiên tòa giả định, hoạt động pháp lý thực tế và thực tập tại các cơ quan tư pháp.</p>
<p>Bên cạnh đào tạo, trường còn là trung tâm nghiên cứu khoa học pháp lý uy tín, tham gia xây dựng và hoàn thiện hệ thống pháp luật Việt Nam. Đội ngũ giảng viên gồm nhiều chuyên gia, tiến sĩ luật có kinh nghiệm trong giảng dạy và thực tiễn pháp lý.</p>
<p>Môi trường học tập tại trường nghiêm túc, mang tính học thuật cao, phù hợp với những sinh viên yêu thích lĩnh vực luật và có định hướng làm việc trong ngành pháp lý. Với quy mô đào tạo lớn, hàng nghìn sinh viên theo học mỗi năm, Trường Đại học Luật Hà Nội đóng vai trò quan trọng trong việc cung cấp nguồn nhân lực chất lượng cao cho hệ thống pháp luật và tư pháp của Việt Nam.</p>', N'Hơn 2.620 sinh viên', 1, N'dai-hoc-luat-ha-noi', 1, CAST(N'2026-04-29T15:11:55.387' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (49, N'Học viện Báo chí và Tuyên truyền', N'36 Đ. Xuân Thủy, Dịch Vọng Hậu, Cầu Giấy, Hà Nội', N'TP Hà Nội', 1, 1, N'0837546963', N'https://ajc.hcma.vn/', N'/Resources/Images/truong/hoc-vien-bao-chi-va-tuyen-truyen_logo_552f5d82.jpg', N'/Resources/Images/truong/hoc-vien-bao-chi-va-tuyen-truyen_cover_5f5c08bf.jpg', N'<p>Học viện Báo chí và Tuyên truyền là một cơ sở đào tạo trực thuộc Học viện Chính trị Quốc gia Hồ Chí Minh, có vai trò quan trọng trong việc đào tạo nguồn nhân lực trong lĩnh vực báo chí, truyền thông, chính trị và tư tưởng. Trường có trụ sở tại Hà Nội và được xem là một trong những học viện hàng đầu về đào tạo báo chí – truyền thông tại Việt Nam.</p>
<p>Học viện đào tạo nhiều ngành như Báo chí, Truyền thông đa phương tiện, Quan hệ công chúng (PR), Quảng cáo, Xây dựng Đảng và Chính trị học. Chương trình đào tạo mang tính học thuật kết hợp thực tiễn, giúp sinh viên vừa nắm vững lý luận chính trị vừa có kỹ năng nghề nghiệp như viết báo, sản xuất nội dung, truyền thông và tổ chức sự kiện.</p>
<p>Bên cạnh giảng dạy, học viện còn là trung tâm nghiên cứu khoa học về truyền thông, báo chí và lý luận chính trị, tham gia nhiều đề tài cấp quốc gia. Đội ngũ giảng viên có trình độ cao, nhiều người là nhà báo, chuyên gia truyền thông và giảng viên giàu kinh nghiệm.</p>
<p>Môi trường học tập tại đây năng động, sáng tạo, phù hợp với những sinh viên yêu thích lĩnh vực truyền thông và báo chí. Sinh viên có nhiều cơ hội tham gia thực tập tại các cơ quan báo chí, đài truyền hình và doanh nghiệp truyền thông. Với quy mô đào tạo hàng nghìn sinh viên mỗi năm, Học viện Báo chí và Tuyên truyền là một trong những cái nôi đào tạo nhân lực chất lượng cho ngành truyền thông và báo chí tại Việt Nam.</p>', N'Hơn 1.950 sinh viên', 1, N'hoc-vien-bao-chi-va-tuyen-truyen', 1, CAST(N'2026-04-29T15:14:43.893' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (50, N'Đại Học Sư Phạm Thái Nguyên', N'Số 20, Đường Lương Ngọc Quyến, TP. Thái Nguyên, Thái Nguyên', N'Tỉnh Thái Nguyên', 1, 1, N'0823902903', N'http://tnue.edu.vn/', N'/Resources/Images/truong/dai-hoc-su-pham-thai-nguyen_logo_55dc39ca.png', N'/Resources/Images/truong/dai-hoc-su-pham-thai-nguyen_cover_84c59eb0.jpg', N'<p>Trường Đại học Sư phạm – Đại học Thái Nguyên là một trường thành viên của Đại học Thái Nguyên, có vai trò quan trọng trong đào tạo giáo viên và cán bộ giáo dục cho khu vực trung du, miền núi phía Bắc và cả nước. Trường có trụ sở tại thành phố Thái Nguyên, với bề dày truyền thống trong lĩnh vực đào tạo sư phạm.</p>
<p>Nhà trường đào tạo nhiều ngành sư phạm như Toán, Ngữ văn, Tiếng Anh, Vật lý, Hóa học, Sinh học, Lịch sử, Địa lý… cùng một số ngành ngoài sư phạm nhằm đáp ứng nhu cầu xã hội. Chương trình đào tạo được xây dựng theo hướng kết hợp giữa lý thuyết chuyên môn và kỹ năng giảng dạy, giúp sinh viên có nền tảng vững chắc và khả năng đứng lớp tốt sau khi tốt nghiệp.</p>
<p>Bên cạnh đào tạo, trường còn chú trọng nghiên cứu khoa học giáo dục và đổi mới phương pháp giảng dạy. Đội ngũ giảng viên có trình độ cao, nhiều người là tiến sĩ, chuyên gia trong lĩnh vực giáo dục. Sinh viên có cơ hội thực tập tại các trường học, tham gia hoạt động giảng dạy thực tế để tích lũy kinh nghiệm.</p>
<p>Môi trường học tập tại trường nghiêm túc, mang tính sư phạm rõ rệt, phù hợp với những sinh viên yêu thích nghề giáo. Với quy mô đào tạo hàng nghìn sinh viên mỗi năm, Trường Đại học Sư phạm – Đại học Thái Nguyên là một trong những cơ sở đào tạo giáo viên uy tín, góp phần cung cấp nguồn nhân lực chất lượng cho ngành giáo dục Việt Nam.</p>', N'Hơn 1.260 sinh viên', 1, N'dai-hoc-su-pham-thai-nguyen', 1, CAST(N'2026-04-29T15:17:26.750' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (51, N'Đại Học Sư Phạm Huế', N'Số 34 đường Lê Lợi, phường Phú Hội, quận Thuận Hóa, thành phố Huế, Việt Nam', N'TP Huế', 2, 1, N'0843822132', N'https://vi.wikipedia.org/wiki', N'/Resources/Images/truong/dai-hoc-su-pham-hue_logo_79379066.png', N'/Resources/Images/truong/dai-hoc-su-pham-hue_cover_8f2806d0.jpg', N'<p>Trường Đại học Sư phạm – Đại học Huế là một trường thành viên của Đại học Huế, có vai trò quan trọng trong đào tạo giáo viên và cán bộ giáo dục cho khu vực miền Trung – Tây Nguyên và cả nước. Trường có trụ sở tại thành phố Huế, với bề dày truyền thống và uy tín lâu năm trong lĩnh vực đào tạo sư phạm.</p>
<p>Nhà trường đào tạo đa dạng các ngành sư phạm như Toán, Ngữ văn, Tiếng Anh, Vật lý, Hóa học, Sinh học, Lịch sử, Địa lý… cùng một số ngành ngoài sư phạm nhằm đáp ứng nhu cầu xã hội. Chương trình đào tạo được xây dựng theo hướng kết hợp giữa kiến thức chuyên môn và kỹ năng giảng dạy, giúp sinh viên có nền tảng vững chắc và khả năng đứng lớp tốt sau khi tốt nghiệp.</p>
<p>Bên cạnh đào tạo, trường còn chú trọng nghiên cứu khoa học giáo dục và đổi mới phương pháp giảng dạy. Đội ngũ giảng viên có trình độ cao, nhiều người là tiến sĩ, chuyên gia trong lĩnh vực giáo dục. Sinh viên có cơ hội thực tập tại các trường học, tham gia giảng dạy thực tế để tích lũy kinh nghiệm.</p>
<p>Môi trường học tập tại trường mang tính sư phạm rõ rệt, nghiêm túc nhưng cũng thân thiện, phù hợp với những sinh viên yêu thích nghề giáo. Với quy mô đào tạo hàng nghìn sinh viên mỗi năm, Trường Đại học Sư phạm – Đại học Huế là một trong những cơ sở đào tạo giáo viên uy tín, góp phần cung cấp nguồn nhân lực chất lượng cho ngành giáo dục Việt Nam.</p>', N'Hơn 3.870 sinh viên', 1, N'dai-hoc-su-pham-hue', 1, CAST(N'2026-04-29T15:21:43.540' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (52, N'Cao đẳng Bách khoa Nam Sài Gòn', N'47 Cao Lỗ, Chánh Hưng, Hồ Chí Minh 790000', N'TP Hồ Chí Minh', 1, 1, N'0981146179', N'https://namsaigon.edu.vn/', N'/Resources/Images/truong/cao-dang-bach-khoa-nam-sai-gon_logo_184892b5.png', N'/Resources/Images/truong/cao-dang-bach-khoa-nam-sai-gon_cover_4ddfb1d4.jpg', N'<p>Trường Cao đẳng Bách khoa Nam Sài Gòn là một cơ sở giáo dục nghề nghiệp tại TP. Hồ Chí Minh, chuyên đào tạo theo định hướng thực hành, gắn liền với nhu cầu của doanh nghiệp và thị trường lao động. Trường tập trung vào mô hình đào tạo ứng dụng, giúp sinh viên có thể làm việc ngay sau khi tốt nghiệp.</p>
<p>Nhà trường đào tạo nhiều ngành nghề như Công nghệ thông tin, Kế toán, Quản trị kinh doanh, Du lịch – Nhà hàng – Khách sạn, Điện – điện tử và một số ngành kỹ thuật khác. Chương trình học được thiết kế chú trọng thực hành, với thời lượng thực tập cao, giúp sinh viên rèn luyện kỹ năng nghề nghiệp ngay trong quá trình học.</p>
<p>Bên cạnh đào tạo, trường còn liên kết với nhiều doanh nghiệp để hỗ trợ sinh viên thực tập và giới thiệu việc làm sau khi ra trường. Đội ngũ giảng viên có kinh nghiệm thực tế, giúp sinh viên tiếp cận với môi trường làm việc thực tiễn.</p>
<p>Môi trường học tập tại trường năng động, thực tế, phù hợp với những sinh viên muốn học nghề nhanh, tiết kiệm thời gian và sớm tham gia thị trường lao động. Với quy mô đào tạo hàng nghìn sinh viên, Trường Cao đẳng Bách khoa Nam Sài Gòn là một lựa chọn phù hợp cho hướng đi học nghề và thực hành tại khu vực TP. Hồ Chí Minh.</p>', N'Hơn 2.420 sinh viên', 1, N'cao-dang-bach-khoa-nam-sai-gon', 1, CAST(N'2026-05-03T00:31:46.043' AS DateTime), 1, 1)
INSERT [dbo].[tbl_Truong] ([MaTruong], [TenTruong], [DiaChi], [TinhThanh], [MaVung], [LoaiTruong], [SoDienThoai], [Website], [AnhDaiDien], [AnhBia], [MoTa], [QuyMo], [KiemDinhChatLuong], [Slug], [MaTaiKhoan], [ThoiGianCapNhat], [TrangThai], [CapBacDaoTao]) VALUES (53, N'Cao đẳng nghề Phú Thọ', N'9942+FVP, Hùng Vương, Vân Phú, Phú Thọ', N'Tỉnh Phú Thọ', 1, 1, N'0806262555', N'https://www.facebook.com/', N'/Resources/Images/truong/cao-dang-nghe-phu-tho_logo_a47c894b.jpg', N'/Resources/Images/truong/cao-dang-nghe-phu-tho_cover_709ee5b8.jpg', N'<p>Trường Cao đẳng nghề Phú Thọ là một cơ sở giáo dục nghề nghiệp công lập tại tỉnh Phú Thọ, chuyên đào tạo nguồn nhân lực kỹ thuật có tay nghề cho khu vực trung du miền núi phía Bắc và cả nước. Trường định hướng đào tạo theo mô hình thực hành, gắn chặt với nhu cầu của doanh nghiệp và thị trường lao động.</p>
<p>Nhà trường đào tạo nhiều ngành nghề như Điện – điện tử, Cơ khí, Công nghệ ô tô, Công nghệ thông tin, Kế toán và một số ngành dịch vụ kỹ thuật khác. Chương trình học chú trọng thực hành, giúp sinh viên nắm vững kỹ năng nghề, có thể làm việc ngay sau khi tốt nghiệp mà không cần đào tạo lại nhiều.</p>
<p>Bên cạnh đào tạo, trường còn hợp tác với các doanh nghiệp, khu công nghiệp để tổ chức thực tập và giới thiệu việc làm cho sinh viên. Đội ngũ giảng viên có kinh nghiệm thực tế, cơ sở vật chất được đầu tư phục vụ tốt cho việc học nghề.</p>
<p>Môi trường học tập tại trường mang tính thực tiễn cao, phù hợp với những người muốn học nghề nhanh, tiết kiệm chi phí và sớm tham gia thị trường lao động. Với quy mô đào tạo hàng nghìn học viên mỗi năm, Trường Cao đẳng nghề Phú Thọ đóng vai trò quan trọng trong việc cung cấp nguồn nhân lực kỹ thuật cho khu vực và xã hội.</p>', N'Hơn 2.000 sinh viên', 1, N'cao-dang-nghe-phu-tho', 1, CAST(N'2026-04-29T15:32:28.370' AS DateTime), 1, 2)
SET IDENTITY_INSERT [dbo].[tbl_Truong] OFF
