-- ─── sp_GopY_TuVan_Them ───────────────────────────────────
-- Dùng cho: form liên hệ trường + form góp ý
-- ───────────────────────────────────────────────────────────
CREATE PROCEDURE [dbo].[sp_GopY_TuVan_Them]
    @Loai           NVARCHAR(10),      -- 'TUVAN' hoặc 'GOPY'
    @MaTaiKhoan     INT            = NULL,
    @MaTruong       INT            = NULL,
    @HoTen          NVARCHAR(100)  = NULL,
    @Email          NVARCHAR(100)  = NULL,
    @SoDienThoai    NVARCHAR(20)   = NULL,
    @NoiDung        NVARCHAR(MAX)  = NULL,
    @LoaiGopY       TINYINT        = NULL,
    @IDMoi          INT            OUTPUT
AS
BEGIN
    SET NOCOUNT ON
    IF @Loai = 'TUVAN'
    BEGIN
        INSERT INTO tbl_TuVan (MaTaiKhoan, MaTruong, HoTen, Email, SoDienThoai, NoiDung)
        VALUES (@MaTaiKhoan, @MaTruong, @HoTen, @Email, @SoDienThoai, @NoiDung)
        SET @IDMoi = SCOPE_IDENTITY()
    END
    ELSE IF @Loai = 'GOPY'
    BEGIN
        INSERT INTO tbl_GopY (MaTaiKhoan, MaTruong, LoaiGopY, NoiDung)
        VALUES (@MaTaiKhoan, @MaTruong, @LoaiGopY, @NoiDung)
        SET @IDMoi = SCOPE_IDENTITY()
    END
END
GO
