    IF @Loai = 'TUVAN'
        UPDATE tbl_TuVan
        SET    TrangThai = @TrangThai, GhiChuAdmin = @GhiChu,
               NgayPhanHoi = CASE WHEN @TrangThai = 1 THEN GETDATE() ELSE NgayPhanHoi END
