-- ─── sp_GopYTuVan_DanhSach (Admin) ────────────────────────
-- Dùng cho: GridView quản lý góp ý / tư vấn trong Admin panel
-- ───────────────────────────────────────────────────────────
CREATE PROCEDURE [dbo].[sp_GopYTuVan_DanhSach]
    @Loai       NVARCHAR(10),          -- 'TUVAN' hoặc 'GOPY'
    @TrangThai  TINYINT       = NULL,
    @MaTruong   INT           = NULL,
    @PageIndex  INT           = 0,
    @PageSize   INT           = 20,
    @TongSo     INT           OUTPUT
AS
BEGIN
    SET NOCOUNT ON
    IF @Loai = 'TUVAN'
    BEGIN
        SELECT @TongSo = COUNT(*) FROM tbl_TuVan
        WHERE  (@TrangThai IS NULL OR TrangThai = @TrangThai)
          AND  (@MaTruong  IS NULL OR MaTruong  = @MaTruong)
 
        SELECT tv.*, tr.TenTruong
        FROM   tbl_TuVan tv
        JOIN   tbl_Truong tr ON tr.MaTruong = tv.MaTruong
        WHERE  (@TrangThai IS NULL OR tv.TrangThai = @TrangThai)
          AND  (@MaTruong  IS NULL OR tv.MaTruong  = @MaTruong)
        ORDER  BY tv.NgayGui DESC
        OFFSET (@PageIndex * @PageSize) ROWS
        FETCH  NEXT @PageSize ROWS ONLY
    END
    ELSE IF @Loai = 'GOPY'
    BEGIN
        SELECT @TongSo = COUNT(*) FROM tbl_GopY
        WHERE  (@TrangThai IS NULL OR TrangThai = @TrangThai)
          AND  (@MaTruong  IS NULL OR MaTruong  = @MaTruong)
 
        SELECT gy.*, tr.TenTruong
        FROM   tbl_GopY gy
        LEFT JOIN tbl_Truong tr ON tr.MaTruong = gy.MaTruong
        WHERE  (@TrangThai IS NULL OR gy.TrangThai = @TrangThai)
          AND  (@MaTruong  IS NULL OR gy.MaTruong  = @MaTruong)
        ORDER  BY gy.NgayGui DESC
        OFFSET (@PageIndex * @PageSize) ROWS
        FETCH  NEXT @PageSize ROWS ONLY
    END
END
GO
/****** Object:  StoredProcedure [dbo].[sp_HopThu_DanhDauDaDoc]    Script Date: 5/3/2026 2:07:24 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROC [dbo].[sp_HopThu_DanhDauDaDoc]
    @MaTuVan    INT,
    @MaTaiKhoan INT
AS
BEGIN
    SET NOCOUNT ON;
    -- Kiểm tra ownership trước
    IF NOT EXISTS(SELECT 1 FROM tbl_TuVan WHERE ID = @MaTuVan AND MaTaiKhoan = @MaTaiKhoan)
        RETURN;

    UPDATE tbl_TuVanPhanHoi
    SET DaDocBoiUser = 1
    WHERE MaTuVan = @MaTuVan
      AND LoaiNguoi != 'HocSinh';  -- chỉ đánh dấu reply từ phía khác
END
GO
/****** Object:  StoredProcedure [dbo].[sp_HopThu_DanhSachByUser]    Script Date: 5/3/2026 2:07:24 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROC [dbo].[sp_HopThu_DanhSachByUser]
    @MaTaiKhoan INT
AS
BEGIN
    SET NOCOUNT ON;
    SELECT
        tv.ID,
        tv.MaTruong,
        tr.TenTruong,
        tv.NoiDung                              AS CauHoiGoc,
        tv.NgayGui,
        tv.TrangThai,
        tv.DaXoa,
        ISNULL(stats.SoLuot,  0)               AS SoLuotPhanHoi,
        stats.PhanHoiCuoi,
        ISNULL(stats.ChuaDoc, 0)               AS SoChuaDoc
    FROM tbl_TuVan tv
    LEFT JOIN tbl_Truong tr ON tr.MaTruong = tv.MaTruong
    OUTER APPLY (
        SELECT
            COUNT(*)                                                                         AS SoLuot,
            MAX(NgayPhanHoi)                                                                 AS PhanHoiCuoi,
            SUM(CASE WHEN DaDocBoiUser = 0 AND LoaiNguoi != 'HocSinh' THEN 1 ELSE 0 END)   AS ChuaDoc
        FROM tbl_TuVanPhanHoi
        WHERE MaTuVan = tv.ID
    ) stats
    WHERE tv.MaTaiKhoan = @MaTaiKhoan
    ORDER BY ISNULL(stats.PhanHoiCuoi, tv.NgayGui) DESC;
END
GO
/****** Object:  StoredProcedure [dbo].[sp_HopThu_DemChuaDoc]    Script Date: 5/3/2026 2:07:24 PM ******/
