CREATE PROC [dbo].[sp_HopThu_DemChuaDoc]
    @MaTaiKhoan INT
AS
BEGIN
    SET NOCOUNT ON;
    SELECT COUNT(*)
    FROM tbl_TuVanPhanHoi ph
    INNER JOIN tbl_TuVan tv ON tv.ID = ph.MaTuVan
    WHERE tv.MaTaiKhoan = @MaTaiKhoan
      AND ph.DaDocBoiUser = 0
      AND ph.LoaiNguoi != 'HocSinh'   -- chỉ đếm reply từ phía khác (Admin/System/...)
      AND tv.DaXoa = 0;
END
GO
