SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[sp_SoSanhNganh_LayTinTheoTruong]
    @MaTruong INT,
    @NamTuyenSinh SMALLINT = NULL
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        t.MaTin,
        t.MaTruong,
        cn.MaChuyenNganh,
        cn.TenChuyenNganh,
        t.NamTuyenSinh,
        t.DiemChuanNamTruoc,
        t.DiemChuanNamNay,
        t.HocPhi,
        t.ChiTieu,
        t.ToHopMonHoc,
        pt.TenPhuongThuc
    FROM dbo.tbl_TinTuyenSinh t
    INNER JOIN dbo.tbl_Truong tr
        ON tr.MaTruong = t.MaTruong
       AND tr.TrangThai = 1
    INNER JOIN dbo.tbl_ChuyenNganh cn
        ON cn.MaChuyenNganh = t.MaChuyenNganh
    INNER JOIN dbo.tbl_PhuongThucXetTuyen pt
        ON pt.MaPhuongThuc = t.MaPhuongThuc
    WHERE t.TrangThai = 1
      AND t.MaTruong = @MaTruong
      AND (@NamTuyenSinh IS NULL OR t.NamTuyenSinh = @NamTuyenSinh)
    ORDER BY
        t.NamTuyenSinh DESC,
        cn.TenChuyenNganh ASC,
        t.MaTin DESC;
END
GO
/****** Object:  StoredProcedure [dbo].[sp_TaiKhoan_DangNhap]    Script Date: 5/3/2026 2:07:24 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[sp_TaiKhoan_DangNhap]
    @Email     NVARCHAR(255),
    @MatKhau   NVARCHAR(MAX),
    @KetQua    TINYINT OUTPUT,    -- 0=OK, 1=SaiMK, 2=BiKhoa, 3=ChuaXN, 4=KhongTonTai
    @MaTaiKhoan INT OUTPUT,
    @MaQuyen   INT OUTPUT,
    @MaTruong  INT OUTPUT         -- NULL nếu không phải TruongHoc
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @MaxSaiLan   INT = 5;
    DECLARE @KhoaPhutCount INT = 30;

    -- Mặc định
    SET @KetQua     = 4;  -- KhongTonTai
    SET @MaTaiKhoan = 0;
    SET @MaQuyen    = 0;
    SET @MaTruong   = NULL;

    -- Lấy thông tin tài khoản
    SELECT
        @MaTaiKhoan        = MaTaiKhoan,
        @MaQuyen           = MaQuyen,
        @MaTruong          = MaTruong
    FROM tbl_TaiKhoan
    WHERE Email = @Email;

    IF @MaTaiKhoan = 0 OR @MaTaiKhoan IS NULL
    BEGIN
        SET @KetQua = 4;  -- KhongTonTai
        RETURN;
    END

    -- Kiểm tra khóa tài khoản
    IF EXISTS (
        SELECT 1 FROM tbl_TaiKhoan
        WHERE MaTaiKhoan = @MaTaiKhoan
          AND KhoaTaiKhoanDen IS NOT NULL
          AND KhoaTaiKhoanDen > GETDATE()
    )
    BEGIN
        SET @KetQua = 2;  -- BiKhoa
        RETURN;
    END

    -- Kiểm tra email xác nhận
    IF NOT EXISTS (
        SELECT 1 FROM tbl_TaiKhoan
        WHERE MaTaiKhoan = @MaTaiKhoan AND EmailDaXacNhan = 1
    )
    BEGIN
        SET @KetQua = 3;  -- ChuaXacNhanEmail
        RETURN;
    END

    -- Kiểm tra trạng thái active
    IF NOT EXISTS (
        SELECT 1 FROM tbl_TaiKhoan
        WHERE MaTaiKhoan = @MaTaiKhoan AND TrangThai = 1
    )
    BEGIN
        SET @KetQua = 2;  -- BiKhoa (vô hiệu hóa)
        RETURN;
    END

    -- Verify mật khẩu — logic verify thực sự làm ở BLL (PBKDF2),
    -- SP chỉ nhận kết quả verify từ BLL truyền vào:
    -- Nếu BLL truyền đúng hash DB → MatKhau match → thành công
    -- Nếu BLL truyền hash giả → không match → tăng counter brute-force
    IF EXISTS (
        SELECT 1 FROM tbl_TaiKhoan
        WHERE MaTaiKhoan = @MaTaiKhoan AND MatKhau = @MatKhau
    )
    BEGIN
        -- Đăng nhập thành công — reset brute-force counter
        UPDATE tbl_TaiKhoan
        SET SoLanDangNhapSai = 0,
            KhoaTaiKhoanDen  = NULL,
            LanDangNhapCuoi  = GETDATE()
        WHERE MaTaiKhoan = @MaTaiKhoan;

        SET @KetQua = 0;  -- ThanhCong
    END
    ELSE
    BEGIN
        -- Sai mật khẩu — tăng counter, khóa nếu quá giới hạn
        DECLARE @SoLanSai INT;

        UPDATE tbl_TaiKhoan
        SET SoLanDangNhapSai = SoLanDangNhapSai + 1,
            KhoaTaiKhoanDen  = CASE
                WHEN SoLanDangNhapSai + 1 >= @MaxSaiLan
                THEN DATEADD(MINUTE, @KhoaPhutCount, GETDATE())
                ELSE NULL
            END
        WHERE MaTaiKhoan = @MaTaiKhoan;

        SELECT @SoLanSai = SoLanDangNhapSai FROM tbl_TaiKhoan WHERE MaTaiKhoan = @MaTaiKhoan;

        SET @KetQua = CASE WHEN @SoLanSai >= @MaxSaiLan THEN 2 ELSE 1 END;
        -- Reset output về 0 (không trả MaTaiKhoan khi sai MK)
        SET @MaTaiKhoan = 0;
        SET @MaQuyen    = 0;
        SET @MaTruong   = NULL;
    END
END
GO
/****** Object:  StoredProcedure [dbo].[sp_TaiKhoan_DatLaiMatKhau]    Script Date: 5/3/2026 2:07:24 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
 
-- ─── sp_TaiKhoan_DatLaiMatKhau ────────────────────────────
-- Dùng cho: ForgotPassword.aspx flow
--   Bước 1: tạo token  → @HanhDong = 'TAO_TOKEN'
--   Bước 2: đặt lại pw → @HanhDong = 'DAT_LAI'
-- ───────────────────────────────────────────────────────────
CREATE PROCEDURE [dbo].[sp_TaiKhoan_DatLaiMatKhau]
    @HanhDong   NVARCHAR(20),          -- 'TAO_TOKEN' hoặc 'DAT_LAI'
    @Email      NVARCHAR(100)  = NULL,
    @Token      NVARCHAR(100)  = NULL,
    @MatKhauMoi NVARCHAR(200)  = NULL,
    @KetQua     TINYINT OUTPUT          -- 0=OK, 1=Không tìm thấy, 2=Token hết hạn
AS
BEGIN
    SET NOCOUNT ON
 
    IF @HanhDong = 'TAO_TOKEN'
    BEGIN
        IF NOT EXISTS (SELECT 1 FROM tbl_TaiKhoan WHERE Email = @Email)
        BEGIN SET @KetQua = 1 RETURN END
 
        UPDATE tbl_TaiKhoan
        SET    TokenDatLaiMatKhau = @Token,
               TokenHetHan        = DATEADD(HOUR, 2, GETDATE())
        WHERE  Email = @Email
        SET @KetQua = 0
    END
 
    ELSE IF @HanhDong = 'DAT_LAI'
    BEGIN
        IF NOT EXISTS (
            SELECT 1 FROM tbl_TaiKhoan
            WHERE  TokenDatLaiMatKhau = @Token AND TokenHetHan > GETDATE()
        )
        BEGIN SET @KetQua = 2 RETURN END
 
        UPDATE tbl_TaiKhoan
        SET    MatKhau            = @MatKhauMoi,
               TokenDatLaiMatKhau = NULL,
               TokenHetHan        = NULL,
               SoLanDangNhapSai   = 0,
               KhoaTaiKhoanDen    = NULL
        WHERE  TokenDatLaiMatKhau = @Token
        SET @KetQua = 0
    END
END
GO
/****** Object:  StoredProcedure [dbo].[sp_TinTuyenSinh_TimKiem]    Script Date: 5/3/2026 2:07:24 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE [dbo].[sp_TinTuyenSinh_TimKiem]
    @MaTruong       INT            = NULL,
    @MaChuyenNganh  INT            = NULL,
    @MaPhuongThuc   INT            = NULL,
    @NamTuyenSinh   SMALLINT       = NULL,
    @DiemTu         DECIMAL(4,2)   = NULL,
    @DiemDen        DECIMAL(4,2)   = NULL,
    @TinhThanh      NVARCHAR(100)  = NULL,
    @PageIndex      INT            = 0,
    @PageSize       INT            = 20,
    @TongSo         INT            OUTPUT
AS
BEGIN
    SET NOCOUNT ON

    SELECT @TongSo = COUNT(*)
    FROM   [dbo].[tbl_TinTuyenSinh]  t
    JOIN   [dbo].[tbl_Truong]         tr ON tr.MaTruong      = t.MaTruong
    WHERE  t.TrangThai                = 1
      AND (@MaTruong      IS NULL OR t.MaTruong      = @MaTruong)
      AND (@MaChuyenNganh IS NULL OR t.MaChuyenNganh = @MaChuyenNganh)
      AND (@MaPhuongThuc  IS NULL OR t.MaPhuongThuc  = @MaPhuongThuc)
      AND (@NamTuyenSinh  IS NULL OR t.NamTuyenSinh  = @NamTuyenSinh)
      AND (@DiemTu        IS NULL OR t.DiemChuanNamTruoc >= @DiemTu)
      AND (@DiemDen       IS NULL OR t.DiemChuanNamTruoc <= @DiemDen)
      AND (@TinhThanh     IS NULL OR tr.TinhThanh    = @TinhThanh)

    SELECT
        t.MaTin,
        tr.TenTruong,
        tr.TinhThanh,
        tr.AnhDaiDien,
        tr.Slug          AS TruongSlug,
        cn.TenChuyenNganh,
        pt.TenPhuongThuc,
        t.NamTuyenSinh,
        t.ChiTieu,
        t.HocPhi,
        t.ToHopMonHoc,
        t.DiemChuanNamTruoc,
        t.DiemChuanNamNay,
        t.ChenhLechDiem,
        t.TrangThai                  -- â† thÃªm cá»™t nÃ y
    FROM   [dbo].[tbl_TinTuyenSinh]       t
    JOIN   [dbo].[tbl_Truong]              tr ON tr.MaTruong      = t.MaTruong
    JOIN   [dbo].[tbl_ChuyenNganh]        cn ON cn.MaChuyenNganh  = t.MaChuyenNganh
    JOIN   [dbo].[tbl_PhuongThucXetTuyen] pt ON pt.MaPhuongThuc   = t.MaPhuongThuc
    WHERE  t.TrangThai = 1
      AND (@MaTruong      IS NULL OR t.MaTruong      = @MaTruong)
      AND (@MaChuyenNganh IS NULL OR t.MaChuyenNganh = @MaChuyenNganh)
      AND (@MaPhuongThuc  IS NULL OR t.MaPhuongThuc  = @MaPhuongThuc)
      AND (@NamTuyenSinh  IS NULL OR t.NamTuyenSinh  = @NamTuyenSinh)
      AND (@DiemTu        IS NULL OR t.DiemChuanNamTruoc >= @DiemTu)
      AND (@DiemDen       IS NULL OR t.DiemChuanNamTruoc <= @DiemDen)
      AND (@TinhThanh     IS NULL OR tr.TinhThanh    = @TinhThanh)
    ORDER BY t.NamTuyenSinh DESC, t.DiemChuanNamTruoc DESC
    OFFSET (@PageIndex * @PageSize) ROWS
    FETCH NEXT @PageSize ROWS ONLY
END
GO
/****** Object:  StoredProcedure [dbo].[sp_Truong_LayChiTiet]    Script Date: 5/3/2026 2:07:24 PM ******/
SET ANSI_NULLS ON
GO
