-- ─── sp_Truong_LayChiTiet ──────────────────────────────────
-- Dùng cho: trang chi tiết trường (ChiTietTruong.aspx)
-- Thêm filter TrangThai=1 để ẩn trường đã bị disabled
-- ───────────────────────────────────────────────────────────
CREATE PROCEDURE [dbo].[sp_Truong_LayChiTiet]
    @MaTruong INT = NULL,
    @Slug     NVARCHAR(200) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT
        tr.*,
        (SELECT AVG(CAST(DiemDanhGia AS FLOAT))
         FROM tbl_DanhGiaTruong WHERE MaTruong = tr.MaTruong AND TrangThai = 1) AS DiemDanhGiaTB,
        (SELECT COUNT(*)
         FROM tbl_DanhGiaTruong WHERE MaTruong = tr.MaTruong AND TrangThai = 1) AS SoLuongDanhGia
    FROM [dbo].[tbl_Truong] tr
    WHERE tr.TrangThai = 1                              -- chỉ hiện trường đang active
      AND (@MaTruong IS NULL OR tr.MaTruong = @MaTruong)
      AND (@Slug     IS NULL OR tr.Slug     = @Slug);
END
GO
/****** Object:  StoredProcedure [dbo].[sp_Truong_TimKiem]    Script Date: 5/3/2026 2:07:24 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
