CREATE PROCEDURE [dbo].[sp_Truong_TimKiem]
        @TenTruong          NVARCHAR(200)   = NULL,
        @TinhThanh          NVARCHAR(100)   = NULL,
        @MaVung             TINYINT         = NULL,
        @LoaiTruong         TINYINT         = NULL,
        @MaChuyenNganh      INT             = NULL,
        @Nam                SMALLINT        = NULL,
        @DiemMin            DECIMAL(4,2)    = NULL,
        @DiemMax            DECIMAL(4,2)    = NULL,
        @TrangThai          BIT             = NULL,
        @SortBy             NVARCHAR(50)    = N'TenTruong',
        @SortDirection      NVARCHAR(4)     = N'ASC',
        @PageIndex          INT             = 0,
        @PageSize           INT             = 12,
        @CapBacDaoTao       TINYINT         = NULL,         -- NULL=tất cả | 1=Đại học | 2=Cao Đẳng | 3=Trường nghề
        @TongSo             INT             OUTPUT
AS
BEGIN
        SET NOCOUNT ON;

        -- Đếm tổng
        SELECT @TongSo = COUNT(DISTINCT t.MaTruong)
        FROM tbl_Truong t
        WHERE
                (
                    @TenTruong IS NULL
                    OR t.TenTruong COLLATE Vietnamese_CI_AI LIKE N'%' + @TenTruong + N'%'
                )
                AND ( @TinhThanh         IS NULL OR t.TinhThanh         = @TinhThanh )
                AND ( @MaVung            IS NULL OR t.MaVung             = @MaVung )
                AND ( @LoaiTruong        IS NULL OR t.LoaiTruong         = @LoaiTruong )
                AND ( @CapBacDaoTao      IS NULL OR t.CapBacDaoTao       = @CapBacDaoTao )
                AND ( @TrangThai         IS NULL OR t.TrangThai          = @TrangThai )
                AND ( @MaChuyenNganh     IS NULL OR EXISTS (
                                SELECT 1 FROM tbl_TruongChuyenNganh tcn
                                WHERE tcn.MaTruong = t.MaTruong AND tcn.MaChuyenNganh = @MaChuyenNganh
                ) )
                AND (
                        @DiemMin IS NULL AND @DiemMax IS NULL
                        OR EXISTS (
                                SELECT 1 FROM tbl_TinTuyenSinh ts
                                WHERE ts.MaTruong = t.MaTruong
                                        AND ts.TrangThai = 1
                                        AND ts.DiemChuanNamTruoc IS NOT NULL
                                        AND ( @Nam     IS NULL OR ts.NamTuyenSinh         = @Nam )
                                        AND ( @DiemMin IS NULL OR ts.DiemChuanNamTruoc >= @DiemMin )
                                        AND ( @DiemMax IS NULL OR ts.DiemChuanNamTruoc <= @DiemMax )
                        )
                );

        -- Lấy dữ liệu phân trang với sorting
        -- FIX N+1: Bổ sung CapBacDaoTao + TenCapBacDaoTao vào SELECT
        --          → TruongDAL không phải gọi DB riêng từng row nữa.
        SELECT
                t.MaTruong,
                t.TenTruong,
                t.Website,
                t.TinhThanh,
                t.QuyMo,
                t.KiemDinhChatLuong,
                t.Slug,
                t.AnhDaiDien,
                t.LoaiTruong,
                t.MaVung,
                t.TrangThai,
                t.ThoiGianCapNhat,
                -- HAI CỘT MỚI — loại bỏ N+1 query trong EnsureCapBacDaoTao()
                t.CapBacDaoTao,
                CASE t.CapBacDaoTao
                        WHEN 1 THEN N'Đại học'
                        WHEN 2 THEN N'Cao Đẳng'
                        WHEN 3 THEN N'Trường nghề'
                        ELSE N''
                END AS TenCapBacDaoTao
        FROM tbl_Truong t
        WHERE
                (
                    @TenTruong IS NULL
                    OR t.TenTruong COLLATE Vietnamese_CI_AI LIKE N'%' + @TenTruong + N'%'
                )
                AND ( @TinhThanh         IS NULL OR t.TinhThanh         = @TinhThanh )
                AND ( @MaVung            IS NULL OR t.MaVung             = @MaVung )
                AND ( @LoaiTruong        IS NULL OR t.LoaiTruong         = @LoaiTruong )
                AND ( @CapBacDaoTao      IS NULL OR t.CapBacDaoTao       = @CapBacDaoTao )
                AND ( @TrangThai         IS NULL OR t.TrangThai          = @TrangThai )
                AND ( @MaChuyenNganh     IS NULL OR EXISTS (
                                SELECT 1 FROM tbl_TruongChuyenNganh tcn
                                WHERE tcn.MaTruong = t.MaTruong AND tcn.MaChuyenNganh = @MaChuyenNganh
                ) )
                AND (
                        @DiemMin IS NULL AND @DiemMax IS NULL
                        OR EXISTS (
                                SELECT 1 FROM tbl_TinTuyenSinh ts
                                WHERE ts.MaTruong = t.MaTruong
                                        AND ts.TrangThai = 1
                                        AND ts.DiemChuanNamTruoc IS NOT NULL
                                        AND ( @Nam     IS NULL OR ts.NamTuyenSinh         = @Nam )
                                        AND ( @DiemMin IS NULL OR ts.DiemChuanNamTruoc >= @DiemMin )
                                        AND ( @DiemMax IS NULL OR ts.DiemChuanNamTruoc <= @DiemMax )
                        )
                )
        ORDER BY
                CASE WHEN @SortBy = N'TenTruong'   AND @SortDirection = N'ASC'  THEN t.TenTruong   END ASC,
                CASE WHEN @SortBy = N'TenTruong'   AND @SortDirection = N'DESC' THEN t.TenTruong   END DESC,
                CASE WHEN @SortBy = N'TinhThanh'   AND @SortDirection = N'ASC'  THEN t.TinhThanh   END ASC,
                CASE WHEN @SortBy = N'TinhThanh'   AND @SortDirection = N'DESC' THEN t.TinhThanh   END DESC,
                t.TenTruong   -- default
        OFFSET ( @PageIndex * @PageSize ) ROWS
        FETCH NEXT @PageSize ROWS ONLY;
END
GO

